export const QUIZ_DATA = {
  'Dominican Republic':{flag:'🇩🇴',lang:'Spanish',questions:[
    {cat:'Food',q:'What do Dominicans call the crispy rice stuck to the bottom of the pot?',options:['Socarrat','Concón','Pegao','Tutuma'],answer:1,exp:'"Concón" is the beloved crispy rice crust at the bottom of the pot. Many Dominicans consider it the best part of the meal and will fight each other for it at the dinner table.'},
    {cat:'Food',q:'What is "La Bandera Dominicana"?',options:['A famous cocktail','A national flag dish: white rice, red beans, and stewed meat','A breakfast pastry','A type of soup'],answer:1,exp:'"La Bandera" (The Flag) is the quintessential Dominican lunch — white rice, red beans, and stewed meat. The colors echo the national flag. Most Dominicans eat this almost every single day.'},
    {cat:'Food',q:'What is "mangú" and when is it typically eaten?',options:['A sweet mango dessert','A fried plantain chip','Mashed boiled plantains, usually eaten at breakfast with eggs, cheese, and salami','A rice-based dinner dish'],answer:2,exp:'Mangú is mashed boiled green plantains — a DR breakfast staple. It\'s typically served with sautéed red onions on top, alongside fried eggs, fried cheese, and Dominican salami. Known as "Los Tres Golpes."'},
    {cat:'Food',q:'What are "Los Tres Golpes"?',options:['Three types of merengue','The classic Dominican breakfast trio: mangú, fried egg, fried cheese, and salami','Three Dominican cocktails','Three carnival dances'],answer:1,exp:'"Los Tres Golpes" (The Three Hits) is the beloved DR breakfast combo: mangú, fried egg, fried salami, and fried white cheese. It\'s so iconic it has its own name.'},
    {cat:'Food',q:'What is "sancocho" in Dominican culture?',options:['A light summer salad','A thick hearty stew with multiple meats and root vegetables — the ultimate comfort food','A type of sweet bread','A cold seafood dish'],answer:1,exp:'Sancocho is a rich, slow-cooked stew made with multiple types of meat (chicken, pork, beef) and root vegetables like yuca and ñame. It\'s served at family gatherings, celebrations, and as a hangover cure.'},
    {cat:'Food',q:'What is "yaroa" — a street food that blew up in the DR?',options:['A type of grilled fish','Layers of fries topped with seasoned meat, cheese, mayo, and ketchup','A fried dough pastry','A cold coconut drink'],answer:1,exp:'Yaroa is a hugely popular DR street food — a tower of french fries loaded with seasoned ground meat or chicken, melted cheese, mayo, and ketchup. It originated in Santiago and spread across the country.'},
    {cat:'Food',q:'What fruit drink is most associated with Dominican street culture?',options:['Tamarind juice','Morir soñando — orange juice blended with milk and sugar','Mamajuana','Chinola juice'],answer:1,exp:'"Morir soñando" (to die dreaming) is a beloved Dominican drink made by blending orange juice with cold milk and sugar. The trick is adding milk to the juice slowly so it doesn\'t curdle. Sold everywhere.'},
    {cat:'Food',q:'What is "chimichurri" in the Dominican Republic — and why is it different from Argentina\'s?',options:['It\'s identical to Argentine chimichurri','In the DR, a "chimi" is a loaded street burger with cabbage, tomato, and special sauce — nothing to do with the green sauce','A type of seasoning rub','A grilled vegetable side dish'],answer:1,exp:'In the DR, "chimi" (chimichurri) means a Dominican street burger — a juicy patty on soft bread loaded with cabbage salad, tomatoes, and a special pink sauce. It has nothing to do with Argentine herb sauce.'},
    {cat:'Music',q:'Which Dominican genre is a UNESCO Intangible Cultural Heritage?',options:['Bachata','Salsa','Merengue','Dembow'],answer:2,exp:'Merengue was recognized by UNESCO in 2016. It\'s the national music and dance of the DR — fast-paced, accordion-driven, and deeply tied to Dominican identity. Every celebration features merengue.'},
    {cat:'Music',q:'Where did bachata originally come from, and what was its early reputation?',options:['It was always celebrated as high-class music','It originated in rural and poor urban neighborhoods and was looked down on as music for the lower class before going global','It was invented in the DR\'s capital for wealthy audiences','It came from Cuba and was adopted by Dominicans'],answer:1,exp:'Bachata originated in the countryside and poor barrios of the DR in the 1960s. It was long stigmatized as música de amargue (music of bitterness) for the poor. Only in the 1990s–2000s did it gain mainstream and global respect.'},
    {cat:'Music',q:'What is "dembow" and what country does it come from?',options:['A type of merengue from the Cibao region','A dancehall-influenced urban genre that originated in the DR and dominates Latin street music','A Venezuelan folk genre','A Cuban rhythm adapted in Santo Domingo'],answer:1,exp:'Dembow is an urban genre born in the DR, heavily influenced by Jamaican dancehall. Its driving beat became the rhythmic backbone of modern reggaeton. Artists like El Alfa and Rochy RD made it global.'},
    {cat:'Music',q:'What is "perico ripiao" in Dominican music?',options:['A type of cocktail','The raw, traditional form of merengue played with accordion, güira, and tambora — the roots of the genre','A bachata subgenre','A carnival song style'],answer:1,exp:'"Perico ripiao" (ripped parrot) is the original, stripped-down form of merengue using accordion, güira (metal scraper), and tambora drum. It\'s the rural ancestor of the polished merengue heard today.'},
    {cat:'Slang',q:'What does "vaina" mean in Dominican slang?',options:['A type of food','An insult','An all-purpose word for "thing," "situation," or "stuff"','A greeting between friends'],answer:2,exp:'"Vaina" is one of the most versatile Dominican words — it means "thing," "stuff," "situation," or basically anything. "¿Qué vaina es esa?" = "What\'s that thing/deal?" You\'ll hear it constantly.'},
    {cat:'Slang',q:'What does "ño" or "ñoño" mean as a Dominican exclamation?',options:['An insult','A term of endearment','An expression of surprise, disbelief, or mild frustration — like "dang!" or "come on!"','A way to greet someone'],answer:2,exp:'"Ño!" is a very common Dominican exclamation — a softened version of a stronger word. Used to express surprise, frustration, or amazement. "¡Ño, qué calor!" = "Damn, it\'s hot!"'},
    {cat:'Slang',q:'If a Dominican says "tíguere," what do they mean?',options:['A literal tiger','A clever, street-smart person who knows how to navigate life — can be a compliment or a warning','An insult for a dishonest person','A term for someone from the countryside'],answer:1,exp:'"Tíguere" (tiger) is a quintessential DR word. It describes someone who is street-smart, resourceful, and knows how to work any situation. It\'s often a compliment — someone impressive and sharp.'},
    {cat:'Slang',q:'What does "ahorita" mean when a Dominican says it?',options:['Right this second','In exactly five minutes','Sometime later — vague, could be an hour or never','First thing tomorrow'],answer:2,exp:'"Ahorita" literally means "right now" but functionally means "later, eventually, maybe." If someone says "ahorita voy," don\'t hold your breath. Dominican time is famously flexible.'},
    {cat:'Slang',q:'What does "bróder" mean in Dominican slang?',options:['A formal title','Brother or close friend — borrowed from English "brother," used constantly','A type of street food vendor','Someone from a wealthy neighborhood'],answer:1,exp:'"Bróder" comes from English "brother" and is used constantly in the DR to mean close friend or buddy. "¡Oye bróder!" is how you\'d greet a friend on the street.'},
    {cat:'Slang',q:'What does it mean when someone calls you "jalabola" in the DR?',options:['A great dancer','A kiss-up, sycophant, or brown-noser','A generous person','Someone who is very funny'],answer:1,exp:'"Jalabola" (literally "ball-puller") means someone who flatters or sucks up to people in power for personal gain — a brown-noser or sycophant. Not a compliment.'},
    {cat:'Culture',q:'What is "el apagón" and why does it define daily Dominican life?',options:['A popular dance','Scheduled daily power outages that force everyone to plan around them','A type of street fair','A national holiday'],answer:1,exp:'Power outages ("apagones") are a constant reality in much of the DR. Families and businesses have generators or inverter systems. "¿Hay luz?" (Is there power?) is a completely normal daily question.'},
    {cat:'Culture',q:'What is the significance of the Malecón in Santo Domingo?',options:['It\'s an ancient colonial fortress','A famous 30km oceanfront avenue where Dominicans gather to socialize, exercise, and celebrate','The country\'s main commercial district','A traditional market exclusively for handicrafts'],answer:1,exp:'The Malecón is Santo Domingo\'s iconic seafront boulevard. It\'s where families walk at sunset, where New Year\'s Eve concerts happen with hundreds of thousands of people, and where life spills out of the city every evening.'},
    {cat:'Culture',q:'What is Carnival in the Dominican Republic most famous for?',options:['Being a solemn religious procession','The "vejigas" — colorful masked figures who playfully hit spectators with inflated bladders','Elaborate float competitions like Brazil\'s Carnival','A silent nighttime parade'],answer:1,exp:'Dominican Carnival (February) features "lechones" and "diablos cojuelos" — masked, costumed characters who chase and playfully hit spectators with "vejigas" (inflated cow bladders or balloons). It\'s wild and joyful.'},
    {cat:'Culture',q:'What is "el Día de las Mercedes" and why do Dominicans celebrate it?',options:['A harvest festival','September 24th — a major religious and cultural holiday honoring the Virgin of Las Mercedes, patroness of the DR','A commemoration of independence','A music festival held each year'],answer:1,exp:'September 24th honors the Virgin of Las Mercedes, the patron saint of the Dominican Republic. It\'s a major religious holiday combining Catholic tradition with African-rooted spiritual practices like 21 Divisiones.'},
    {cat:'Culture',q:'What are the "21 Divisiones"?',options:['The 21 provinces of the Dominican Republic','An Afro-Dominican spiritual tradition blending West African beliefs with Catholicism and indigenous elements','A type of merengue dance with 21 steps','A set of national laws'],answer:1,exp:'Las 21 Divisiones is an Afro-Dominican folk religion — a syncretic spiritual system blending West African, indigenous Taíno, and Catholic elements. It involves spirits called "misterios" and is widely practiced alongside Catholicism.'},
    {cat:'History',q:'What is the Zona Colonial of Santo Domingo?',options:['A modern shopping district','The first permanent European settlement in the Americas, founded in 1498 — now a UNESCO World Heritage Site','A 20th-century residential neighborhood','The DR\'s main financial district'],answer:1,exp:'The Zona Colonial (Colonial Zone) is the oldest continuously inhabited European city in the Americas, founded in 1498. It contains the first cathedral, first university, and first paved road in the New World. UNESCO listed it in 1990.'},
    {cat:'History',q:'Who was Rafael Trujillo and why does his legacy still echo in the DR?',options:['A beloved democratic president who modernized the country','A brutal dictator who ruled for 31 years (1930–1961), leaving deep scars and a complicated cultural legacy','A famous Dominican poet','The founder of the Dominican Republic'],answer:1,exp:'Rafael Trujillo ruled the DR as a brutal dictator for 31 years until his assassination in 1961. He renamed the capital after himself, massacred Haitians in 1937, and created a pervasive culture of fear. His legacy still shapes Dominican identity and politics.'},
    {cat:'History',q:'What is the significance of February 27th in the Dominican Republic?',options:['The date Columbus arrived in Hispaniola','Dominican Independence Day — declared independence from Haiti in 1844','The anniversary of the end of Trujillo\'s dictatorship','A religious feast day'],answer:1,exp:'February 27, 1844 is Dominican Independence Day — the day the DR declared independence from Haitian rule, which had unified the island since 1822. It\'s the most important national holiday, celebrated with carnival and parades.'},
    {cat:'History',q:'The Dominican Republic shares the island of Hispaniola with which country?',options:['Cuba','Puerto Rico','Haiti','Jamaica'],answer:2,exp:'Hispaniola is shared by the Dominican Republic (east, Spanish-speaking) and Haiti (west, French/Haitian Creole-speaking). It\'s the most densely populated island in the Caribbean and the site of complex shared history.'},
    {cat:'Daily Life',q:'What is "colmado" and why is it central to Dominican community life?',options:['A type of music venue','A corner store that also functions as a social hub — people gather, drink, and socialize there','A neighborhood church','A public bus system'],answer:1,exp:'A colmado is a small neighborhood convenience store, but it\'s far more than that. In the DR, colmados sell drinks, food, and basics — and double as gathering spots where neighbors hang out, listen to music, and socialize for hours.'},
    {cat:'Daily Life',q:'What is "guineo" in Dominican Spanish?',options:['A type of dance','A banana — Dominicans use this word instead of "plátano" or "banana"','A slang word for money','A neighborhood in Santo Domingo'],answer:1,exp:'Dominicans call bananas "guineos" — not "bananas" or "plátanos." The word comes from Guinea, West Africa. You\'ll confuse vendors if you ask for a "banana" at a Dominican market.'},
    {cat:'Daily Life',q:'What is a "guagua" in the Dominican Republic?',options:['A type of food','A baby','A public minibus or bus — the main form of public transport','A neighborhood party'],answer:2,exp:'A "guagua" is a public bus or minibus in the DR — the main form of affordable public transport. They\'re often packed, loud, and play music at full volume. Taking a guagua is a very authentic Dominican experience.'},
    {cat:'Daily Life',q:'What does "tranquilo" signal in Dominican conversations?',options:['Only "calm down"','Relax, it\'s fine, don\'t worry — used to reassure or defuse tension in any situation','A way to say goodbye','That someone is being boring'],answer:1,exp:'"Tranquilo" (or "tranquila") is used constantly in the DR to mean "relax," "it\'s fine," "don\'t stress." It reflects the broader cultural value of keeping things calm, easy, and not letting problems ruin the mood.'},

    {cat:'Music',q:'What global music genre did the Dominican Republic give the world?',options:['Salsa','Bachata and merengue — both born in the DR, now danced in clubs from New York to Tokyo','Reggaeton','Cumbia'],answer:1,exp:'Merengue is the DR\'s national music — fast, brass-heavy, and impossible not to move to. Bachata started as working-class music dismissed by elites, then Romeo Santos and Prince Royce brought it to global fame. Both genres are now staples of Latin night everywhere.'},
    {cat:'Food',q:'What Dominican ingredient shows up in American cities with large DR communities?',options:['Plantains are only for restaurants','Platanos (plantains) — fried tostones and sweet maduros became staples in NYC bodegas and Dominican kitchens across the US','Rice is the main export','Only tropical fruits'],answer:1,exp:'In Washington Heights, the Bronx, and Providence — major Dominican communities — you\'ll find platanos at every meal. Tostones (twice-fried green plantain) and maduros (sweet ripe plantain) are gateway foods many Americans discover through Dominican neighbors.'},
    {cat:'Culture',q:'What does "Dominican time" mean?',options:['A time zone','Events start significantly later than the stated time — being 30-60 minutes late is completely normal and expected','Being early is respectful','Only for funerals'],answer:1,exp:'Like many Caribbean and Latin cultures, social events in the DR operate on flexible time. A party at 8pm might not really start until 10pm. Showing up exactly on time to a Dominican gathering can feel awkward — you might be the only one there.'},
    {cat:'Sports',q:'What sport is the Dominican Republic most famous for globally?',options:['Soccer','Baseball — the DR produces more MLB players per capita than any other country','Basketball','Boxing'],answer:1,exp:'The Dominican Republic is a baseball powerhouse. More MLB players come from the DR than any country outside the US — including legends like Pedro Martínez, David Ortiz, Albert Pujols, and Vladimir Guerrero Jr. Baseball academies across the country funnel players directly to the majors.'},
    {cat:'Sports',q:'What is "la pelota" in Dominican culture?',options:['A children\'s toy','Baseball — the word literally means "the ball" but refers to the national obsession','Soccer','A street game'],answer:1,exp:'"La pelota" (the ball) means baseball in the DR — a sport so central to Dominican identity that it\'s simply called "the ball." Kids play in the streets, in empty lots, with makeshift equipment. It\'s a way out of poverty and a source of immense national pride.'},
    {cat:'Media',q:'What is "telenovela" culture like in the Dominican Republic?',options:['Dominicans prefer American TV','Telenovelas (soap operas) dominate TV — mostly Mexican and Colombian ones dubbed in Spanish','Only local DR shows are popular','Sports are the only popular TV content'],answer:1,exp:'Telenovelas are hugely popular in the DR. Mexican and Colombian novelas air constantly and are discussed like sports. Phrases, characters, and storylines from popular telenovelas enter everyday conversation.'},
    {cat:'Media',q:'Which Dominican-American writer won the Pulitzer Prize?',options:['Julia Alvarez','Edwidge Danticat','Junot Díaz — for "The Brief Wondrous Life of Oscar Wao"','Sandra Cisneros'],answer:2,exp:'Junot Díaz won the 2008 Pulitzer Prize for Fiction for "The Brief Wondrous Life of Oscar Wao," a novel deeply rooted in Dominican history, culture, and diaspora identity. It\'s essential reading for understanding the Dominican-American experience.'},
    {cat:'Daily Life',q:'What is the typical schedule of a Dominican workday compared to North America?',options:['Same as the US','Work starts early, long lunch break in the afternoon, then back to work — many shops close midday','Work ends at noon','Only evening shifts are common'],answer:1,exp:'In the DR, the traditional schedule often includes a long lunch break (sometimes 2 hours) in the early afternoon when the heat peaks. Many families go home to eat together. The pace is more relaxed and relationship-centered than in North America.'},
    {cat:'Daily Life',q:'How do Dominicans typically greet each other?',options:['Handshake only','Women kiss each other on the cheek, men handshake or hug close friends — physical warmth is normal','Only verbal greetings','Bowing is common'],answer:1,exp:'Physical greetings are warm and normal in Dominican culture. Women kiss each other on the cheek; men handshake or embrace close friends. Not greeting someone properly when you enter a room is considered rude.'},
    ]},
  'Puerto Rico':{flag:'🇵🇷',lang:'Spanish',questions:[
    {cat:'Food',q:'What is "mofongo"?',options:['A sweet dessert','Mashed fried plantains with garlic and chicharrón','A seafood stew','Rice with coconut milk'],answer:1,exp:'Mofongo is mashed fried green plantains with garlic, olive oil, and chicharrón. Often served stuffed with shrimp or chicken in a savory broth.'},
    {cat:'Slang',q:'What does "wepa!" express?',options:['Sadness','Excitement or approval','Confusion','Hunger'],answer:1,exp:'"Wepa!" is a uniquely Puerto Rican exclamation of joy. You hear it at parties, sports games — anywhere good things happen.'},
    {cat:'Culture',q:'What is "La Placita de Santurce" famous for?',options:['Oldest church in PR','A vibrant nightlife and food hub in San Juan','The largest beach','A colonial fortress'],answer:1,exp:'La Placita transforms into a massive outdoor party on weekends — quintessential San Juan nightlife.'},
    {cat:'Music',q:'Reggaeton was largely born in which city?',options:['Miami','Santo Domingo','San Juan, Puerto Rico','Medellín'],answer:2,exp:'San Juan is the birthplace of reggaeton. Daddy Yankee, Tego Calderón, and Don Omar emerged from the underground scene here in the late 1990s.'},
    {cat:'Culture',q:'What is a "piragua"?',options:['A canoe','A shaved ice treat with flavored syrup','A type of music','A neighborhood'],answer:1,exp:'A piragua is shaved ice shaped like a pyramid drenched in flavored syrup — Puerto Rico\'s beloved street snack sold from pushcarts.'},
    {cat:'Food',q:'What is "arroz con gandules"?',options:['Rice with chicken','Rice with pigeon peas — the national dish, essential at Christmas','A breakfast porridge','A cold rice salad'],answer:1,exp:'Arroz con gandules (rice with pigeon peas) is Puerto Rico\'s national dish, cooked with sofrito and pork. Essential at Christmas alongside pernil.'},
    {cat:'Food',q:'What is "pernil"?',options:['A type of bread','Slow-roasted pork shoulder marinated in garlic and spices — centerpiece of Christmas dinner','A dessert','A fish stew'],answer:1,exp:'Pernil is slow-roasted pork shoulder, marinated overnight in garlic and spices. The star of Puerto Rican Christmas — families fight over the crispy skin called "cuero."'},
    {cat:'Slang',q:'What does "boricua" mean?',options:['From the Dominican Republic','A native of Puerto Rico — from the Taíno name Borikén','A slang word for party','A neighborhood in San Juan'],answer:1,exp:'"Boricua" comes from "Borikén," the Taíno name for Puerto Rico. It\'s a term of identity Puerto Ricans use proudly, especially in the diaspora.'},
    {cat:'Culture',q:'What is "El Yunque"?',options:['A famous Puerto Rican musician','The only tropical rainforest in the US National Forest System','A neighborhood in Old San Juan','A traditional drum'],answer:1,exp:'El Yunque is the only tropical rainforest in the US National Forest System, home to the iconic coquí frog and deeply symbolic of Puerto Rican natural heritage.'},
    {cat:'Culture',q:'What is the "coquí" and why do Puerto Ricans feel so strongly about it?',options:['A type of music','A tiny tree frog whose "ko-KEE" call is the sound of Puerto Rico — a national symbol','A traditional dessert','A type of rum'],answer:1,exp:'The coquí is a tiny tree frog named for its call. Puerto Ricans say if you take one off the island it stops singing — a metaphor for the diaspora experience.'},
    {cat:'Slang',q:'What does "chavos" mean in Puerto Rican slang?',options:['Friends','Money','Children','Food'],answer:1,exp:'"Chavos" means money in Puerto Rican slang. Completely unique to PR, coming from "ochavo," an old Spanish coin.'},
    {cat:'History',q:'What is Puerto Rico\'s political status?',options:['Fully independent','A US state with voting rights','An unincorporated US territory — Puerto Ricans are US citizens but can\'t vote for president','Fully independent from the US'],answer:2,exp:'Puerto Rico is an unincorporated US territory. Puerto Ricans are US citizens by birth but residents can\'t vote for president and have no voting Congress representation.'},
    {cat:'Food',q:'What is "sofrito"?',options:['A dessert','A blended paste of peppers, garlic, onion, and herbs — flavor foundation of Puerto Rican cooking','A type of bread','A hot sauce'],answer:1,exp:'Sofrito is the aromatic base of Puerto Rican cooking — blended ají dulce peppers, garlic, onion, cilantro, and recao. Every family has their own recipe.'},
    {cat:'Slang',q:'What does "brutal" mean in Puerto Rican slang?',options:['Something violent','Something awesome or excellent','An insult','Something old'],answer:1,exp:'In Puerto Rico, "brutal" is a huge compliment — "¡Eso está brutal!" = "That\'s awesome!" The opposite of the English meaning.'},
    {cat:'Culture',q:'What are "parandas" in Puerto Rican Christmas culture?',options:['Christmas gifts','Surprise late-night musical visits where groups sing and expect food and drinks','Christmas Eve masses','Carnival costumes'],answer:1,exp:'Parandas are a beloved Puerto Rican tradition — a group shows up at your door late at night with instruments singing aguinaldos. You join and feed them, then move to the next house.'},
    {cat:'Daily Life',q:'What does "al garete" mean?',options:['Going smoothly','Adrift, out of control, or chaotic','Doing great','Moving quickly'],answer:1,exp:'"Al garete" (from a nautical term) describes something that\'s gone off the rails. "Ese plan fue al garete" = "That plan went sideways." Very Puerto Rican.'},
    {cat:'Culture',q:'What makes Old San Juan\'s cobblestones special?',options:['Painted blue for tourism','Made from slag from Spanish ships — naturally blue-grey and over 400 years old','Installed in the 1950s','Symbolic of the sea'],answer:1,exp:'Old San Juan\'s iconic blue cobblestones are adoquines — blocks of iron slag used as ship ballast by Spanish vessels, 400+ years old and UNESCO-protected.'},
    {cat:'Food',q:'What is "lechón" and where is the best place to eat it?',options:['A beef stew','Whole roasted pig — the best found along "La Ruta del Lechón" in Guavate, Cayey','A seafood dish','A dessert'],answer:1,exp:'Lechón is whole roasted pig over wood. Guavate in Cayey is the undisputed capital — "La Ruta del Lechón" is a mountain road of lechoneras packed every weekend.'},
    {cat:'Slang',q:'What does "chacho/chacha" mean?',options:['A type of food','An all-purpose exclamation or term of endearment — from "muchacho/a"','Only a formal greeting','An insult'],answer:1,exp:'"Chacho" is an extremely common Puerto Rican filler word. "¡Chacho, qué calor!" = "Man, it\'s so hot!" Very PR-specific.'},
    {cat:'Music',q:'What is "salsa" music and Puerto Rico\'s role in it?',options:['Salsa originated in Cuba only','Nuyoricans (New York Puerto Ricans) were central to developing modern salsa in the 1960s-70s at Fania Records','Salsa is Mexican','It originated in Colombia'],answer:1,exp:'While rooted in Cuba, Nuyorican musicians like Héctor Lavoe and Willie Colón shaped modern salsa at Fania Records. Puerto Rico\'s contribution to salsa is immense.'},
    {cat:'Culture',q:'What is "La Fortaleza" in San Juan?',options:['A prison','The oldest executive mansion still in use in the Western Hemisphere — home to the Governor of Puerto Rico','A military fortress for tourists','A famous restaurant'],answer:1,exp:'La Fortaleza (built 1533) is the oldest executive mansion still in use in the Western Hemisphere — the governor\'s residence and a UNESCO World Heritage Site.'},
    {cat:'Food',q:'What is "tembleque"?',options:['A spicy pepper dish','A creamy coconut pudding that jiggles — the name means "wobbly"','A type of fried dough','A rum cocktail'],answer:1,exp:'Tembleque is a silky coconut milk pudding. Beloved Puerto Rican dessert, especially at Christmas, dusted with cinnamon on top.'},
    {cat:'Slang',q:'What is "bregar" and why is it uniquely Puerto Rican?',options:['Just fighting','A word meaning to work hard, cope, hustle — capturing the Puerto Rican spirit of resilience','A cooking term','A musical style'],answer:1,exp:'"Bregar" means to struggle, hustle, cope with whatever comes. Anthropologist Arcadio Díaz Quiñones wrote an entire essay on it — it captures the Puerto Rican experience of navigating life with creativity and grit.'},
    {cat:'Food',q:'What is "morir soñando"?',options:['A saying about dreams','Orange juice blended with cold milk and sugar — a Caribbean drink popular across the island, meaning "to die dreaming"','A dessert','A coffee drink'],answer:1,exp:'"Morir soñando" (to die dreaming) is a beloved Caribbean drink found across the islands, including Puerto Rico — — orange juice blended with cold milk and sugar. The trick is adding the milk slowly. Sold everywhere.'},

    {cat:'Music',q:'Which Puerto Rican artist made reggaeton a global phenomenon?',options:['Marc Anthony','Daddy Yankee — his song "Gasolina" in 2004 broke reggaeton into mainstream America and internationally','Bad Bunny was first','Ricky Martin created reggaeton'],answer:1,exp:'"Gasolina" by Daddy Yankee is widely credited with bringing reggaeton to mainstream America. Bad Bunny then took it further, becoming one of the most streamed artists in the world. Puerto Rico essentially exported a global music genre.'},
    {cat:'Culture',q:'What connects Puerto Rico uniquely to the United States?',options:['It\'s a foreign country','Puerto Ricans are US citizens by birth but cannot vote in presidential elections if living on the island — a unique political status','It became a state in 1952','It\'s an independent nation'],answer:1,exp:'Puerto Rico\'s status as a US territory means its residents are American citizens but lack full congressional representation and can\'t vote for president while living there. This complex relationship shapes Puerto Rican identity and the large diaspora in New York and Florida.'},
    {cat:'Media',q:'What Broadway musical and film brought Puerto Rican culture to mainstream America?',options:['Hamilton','West Side Story — it brought Puerto Rican characters, culture, and the concept of Nuyorican identity to mainstream America, for better and worse','Rent','In the Heights'],answer:1,exp:'West Side Story (1957 musical, 1961 and 2021 films) put Puerto Rican New York on the cultural map, though it has been criticized for stereotyping. Lin-Manuel Miranda\'s "In the Heights" later gave a more authentic portrayal of Dominican-Puerto Rican Washington Heights culture.'},
    {cat:'Sports',q:'What is Puerto Rico\'s complex relationship with the Olympics?',options:['Puerto Rico competes as part of the US team','Puerto Rico competes as its own nation in the Olympics despite being a US territory','Puerto Rico is banned from the Olympics','Only Puerto Rican-born US citizens can compete'],answer:1,exp:'Puerto Rico has its own Olympic Committee and competes as a separate nation in the Olympics — not as part of the US team. This is a source of enormous pride. Puerto Rican athletes choose between representing PR or the US.'},
    {cat:'Sports',q:'Which sport besides baseball is huge in Puerto Rico?',options:['Cricket','Boxing — Puerto Rico has produced world champions in nearly every weight class','Golf','Tennis'],answer:1,exp:'Puerto Rico has a remarkable boxing legacy — Félix Trinidad, Miguel Cotto, and Wilfredo Gómez are legends. Puerto Rican fight nights are massive cultural events. Roberto Clemente also made baseball a point of deep national pride.'},
    {cat:'Media',q:'What Puerto Rican singer is one of the best-selling artists in history?',options:['Marc Anthony','Ricky Martin — one of the best-selling Latin artists ever with over 70 million records','Bad Bunny','Ozuna'],answer:1,exp:'Ricky Martin is one of Puerto Rico\'s most globally recognized exports — over 70 million records sold. His 1999 performance of "La Copa de la Vida" at the Grammys launched the Latin pop explosion in the US.'},
    {cat:'Media',q:'What genre did Bad Bunny help make global?',options:['Merengue','Reggaeton and Latin trap — he\'s the most streamed artist on Spotify multiple years in a row','Salsa','Bachata'],answer:1,exp:'Bad Bunny (Benito Ocasio) from Vega Baja, Puerto Rico became the most streamed artist globally. He elevated reggaeton and Latin trap to mainstream status while rapping entirely in Spanish — a huge cultural statement.'},
    {cat:'Daily Life',q:'What is "la hora puertorriqueña"?',options:['A time zone','The local tradition of arriving significantly later than the stated time','A morning greeting ritual','A type of clock'],answer:1,exp:'"La hora puertorriqueña" (Puerto Rican time) means showing up 30-60+ minutes after the scheduled time for social events. It\'s completely normal and expected. Showing up exactly on time to a party often means you arrive before the host is ready.'},
    {cat:'Daily Life',q:'What is the coquí and why does it matter to Puerto Ricans?',options:['A type of food','A tiny frog whose chirp is the soundtrack of the island — deeply symbolic of Puerto Rican identity','A traditional dance','A musical instrument'],answer:1,exp:'The coquí is a tiny endemic frog whose "ko-KEE" call fills Puerto Rican nights. It\'s a powerful symbol of home — Puerto Ricans in the diaspora often say the coquí doesn\'t sing anywhere else in the world, meaning Puerto Rico is truly unique.'},
    ]},
    'Argentina':{flag:'🇦🇷',lang:'Spanish',questions:[
    {cat:'Food',q:'What is "asado" and what makes it a social ritual?',options:['A quick breakfast','A long ceremonial BBQ where the asador holds a position of great honor','A dessert','A type of empanada'],answer:1,exp:'Asado is Argentina\'s sacred BBQ — never rushed, takes 3-4 hours. The asador (grill master) is responsible for fire, timing, and feeding everyone. Deeply social.'},
    {cat:'Culture',q:'What is "mate" and what does sharing it signify?',options:['A type of steak','A bitter herbal drink shared from the same gourd — a sign of friendship and trust','A cocktail','A children\'s game'],answer:1,exp:'Mate is sipped through a metal straw from a shared gourd. Passing mate is a sign of trust and inclusion. Refusing it can feel like a social snub.'},
    {cat:'Slang',q:'What does "che" mean?',options:['Yes emphatically','An all-purpose filler like hey or dude — used constantly','No way','A formal greeting'],answer:1,exp:'"Che" is Argentina\'s most famous slang word. Ernesto Guevara got his nickname because he used it constantly. An all-purpose "hey," "dude," or "listen."'},
    {cat:'Culture',q:'Why do Argentines use "vos" instead of "tú"?',options:['More respectful','A colonial variant that survived only in the Río de la Plata region','Portuguese influence','Only in informal texts'],answer:1,exp:'"Vos" replaced "tú" in Argentina and Uruguay. It has its own conjugations — "vos tenés" not "tú tienes." Using "tú" sounds foreign to Argentines.'},
    {cat:'Food',q:'What is "dulce de leche"?',options:['Same as caramel','Made by slowly heating sweetened milk — creamier and less bitter than caramel','A chocolate spread','Made with condensed milk and eggs'],answer:1,exp:'Dulce de leche is made by slowly cooking sweetened milk — creamier and milkier than caramel. Argentines put it on everything.'},
    {cat:'Music',q:'What is "tango" and what was its original social context?',options:['A formal ballroom dance from European nobility','A dance born in working-class immigrant neighborhoods of Buenos Aires — originally considered scandalous','A children\'s folk dance','A religious ceremony'],answer:1,exp:'Tango was born in the conventillos (tenements) of Buenos Aires among immigrants. It was considered dangerously sensual — banned in polite society before becoming Argentina\'s greatest cultural export.'},
    {cat:'Slang',q:'What does "boludo" mean and when can you use it?',options:['Always an insult','Between close friends it\'s an affectionate "dude" — but to a stranger or with aggression it\'s a serious insult','Always a compliment','A neutral greeting'],answer:1,exp:'"Boludo" between friends is warm and affectionate — like "bro." Said to a stranger or with anger, it\'s deeply offensive. Context is everything.'},
    {cat:'Culture',q:'What is Argentina\'s unique relationship with psychoanalysis?',options:['Argentina has the fewest therapists per capita','Buenos Aires has more psychoanalysts per capita than any city in the world — therapy is deeply embedded in middle-class culture','Therapy is illegal','Only practiced in rural areas'],answer:1,exp:'Buenos Aires has the most psychoanalysts per capita of any city in the world. Going to therapy is normal, common, and openly discussed. Freudian psychoanalysis is deeply embedded in Argentine middle-class identity.'},
    {cat:'Food',q:'What is an "empanada" and how do fillings differ by region?',options:['A type of pasta','A stuffed pastry — fillings vary dramatically by region: beef with egg and olives, humita in Salta, seafood on the coast','A dessert','A type of bread'],answer:1,exp:'Empanada fillings are fierce regional identity. Salta uses beef with potato and chile. Tucumán are known for juicy beef. Buenos Aires often has ham and cheese. Each region defends its version.'},
    {cat:'Slang',q:'What does "copado/copada" mean?',options:['Something disappointing','Cool, great, awesome — one of the most common compliments in Argentine Spanish','Old-fashioned','Expensive'],answer:1,exp:'"Copado/copada" means cool or great. "¡Qué copado!" = "How cool!" Immediately identifies you as Argentine to other Spanish speakers.'},
    {cat:'Music',q:'Who was Carlos Gardel and why is he still worshipped?',options:['A football player','The most iconic tango singer in history — his 1935 death at the height of his fame made him mythological','A president','A film director'],answer:1,exp:'Carlos Gardel is the God of Tango. Argentines say "cada día canta mejor" (he sings better every day) — his legend only grows.'},
    {cat:'Slang',q:'What does "fiaca" mean?',options:['Energy and motivation','Laziness or not wanting to do anything — a beloved Argentine concept','Hunger','Anger'],answer:1,exp:'"Fiaca" describes pure laziness. "Tengo una fiaca tremenda" = "I\'m so lazy right now." Almost celebrated in Argentina — acknowledging fiaca is honest and very Argentine.'},
    {cat:'Culture',q:'What is "el fútbol" to Argentines really?',options:['A sport they enjoy casually','A religion and source of national identity that shapes daily conversation and national mood more than almost anything','Just entertainment','A sport mainly for men'],answer:1,exp:'Football in Argentina is metaphysical. The Boca-River Superclásico is the world\'s most passionate local derby. Argentina\'s 2022 World Cup win caused the largest street celebrations in the country\'s history.'},
    {cat:'Slang',q:'What does "re" as a prefix mean in Argentine slang?',options:['Nothing','An intensifier meaning very or really — "re bueno" = really good, "re caro" = really expensive','A prefix meaning again','A formal modifier'],answer:1,exp:'"Re" as a prefix is quintessentially Argentine — it means "very." "Re bueno" = really good. "Re copado" = really cool. You\'ll hear it constantly in Buenos Aires.'},
    {cat:'Food',q:'What is "locro" and when is it eaten?',options:['A light summer salad','A thick stew of corn, beans, and meat — eaten on cold winter days, particularly on national holidays','A Christmas dessert','A breakfast porridge'],answer:1,exp:'Locro is a thick, hearty stew of white corn, beans, squash, and pork. The quintessential winter dish, traditionally eaten on patriotic holidays like May 25.'},
    {cat:'Slang',q:'What does "¡Qué quilombo!" mean?',options:['What a beautiful thing','What a mess, chaos, or disaster','What a coincidence','What an achievement'],answer:1,exp:'"Quilombo" means chaos or mess. "¡Qué quilombo!" = "What a mess!" The word originally referred to Afro-Brazilian maroon communities before arriving in Argentina.'},
    {cat:'Culture',q:'What is "la siesta" culture in Argentine provinces?',options:['Siestas are universal','Buenos Aires barely observes siesta, but in Mendoza, Salta, and Córdoba everything shuts from 1-5pm — strictly observed','Only for children','A myth in Argentina'],answer:1,exp:'In Buenos Aires, siesta barely exists. But in the provinces — especially Mendoza, Salta, and Córdoba — shops genuinely close from 1-5pm. Don\'t try to shop during siesta.'},
    {cat:'History',q:'What happened during the Argentine "Dirty War" (1976-1983)?',options:['A war with another country','The military dictatorship disappeared an estimated 30,000 people — activists, students, anyone deemed subversive','A civil war between provinces','An economic crisis'],answer:1,exp:'During the military dictatorship, an estimated 30,000 people were "disappeared" — kidnapped, tortured, and killed. The Madres de Plaza de Mayo became a global human rights symbol.'},
    {cat:'Food',q:'What is "medialunas" and what makes Argentine ones special?',options:['A type of steak','Sweet buttery croissants — Argentine medialunas are sweeter and glazed, eaten for breakfast with café con leche','A chocolate dessert','A type of pasta'],answer:1,exp:'Medialunas are sweet, glazed croissants. The breakfast of "medialunas con café con leche" is a cherished Argentine ritual at any confitería.'},
    {cat:'Slang',q:'What does "¿Todo bien?" mean in Argentine conversation?',options:['Are you physically okay?','A casual "all good?" greeting used constantly as filler between friends — not really asking if something is wrong','A formal inquiry','A farewell'],answer:1,exp:'"¿Todo bien?" (all good?) is used constantly in Argentine conversation — as a greeting, check-in, or filler. "Todo bien" as a response means everything is fine, nothing to worry about.'},
    {cat:'Culture',q:'What is "el veraneo" and where do Argentines go?',options:['A sports event','The summer vacation season (January-February) — families flock to Mar del Plata or Pinamar on the Atlantic coast','A harvest festival','A school tradition'],answer:1,exp:'"El veraneo" is when Argentines flee to the coast during Buenos Aires summer. Mar del Plata is most popular — working class and students. Pinamar attracts the upper-middle class.'},
    {cat:'Music',q:'What is "folklore" music in Argentina?',options:['Same as tango','Music of the Argentine interior provinces — chacareras, zambas, and bagualas from Tucumán, Salta, Jujuy. Completely different from urban tango.','Only exists in Patagonia','Tango predates it'],answer:1,exp:'Argentine folklore represents the interior — chacareras, zambas, bagualas. Artists like Mercedes Sosa and Atahualpa Yupanqui defined it. It\'s the sound of the "other" Argentina that Buenos Aires often ignores.'},
    {cat:'Culture',q:'What is the Sunday asado ritual in Argentina?',options:['A quick weekend meal','A sacred weekly family ritual — the asador tends fire for hours, family gathers gradually, eating and talking all afternoon','A commercial event','Only in Buenos Aires'],answer:1,exp:'Sunday asado is Argentina\'s most sacred weekly ritual. The asador starts early, family arrives slowly. It\'s not about the meat — it\'s about unhurried togetherness. Missing it requires a serious excuse.'},
    {cat:'History',q:'What was the Dirty War (Guerra Sucia) in Argentina?',options:['A border conflict','A state terror campaign (1976-1983) where the military junta disappeared around 30,000 people','A civil war','An economic crisis'],answer:1,exp:'The military dictatorship (1976-1983) disappeared an estimated 30,000 people. The Madres de Plaza de Mayo still march weekly for justice. The trauma shaped Argentine democracy and identity permanently.'},
    {cat:'Slang',q:'What does boludo mean and why does context change everything?',options:['Always an insult','Offensive between strangers but affectionate between close friends — like dude — same word, opposite meanings','Always positive','A neutral greeting'],answer:1,exp:'"Boludo" is one of Argentina\'s most fascinating words. Between strangers it\'s an insult. Between close friends it\'s "dude" or "man." Tone and relationship determine everything. Getting it wrong is memorable.'},
  ]},
    'Cuba':{flag:'🇨🇺',lang:'Spanish',questions:[
    {cat:'Food',q:'What is "ropa vieja" and what does the name mean?',options:['Old rice','Old clothes — shredded beef stew that looks like tattered fabric','Leftover food','A dish with old vegetables'],answer:1,exp:'"Ropa vieja" means "old clothes" — the shredded beef looks like tattered rags. Cuba\'s national dish: beef slow-cooked then stewed in tomato sauce with peppers and onions.'},
    {cat:'Music',q:'What is "son cubano" and why does it matter globally?',options:['A Cuban drinking song','The musical root of salsa — a blend of Spanish guitar and African rhythms born in Santiago de Cuba','A classical style','A modern genre'],answer:1,exp:'Son cubano originated in Santiago de Cuba in the late 1800s, blending Spanish guitar with African percussion. It became the foundation of salsa, mambo, and much of global Latin music.'},
    {cat:'Culture',q:'What is a "bodega" in Cuban daily life?',options:['A fancy restaurant','A government-run ration store where Cubans receive subsidized food with their libreta','A neighborhood bar','A farmers market'],answer:1,exp:'In Cuba, a bodega is a state-run store tied to the "libreta" (ration book). Every household gets subsidized quantities of rice, beans, sugar, etc. Central to daily survival.'},
    {cat:'Slang',q:'What does "asere" mean?',options:['An insult','Close friend or buddy — the ultimate Cuban term of camaraderie','A call for help','A type of dance'],answer:1,exp:'"Asere" is the quintessential Cuban term for a close friend. "¡Asere, qué bolá!" is one of the most iconic Cuban greetings — "dude, what\'s up!"'},
    {cat:'Food',q:'What is "congrí" or "moros y cristianos"?',options:['Two separate dishes','Rice and black beans cooked together — a Cuban staple. "Moros" (black beans) and "cristianos" (white rice) refers to the cultural mix','A soup','A dessert'],answer:1,exp:'"Moros y cristianos" is rice and black beans cooked together — a Cuban staple. The name references Cuba\'s racial and cultural history.'},
    {cat:'Music',q:'What is the "Buena Vista Social Club"?',options:['A nightclub in Havana','A 1997 music project that revived classic Cuban son musicians who had been forgotten — became a global phenomenon','A government cultural program','A type of dance hall'],answer:1,exp:'Buena Vista Social Club (1997) gathered elderly Cuban son musicians. The album sold 8 million copies and launched a global Cuban music revival.'},
    {cat:'Culture',q:'What is "el período especial" and what impact did it have?',options:['A political summit','The economic crisis after the Soviet Union collapsed in 1991 — Cubans faced extreme food and fuel shortages','A cultural flowering','A construction boom'],answer:1,exp:'"El Período Especial" (1991-2000) was Cuba\'s devastating economic crisis after Soviet subsidies ended. GDP fell 35%, food became scarce, blackouts lasted 16+ hours daily.'},
    {cat:'Slang',q:'What does "qué bolá" mean?',options:['What ball game?','What\'s up? — Cuba\'s most characteristic greeting','What happened?','What\'s rolling?'],answer:1,exp:'"¿Qué bolá?" is the quintessential Cuban greeting — "what\'s up?" You can\'t spend a day in Cuba without hearing it. Paired with "asere," it\'s pure Havana.'},
    {cat:'Food',q:'What is "picadillo" in Cuban cooking?',options:['A pickled vegetable','Seasoned ground beef with olives, raisins, and tomato sauce — a Cuban comfort food eaten with rice and black beans','A type of bread','A seafood dish'],answer:1,exp:'Picadillo is spiced ground beef with tomato sauce, olives, raisins, and capers — a uniquely Cuban combination of sweet and savory. Served over rice with black beans.'},
    {cat:'Culture',q:'What is "el malecón" and why is it the heart of Havana?',options:['A government building','The 8km seafront esplanade where Havanese gather at all hours — to socialize, fish, watch sunsets, and escape small apartments','A market','A park'],answer:1,exp:'The Malecón is Havana\'s legendary seafront esplanade. Since apartments are small, the Malecón is where people come to breathe, socialize, play music, and watch the sea.'},
    {cat:'Slang',q:'What does "resolver" mean in the Cuban context?',options:['Only to solve a problem','The art of resourcefully figuring things out in a system of scarcity — a fundamental Cuban life skill','A type of negotiation','A business term'],answer:1,exp:'"Resolver" means creatively solving any problem — finding food, obtaining goods, fixing things, navigating bureaucracy. The ability to "resolver" is deeply respected.'},
    {cat:'Music',q:'What is "timba" and how is it different from salsa?',options:['They\'re identical','Timba is Cuba\'s modern evolution of salsa — more complex rhythmically, harder-edged, born in 1990s Havana','Timba is slower and romantic','Timba is from Santiago'],answer:1,exp:'Timba emerged in 1990s Havana as a harder, more complex evolution of Cuban dance music. Bands like NG La Banda created something rawer and more rhythmically demanding.'},
    {cat:'Culture',q:'What is the Cuban concept of "sociolismo"?',options:['A political ideology','A wordplay on "socialismo" and "socio" — getting things through personal connections and favors','An economic policy','A neighborhood committee'],answer:1,exp:'"Sociolismo" blends "socialismo" and "socio" (partner/connection). In Cuba\'s system of scarcity, who you know is often more valuable than money.'},
    {cat:'Food',q:'What is "guarapo"?',options:['A type of coffee','Fresh-squeezed sugarcane juice — ice-cold, sold at street stands, deeply associated with Cuban summer','A rum cocktail','A fruit smoothie'],answer:1,exp:'Guarapo is cold-pressed sugarcane juice sold at street stands. Ice-cold on a hot Havana day, it\'s one of the most refreshing and quintessentially Cuban experiences.'},
    {cat:'History',q:'What is the significance of the "Granma" in Cuba?',options:['A newspaper only','The yacht that brought Fidel Castro and 81 revolutionaries from Mexico to Cuba in 1956 — launching the revolution','A Cuban warship','A fishing vessel'],answer:1,exp:'The "Granma" brought Castro, Che Guevara, and 80 others (82 total) from Mexico to Cuba in December 1956. Most were killed or captured. The survivors launched the revolution from the mountains.'},
    {cat:'Slang',q:'What does "tremendo" mean in Cuban usage?',options:['Terrible only','Tremendous, extreme, intense — used to emphasize anything: "tremendo calor" = insane heat','Just large','Only positive things'],answer:1,exp:'"Tremendo" in Cuba is an intensifier for everything — "tremendo calor" (insane heat), "tremenda fiesta" (amazing party), "tremendo lío" (huge mess).'},
    {cat:'Culture',q:'What is "La Habana Vieja" and why is it significant?',options:['Just an old neighborhood','The historic core of Havana — one of the best-preserved Spanish colonial city centers in the Americas, UNESCO World Heritage Site','A modern tourist development','A government district'],answer:1,exp:'Old Havana (founded 1519) is one of the Western Hemisphere\'s finest preserved colonial city centers. UNESCO listed it in 1982. Despite decades of decay, it remains breathtaking.'},
    {cat:'Daily Life',q:'What does "inventar" mean in the Cuban context?',options:['Just inventing something','To creatively improvise and figure out how to survive with limited resources — a Cuban life philosophy','To lie','To make art'],answer:1,exp:'"Inventar" means creative improvisation under scarcity. When resources are limited, Cubans "invent" — fixing engines with repurposed parts, creating businesses in the shadow economy.'},
    {cat:'Music',q:'Who was Celia Cruz?',options:['A Cuban politician','The "Queen of Salsa" — a Cuban singer who became the most iconic female voice in Latin music history','A classical musician','A folklore singer only'],answer:1,exp:'Celia Cruz was born in Havana and became the undisputed Queen of Salsa. After leaving Cuba in 1960, she recorded over 70 albums. Her cry of "¡Azúcar!" became a cultural rallying call.'},
    {cat:'Food',q:'What is "café cubano" and how is it different?',options:['Just regular espresso','Espresso sweetened with sugar whipped into the first drops — creating a sweet, thick foam called "espuma" — intensely sweet and strong','A large coffee','A cold coffee'],answer:1,exp:'Cuban coffee is made by whipping sugar with the first drops of espresso into a thick foam (espuma). It\'s sweet, strong, and drunk in small cups throughout the day.'},
    {cat:'Music',q:'What is "nueva trova" music?',options:['A modern pop genre','An acoustic singer-songwriter tradition with politically conscious lyrics — Silvio Rodríguez and Pablo Milanés are its icons','A type of salsa','A children\'s music tradition'],answer:1,exp:'"Nueva trova" emerged in the late 1960s as Cuba\'s folk protest music. Silvio Rodríguez and Pablo Milanés became icons with poetic, politically nuanced songs.'},
    {cat:'Culture',q:'What is "el apagón" in modern Cuba?',options:['A dance style','Widespread electricity blackouts that can last 12-20 hours daily — a defining feature of daily Cuban life in recent years','A government program','A festival'],answer:1,exp:'Cuba has faced severe electricity blackouts (apagones) in recent years — sometimes 12-20 hours per day. Families organize their lives around power schedules. Generators and inverters are treasured. It\'s become central to the Cuban experience.'},
    {cat:'Slang',q:'What does "estar en candela" mean in Cuban slang?',options:['To be on fire literally','To be in trouble, in hot water, or in an intense situation','To be very cold','To be happy'],answer:1,exp:'"Estar en candela" means to be in trouble or in an intense, heated situation. "Esto está en candela" = this situation is getting heated/dangerous. Candela (flame/fire) is used in many Cuban expressions.'},
    {cat:'Food',q:'What is "el paladar" in Cuban food culture?',options:['A government restaurant','A small private family restaurant — legalized in the 1990s — one of the first private businesses allowed in Cuba','A type of food','A market'],answer:1,exp:'Paladares are small private restaurants, usually in family homes. They were legalized during the Período Especial in the 1990s as Cuba allowed limited private enterprise. Some have become genuinely excellent and are where you eat best in Cuba.'},

    {cat:'Music',q:'What music did Cuba give the world that became a foundation of American jazz?',options:['Only salsa','Cuban rhythms — the clave, mambo, cha-cha-chá, and son cubano — deeply influenced American jazz, funk, and R&B, giving birth to Afro-Cuban jazz','Cuba only received American music','Only classical music'],answer:1,exp:'The clave rhythm (a 3-2 or 2-3 pattern) from Cuban music became foundational to jazz and Latin music globally. Artists like Dizzy Gillespie and Chano Pozo fused Cuban rhythms with jazz in the 1940s, creating Afro-Cuban jazz. Salsa itself grew from Cuban son mixed with New York energy.'},
    {cat:'Culture',q:'What is the cultural significance of Cuban cigars?',options:['Just a product','They became a global luxury symbol — the combination of Cuba\'s climate, soil, and centuries of craft made Habanos (Cuban cigars) the gold standard, famously loved by Winston Churchill and JFK','Only significant in Cuba','A recent development'],answer:1,exp:'Cuban cigars are one of the world\'s great luxury items. The Vuelta Abajo region produces tobacco considered the finest on earth. JFK reportedly ordered 1,200 H. Upmann petit coronas the day before signing the Cuban embargo. They remain banned for import to the US.'},
    {cat:'Food',q:'What Cuban dish became iconic in Miami and Cuban-American culture?',options:['Only rice and beans','The Cuban sandwich — ham, roasted pork, Swiss cheese, pickles, mustard on Cuban bread, pressed flat — became the signature food of Miami\'s Cuban exile community','Ropa vieja is unknown outside Cuba','Only in Cuba City'],answer:1,exp:'The Cuban sandwich (Cubano) is the food that traveled. Miami and Tampa both claim the original. Cuban bread — made with lard and a palm frond scored on top — is itself a cultural artifact. The sandwich became a symbol of Cuban-American identity in South Florida.'},
    ]},
    'Spain':{flag:'🇪🇸',lang:'Spanish',questions:[
    {cat:'Food',q:'What is the difference between "tapas" and "pinchos"?',options:['Same thing','Tapas are shared dishes; pinchos are bites on bread skewered with toothpick — typical in the Basque Country','Tapas are free; pinchos are paid','Tapas cold; pinchos hot'],answer:1,exp:'Tapas are shared table dishes. Pintxos are bar snacks on bread — you grab them yourself from the counter.'},
    {cat:'Culture',q:'Is "la siesta" still widely practiced in modern Spain?',options:['Everyone takes one daily','Mostly a myth — urban Spaniards rarely nap, though businesses may close midday','Only on Sundays','Only for children'],answer:1,exp:'Businesses closing 2-5pm is still common, but actual napping is mostly rural or elderly. The real reason is heat and long lunch culture.'},
    {cat:'Slang',q:'What does "tío/tía" mean in casual Spanish?',options:['Only aunt/uncle','Dude or guy/girl — like "man" in English','A formal term','Only means friend'],answer:1,exp:'"Tío/tía" literally means uncle/aunt but is used constantly as "dude" or "mate." "¡Tío, qué fuerte!" = "Dude, that\'s wild!"'},
    {cat:'Culture',q:'What is "La Tomatina" festival?',options:['A cooking competition','A massive tomato-throwing fight in Buñol, Valencia — no competition, pure chaos','A harvest display','A religious procession'],answer:1,exp:'La Tomatina happens the last Wednesday of August — tens of thousands throw overripe tomatoes for about an hour. Pure fun, no winners.'},
    {cat:'Food',q:'What is "jamón ibérico de bellota" and why is it revered?',options:['Just any cured ham','Cured ham from free-range pigs that eat only acorns — one of Spain\'s most prized delicacies','A cheap everyday food','Only from one region'],answer:1,exp:'"Jamón ibérico de bellota" comes from pigs roaming oak forests eating only acorns. The fat marbles through the meat. A leg can cost hundreds of euros.'},
    {cat:'Culture',q:'What is "el horario español" (Spanish schedule)?',options:['Shorter hours than Europe','Spain runs 1-2 hours later than Europe — lunch at 3pm, dinner at 10pm, clubs at 2am — completely normal','Only in summer','Only in cities'],answer:1,exp:'Spain runs 1-2 hours later than surrounding countries — a legacy of Franco adopting Central European time. Dinner at 10pm and clubs at 2am are genuinely normal.'},
    {cat:'Slang',q:'What does "venga" mean in Spain?',options:['Come here only','All-purpose — come on, okay, let\'s go, bye, sure, hurry up','Only a command','An insult'],answer:1,exp:'"Venga" is an all-purpose word in Spain. "Venga, hasta luego!" = "Okay, bye!" You\'ll hear it dozens of times a day.'},
    {cat:'Food',q:'What makes "tortilla española" controversial?',options:['A Mexican flatbread','A potato-egg omelette — the "with or without onion" debate is one of Spain\'s most passionate food arguments','A simple egg dish','Only from Catalonia'],answer:1,exp:'The con/sin cebolla (with/without onion) debate is fierce. Families are divided. There is no wrong answer, but everyone has a strong opinion.'},
    {cat:'Culture',q:'What was "la Movida Madrileña"?',options:['A traffic problem','The cultural explosion in Madrid after Franco\'s death — art, music, sexual freedom erupting after 40 years of dictatorship','A festival','A political movement'],answer:1,exp:'"La Movida" was creative and social explosion after Franco\'s death — Pedro Almodóvar, punk music, sexual openness. Spain went from most repressive to most liberal in Europe in a decade.'},
    {cat:'Slang',q:'What does "guay" mean?',options:['Foreign or strange','Cool or great — specifically Spanish Spain slang','An insult','Old-fashioned'],answer:1,exp:'"Guay" is specifically Spain slang for cool. Latin Americans don\'t use it and will immediately identify you as from Spain.'},
    {cat:'Culture',q:'What is "las Fallas" festival in Valencia?',options:['A flower festival','Enormous papier-mâché sculptures displayed then ceremonially burned on March 19 — with massive fireworks','A bullfighting festival','A carnival'],answer:1,exp:'Las Fallas features enormous satirical sculptures (ninots) displayed throughout Valencia. On March 19, almost all are burned in La Cremà. Constant firecrackers for a week.'},
    {cat:'Slang',q:'What does "flipar" mean?',options:['A type of swimming','To be amazed or blown away','To flip something','A dance move'],answer:1,exp:'"Flipar" means to be blown away or amazed. "Me flipa este sitio" = I love/am amazed by this place. Very Spanish Spain slang.'},
    {cat:'Food',q:'What is "sobremesa" and why is it uniquely Spanish?',options:['A type of dessert','The long conversation at the table after a meal — sometimes hours, considered the best part','A type of cheese','A pre-dinner drink'],answer:1,exp:'"Sobremesa" (over the table) is the long conversation after a meal. Leaving immediately is rude. The best meals extend for hours past the last bite. English has no word for this.'},
    {cat:'Slang',q:'What does "mola" mean?',options:['A type of fabric','Something is cool or you like it — "eso mola mucho" = that\'s really cool','An insult','A greeting'],answer:1,exp:'"Molar" means to be cool or to like something. Very distinctly Peninsular Spanish.'},
    {cat:'Culture',q:'What are "botellones" in Spanish youth culture?',options:['A type of drink','Large outdoor gatherings where young people bring their own alcohol — a social institution responding to expensive bars','Music festivals','Illegal gatherings'],answer:1,exp:'"Botellón" is when young Spaniards gather in public with their own drinks. A response to expensive bars, a tradition, and a right of passage.'},
    {cat:'Food',q:'When do Spaniards actually eat dinner?',options:['Dinner at 6-7pm like northern Europe','Before 9pm is for tourists — most Spaniards eat between 9-11pm, restaurants fill up at 10pm','8pm is normal','Only in Madrid is dinner late'],answer:1,exp:'Eating dinner at 6pm in Spain is very unusual. Most eat between 9-11pm. Restaurants before 9pm are full of tourists. This is nationwide.'},
    {cat:'Slang',q:'What does "ostras!" express?',options:['A love of oysters','A mild exclamation of surprise or frustration — the polite version; "ostia" is stronger','A greeting','A farewell'],answer:1,exp:'"Ostras" is the polite exclamation. "Ostia/hostia" is stronger. Both express surprise, frustration, or emphasis.'},
    {cat:'Culture',q:'What is the political sensitivity of Catalan and Basque identity?',options:['Minor regional pride only','Deep political tension — both have strong independence movements, distinct languages, complex relationships with Madrid','Only historical','Only academic'],answer:1,exp:'Catalonia held an unofficial independence referendum in 2017. The Basque separatist group ETA caused decades of violence. Regional languages and identity are fiercely protected.'},
    {cat:'Food',q:'What is "churros con chocolate" culture in Spain?',options:['A children\'s breakfast only','A beloved late-night tradition — eaten at 4-7am after clubbing, also on Sunday mornings','A Christmas food only','An afternoon snack only'],answer:1,exp:'In Spain, churros con chocolate is the perfect post-party food — eaten at 4-7am in a churrería after a night out. The thick chocolate is a dipping sauce, not a drink.'},
    {cat:'Culture',q:'What is "duende" in Spanish culture?',options:['A type of elf','An untranslatable quality of intense emotional power in art — especially flamenco — that gives you chills','A musical term','A type of folklore'],answer:1,exp:'"Duende" is what flamenco performers seek — raw emotion that makes art transcend technique. Federico García Lorca wrote an essay on it.'},
    {cat:'Slang',q:'What does "¡Que sí!" mean?',options:['A simple yes','An emphatic "I\'m telling you it\'s true!" — used when insisting against doubt','A formal agreement','A polite response'],answer:1,exp:'"¡Que sí!" emphatically insists something is true in the face of doubt. "¡Que sí, te lo juro!" = "I\'m telling you, I swear!" Very alive in Spanish argument culture.'},
    {cat:'Food',q:'What is "cocido madrileño" and when is it eaten?',options:['A light summer dish','A slow-cooked chickpea stew with meats — Madrid\'s ultimate winter comfort food, traditionally eaten on Thursdays','A breakfast dish','A dessert'],answer:1,exp:'"Cocido madrileño" is Madrid\'s quintessential winter dish — chickpeas with multiple meats, served in three courses. Traditionally eaten on Thursdays.'},
    {cat:'Culture',q:'What is "el peloteo" in Spanish office culture?',options:['A type of sport','Excessive flattery of the boss — acknowledged and quietly scorned but seemingly effective','A workplace policy','A team-building exercise'],answer:1,exp:'"El peloteo" means excessive sycophancy. Everyone recognizes the "pelota" (suck-up), everyone complains, yet somehow it seems to work.'},

    {cat:'History',q:'What did Spain give the Americas that still shapes culture today?',options:['Only language','The Spanish language, Catholicism, architecture, food crops, and governance structures — Spanish colonization created the entire Spanish-speaking world from Mexico to Argentina','Only trade routes','Only the Spanish Inquisition'],answer:1,exp:'Spain\'s colonization of the Americas (1492 onwards) created the Spanish-speaking world. The language, Catholic church architecture, legal systems, and food culture (bringing cattle, pigs, wheat, and olive oil) all trace to Spain. The Americas also transformed Spain — tomatoes, potatoes, and chocolate all came back to Europe.'},
    {cat:'Food',q:'What Spanish food concept became a global restaurant trend?',options:['Only paella is known','Tapas — small shared plates — became a worldwide dining format. The concept of many small dishes shared at the table spread from Spain to restaurants globally','Tortilla española is the only export','Only sangria is internationally known'],answer:1,exp:'Tapas culture — ordering multiple small dishes to share — transformed global restaurant culture. The word "tapas" is now used on menus worldwide. The concept of grazing and sharing rather than individual plates traces back to Andalusian bar culture. Spanish cuisine (Ferran Adrià, elBulli) also pioneered molecular gastronomy.'},
    {cat:'Culture',q:'What is the Spanish siesta and does it still exist?',options:['Everyone still takes 3-hour naps','The midday rest tradition is largely gone in cities — modern Spain mostly works standard hours — but the stereotype persists globally. It originated from agricultural rhythms avoiding peak afternoon heat','Only in rural areas ever','It was never real'],answer:1,exp:'The siesta stereotype is mostly outdated for urban Spaniards. Younger generations in Madrid and Barcelona work standard hours. However, some small towns and businesses still close midday. The tradition came from agricultural workers avoiding the intense afternoon sun — practical origins, now a persistent cultural myth abroad.'},
    ]},
  'Brazil':{flag:'🇧🇷',lang:'Portuguese',questions:[
    {cat:'Food',q:'What is "feijoada" and when is it traditionally eaten?',options:['A light breakfast','A black bean and pork stew eaten on Saturdays — the national dish','A quick street snack','A dessert from Rio'],answer:1,exp:'Feijoada is Brazil\'s national dish — a rich black bean stew with pork, served with rice, farofa, orange slices, and collard greens. Saturdays are feijoada day.'},
    {cat:'Culture',q:'What does "saudade" mean?',options:['Simple sadness','A deep bittersweet longing for something absent — a person, place, or time that may never return','Homesickness only','Nostalgia about childhood'],answer:1,exp:'"Saudade" is a uniquely Portuguese/Brazilian emotional state — a melancholy longing for something absent. English has no single equivalent.'},
    {cat:'Music',q:'What is the connection between "baile funk" and Rio\'s favelas?',options:['A classical tradition from the upper class','It originated in the favelas mixing Miami bass with Brazilian rhythms — now global','A type of samba from the 1940s','It originated in São Paulo'],answer:1,exp:'Baile funk was born in Rio\'s favelas in the late 1980s, blending Miami bass with Portuguese lyrics. Favela funk parties are massive community events.'},
    {cat:'Slang',q:'What does "mano" or "cara" mean in Brazilian slang?',options:['An insult','Both mean dude or man — used constantly in casual conversation regardless of gender','Formal address','A term for older people'],answer:1,exp:'"Mano" and "cara" are the Brazilian equivalents of "dude" or "man." Used by all genders and ages in casual speech.'},
    {cat:'Culture',q:'What is "jeitinho brasileiro"?',options:['A dance technique','The cultural art of finding creative workarounds to problems — bending rules with creativity and charm','A cooking style','A type of capoeira move'],answer:1,exp:'"Jeitinho brasileiro" is the uniquely Brazilian ability to find a clever solution to any obstacle, often by bending rules. Seen as both a cultural strength and challenge.'},
    {cat:'Food',q:'What is "churrasco" Brazilian style and how does it differ from Argentine asado?',options:['They are identical','Brazilian churrasco uses different cuts on metal skewers and a more aggressive fire; rodízio restaurants rotate them tableside','Churrasco is only from Rio','Argentine asado is faster'],answer:1,exp:'Brazilian churrasco features cuts on long metal skewers over intense heat. Rodízio churrascarias bring skewers to your table continuously — a distinct experience from Argentine asado.'},
    {cat:'Music',q:'What is "samba" and where does it come from?',options:['A dance invented in Rio for Carnival only','A music and dance tradition with African roots — born in Rio\'s working-class communities, now the heartbeat of Brazilian identity','A European ballroom dance adapted in Brazil','A modern pop genre'],answer:1,exp:'Samba has deep African roots — brought by enslaved people from Angola and West Africa. It evolved in Rio\'s working-class communities and became the defining expression of Brazilian cultural identity.'},
    {cat:'Slang',q:'What does "saudade" feel like as a daily emotion?',options:['It\'s only for major losses','Brazilians and Portuguese feel it for small things too — a song, a smell, a childhood memory — it\'s a gentle, present feeling','It\'s always intense and dramatic','It\'s only felt by older generations'],answer:1,exp:'"Saudade" isn\'t just for tragedies. Hearing an old song, smelling something familiar, seeing a photo — these trigger a gentle, bittersweet ache that Brazilians and Portuguese navigate daily.'},
    {cat:'Culture',q:'What is "Carnaval" really about beyond the parades?',options:['Purely a tourist spectacle','A profound cultural event where social hierarchies temporarily dissolve — anyone can be anything for five days','A religious festival','Just a party'],answer:1,exp:'Carnaval is one of the world\'s great social equalizers — for five days, class, race, and status blur. The samba school parades are year-long community projects. Street parties (blocos) are genuinely democratic.'},
    {cat:'Slang',q:'What does "saudade" signal when a Brazilian says it to you?',options:['Just politeness','That they genuinely miss you or miss time with you — it\'s a warm, heartfelt expression, not small talk','A formal goodbye','That something bad happened'],answer:1,exp:'When a Brazilian says "tenho saudade de você" (I have saudade of you), it\'s genuinely emotional — they miss you in that deep, aching way. It\'s not small talk.'},
    {cat:'Music',q:'What is "bossa nova" and what made it revolutionary?',options:['Just a slow samba','A sophisticated fusion of samba rhythms with jazz harmonies — invented in Rio in the late 1950s, it changed global music','A traditional folk music','A dance competition style'],answer:1,exp:'Bossa nova emerged in Rio in 1958 with João Gilberto and Tom Jobim — it blended samba\'s rhythm with jazz\'s harmonics into something intimate and revolutionary. "The Girl from Ipanema" made it global.'},
    {cat:'Culture',q:'What is "jogo bonito" and why does it matter beyond football?',options:['Just a football term','The beautiful game — a philosophy of playing with creativity, joy, and flair that reflects a broader Brazilian cultural value','A type of music','A carnival tradition'],answer:1,exp:'"Jogo bonito" (the beautiful game) is Brazil\'s football philosophy — prioritizing creativity and joy over pure efficiency. It reflects a broader Brazilian value of doing things with flair and beauty.'},
    {cat:'Slang',q:'What does "vai se f..." or "vai tomar banho" mean in Brazilian slang?',options:['An invitation to swim','A strong dismissal — "go take a bath" is the polite version of "get lost," used between friends and in frustration','A compliment','A greeting'],answer:1,exp:'"Vai tomar banho" (go take a bath) is the polite version of a strong dismissal. Between close friends it\'s playful; with aggression it\'s a real insult. Context is everything.'},
    {cat:'Culture',q:'What is "the carioca" spirit?',options:['Just someone from Rio','A lifestyle attitude — relaxed, beach-loving, living in the moment, not taking things too seriously','A type of dance','A type of coffee'],answer:1,exp:'"Carioca" describes someone from Rio de Janeiro, but also an attitude — relaxed, sociable, beach-oriented, living for the moment. Residents of other cities both envy and mock it.'},
    {cat:'Food',q:'What is "pão de queijo" and why do Brazilians love it so much?',options:['A type of cheese','A chewy, cheese-filled bread ball from Minas Gerais — eaten at breakfast and snack time across the country','A dessert from São Paulo','A savory pastry only from Rio'],answer:1,exp:'"Pão de queijo" (cheese bread) is a national obsession — naturally gluten-free, chewy, warm, with melted cheese inside. Invented in Minas Gerais and now eaten everywhere, every day.'},
    {cat:'Slang',q:'What does "legal" mean in Brazilian slang?',options:['Only the legal/lawful meaning','Cool, great, or awesome — "isso é muito legal!" = that\'s really cool','Just formal','Only in older speech'],answer:1,exp:'"Legal" in Brazilian Portuguese slang means cool or great. "Muito legal!" = very cool! One of the most common positive expressions in Brazilian casual speech.'},
    {cat:'Culture',q:'What is "the race question" in Brazil vs the US?',options:['Brazil and the US have identical racial histories','Brazil has "racial democracy" as a national myth — the reality is more complex, with significant inequality, but race is discussed differently than in the US','Brazil has no racial issues','Only academic discussions differ'],answer:1,exp:'Brazil\'s "racial democracy" myth — that races coexist harmoniously — is contested. Significant racial inequality exists, but conversations about race are different from the US — more about shades and mixing, less binary.'},
    {cat:'Food',q:'What is "caipirinha" and what makes it Brazil\'s national cocktail?',options:['A type of juice','Cachaça, lime, and sugar — Brazil\'s national cocktail, made with sugarcane spirit, deeply tied to social culture','A type of beer','A wine-based drink'],answer:1,exp:'Caipirinha is made with cachaça (sugarcane spirit), fresh lime, and sugar. Simple, potent, and deeply embedded in Brazilian social life. Cachaça itself predates Brazilian independence.'},
    {cat:'Slang',q:'What does "oxente" or "eita" express in Brazilian Portuguese?',options:['Only in formal contexts','Exclamations of surprise, amazement, or emphasis — "eita!" is nationwide; "oxente" is distinctly Northeastern','An insult','A farewell'],answer:1,exp:'"Eita!" is a nationwide Brazilian exclamation of surprise. "Oxente!" is distinctly from the Northeast (Nordeste) — a marker of regional identity that Northeasterners use with pride.'},
    {cat:'Culture',q:'What is the significance of "the Nordeste" in Brazilian culture?',options:['Just a poor region','The cultural heartland of Brazil — birthplace of forró music, cordel literature, and many of the country\'s greatest cultural exports','Only important historically','A homogeneous region'],answer:1,exp:'The Northeast (Nordeste) is culturally the most distinctive Brazilian region — birthplace of forró music, cangaço outlaws, and one of the world\'s richest folkloric traditions. Northeasterners have a fierce regional pride.'},
    {cat:'Music',q:'What is "forró" and what does it mean for Northeastern Brazil?',options:['Just a type of food','A syncopated folk dance and music tradition from the Northeast — deeply tied to São João festival and regional identity','A type of samba','A modern electronic genre'],answer:1,exp:'"Forró" is the musical soul of Northeastern Brazil — accordion-driven, syncopated, deeply associated with Festa Junina and São João celebrations. For Northeasterners in other cities, it\'s a lifeline to home.'},
    {cat:'Culture',q:'What is Brazil\'s "jeitinho" as applied to bureaucracy?',options:['Brazil has very efficient bureaucracy','Creative navigation around Brazil\'s notoriously complex bureaucracy — a survival skill','A legal shortcut','Only practiced by the wealthy'],answer:1,exp:'Brazil\'s bureaucracy ("burocracia") is legendary for complexity. The "jeitinho" applied to bureaucracy means finding creative, sometimes unofficial paths through paperwork — a daily survival skill.'},
    {cat:'Slang',q:'What does "tá bom" vs "tá ótimo" signal?',options:['They mean the same thing','Tá bom = fine/okay (mild acceptance); tá ótimo = great/perfect (enthusiastic) — the distinction matters in reading Brazilian enthusiasm','Only formal contexts','Both mean excellent'],answer:1,exp:'"Tá bom" means "okay" or "fine" — a mild acceptance. "Tá ótimo" means "perfect" or "great." When a Brazilian says "tá bom" without energy, they may just be agreeing politely rather than genuinely enthusiastically.'},

    {cat:'Music',q:'What music did Brazil give the world that influenced jazz and pop globally?',options:['Only samba','Bossa nova — created in Rio in the late 1950s, it fused samba with cool jazz and became globally influential. "The Girl from Ipanema" is one of the most recorded songs in history','Only funk carioca','Forró is the main export'],answer:1,exp:'Bossa nova (literally "new trend") was born in Rio de Janeiro\'s Zona Sul apartments in the late 1950s. João Gilberto, Tom Jobim, and Vinícius de Moraes created a sound that captivated the world. "The Girl from Ipanema" has been covered thousands of times and introduced millions to Brazilian Portuguese.'},
    {cat:'Sports',q:'Why is Brazilian football (soccer) culturally different from everywhere else?',options:['Brazil just wins more','Brazilian futebol developed its own aesthetic called "jogo bonito" (beautiful game) — technically brilliant, expressive, creative play that prioritizes flair alongside winning','They have better facilities','Only because of Pelé'],answer:1,exp:'"Jogo bonito" — the beautiful game — is Brazil\'s football philosophy. Players like Pelé, Ronaldo, Ronaldinho, and Neymar embodied skill, creativity, and joy as much as results. Brazilian football culture is inseparable from national identity — the 1950 World Cup loss (Maracanazo) is still a national trauma.'},
    {cat:'Culture',q:'What is Carnival and why is it culturally significant beyond the party?',options:['Just a big party','Brazil\'s Carnival is a profound cultural expression — samba schools spend the entire year creating elaborate floats and costumes that tell stories about Brazilian history, politics, and identity','Only in Rio','A recent tourist invention'],answer:1,exp:'Rio\'s Carnival is more than spectacle — samba schools (comunidades) from favelas spend a year creating multi-float parades that tell complex stories. It\'s a space where working-class communities get global attention for their art. The Sambadrome parade is a competitive art form judged on music, dance, and storytelling.'},
    ]},
  'France':{flag:'🇫🇷',lang:'French',questions:[
    {cat:'Food',q:'What do you get when you order "un café" in France?',options:['A large drip coffee','A small espresso — always','A café au lait','You must specify'],answer:1,exp:'In France, "un café" is always a small espresso. For milk, ask for "un crème." Expecting drip coffee will confuse waitstaff.'},
    {cat:'Culture',q:'How many kisses in "la bise" greeting?',options:['Always two nationwide','Varies by region — Paris 1-2, south does 3-4, locals sometimes collide','Always one on the right cheek','Only between women'],answer:1,exp:'"La bise" varies chaotically. Even French people sometimes awkwardly go the wrong direction.'},
    {cat:'Slang',q:'What does "bof" express?',options:['Strong agreement','Enthusiasm','Total indifference — the ultimate French shrug','Anger'],answer:2,exp:'"Bof" is the French verbal shrug — "meh." If someone reviews your cooking with "bof," that\'s not a compliment.'},
    {cat:'Culture',q:'Why is "le droit à la déconnexion" a French law?',options:['Protect children','Employees can ignore work emails outside office hours','Bans internet on Sundays','Cybersecurity'],answer:1,exp:'France\'s 2017 law gives workers the right to disconnect from work outside hours — reflecting the value of work-life separation.'},
    {cat:'Food',q:'What causes heated debate: "pain au chocolat" vs "chocolatine"?',options:['Two different pastries','The exact same pastry — the name you use reveals where you\'re from in France','One has more chocolate','One is savory'],answer:1,exp:'Same pastry, different name. Paris says "pain au chocolat," the southwest says "chocolatine." Arguments get genuinely heated.'},
    {cat:'Slang',q:'What does "c\'est nul" mean?',options:['It\'s zero','It\'s rubbish or terrible','It\'s nothing special','Legally invalid'],answer:1,exp:'"C\'est nul" means "it\'s rubbish" or "that sucks." Used constantly to express disappointment or poor quality.'},
    {cat:'Culture',q:'What does "métro, boulot, dodo" capture?',options:['A Paris metro line','Metro, work, sleep — the monotonous daily grind','A jazz genre','A children\'s rhyme'],answer:1,exp:'"Métro, boulot, dodo" captures the repetitive urban grind. Used to complain about having no time for life outside work.'},
    {cat:'Food',q:'What is "apéro" culture in France?',options:['A formal dinner tradition','Pre-dinner drinks and snacks — a social ritual that often replaces dinner','A type of dessert','A breakfast tradition'],answer:1,exp:'"Apéro" is a French institution — drinks with nibbles, deeply social, often starting at 7pm and running so long nobody wants dinner.'},
    {cat:'Slang',q:'What does "avoir le cafard" mean?',options:['Cockroach problem','To feel down or depressed','To be angry','To be exhausted'],answer:1,exp:'"Avoir le cafard" (to have the cockroach) means feeling blue or depressed. The expression is traced to Baudelaire.'},
    {cat:'Culture',q:'What is France\'s strike culture?',options:['The right to vote','The right to strike — France has one of Europe\'s highest strike rates, deeply embedded in culture','Right to peaceful protest','Labor law about breaks'],answer:1,exp:'France has a deep strike culture. Workers strike frequently and unashamedly — it\'s seen as a legitimate democratic tool.'},
    {cat:'Food',q:'What makes a French baguette legally different?',options:['No regulations','The "pain de tradition" law — only flour, water, yeast, and salt, made on-site, no additives','Must be a specific length','Bakers need a national license'],answer:1,exp:'The 1993 "pain de tradition" law protects artisan bread — no additives, made on-site. That\'s why a real boulangerie baguette tastes different.'},
    {cat:'Slang',q:'What does "genre" mean in French youth slang?',options:['Only the literary term','Like or sort of — a constant filler word: "c\'est genre super cool"','A music category','A film type'],answer:1,exp:'"Genre" as filler means "like" in youth French — identical to how English speakers overuse "like."'},
    {cat:'Culture',q:'What is "laïcité" and why is it fundamental?',options:['A cooking technique','Strict separation of church and state — shapes education, headscarves, public life','A regional custom','A holiday'],answer:1,exp:'"Laïcité" means religion stays private. No religious symbols in public schools or government. A core republican value, deeply controversial in multicultural France.'},
    {cat:'Slang',q:'What does "c\'est la galère" mean?',options:['It\'s a famous ship','It\'s a nightmare or real struggle','It\'s delicious','It\'s unbelievable'],answer:1,exp:'"La galère" (galley ship) means a terrible ordeal. "C\'est la galère" = "It\'s a nightmare." "Galérer" = to struggle through something.'},
    {cat:'Culture',q:'What are "les grandes écoles" and why do they matter?',options:['Primary schools','Elite schools separate from universities — graduates virtually guarantee top careers','Regional high schools','Government training centers'],answer:1,exp:'Les grandes écoles (ENA, Polytechnique, HEC) produce a disproportionate share of French presidents, ministers, and CEOs.'},
    {cat:'Food',q:'What is "terroir" in French food philosophy?',options:['A cooking technique','Food expresses the specific land, climate, and culture where it was produced','A restaurant rating','A type of market'],answer:1,exp:'"Terroir" captures the French belief that wine and cheese express the specific character of their place of origin.'},
    {cat:'Slang',q:'What does "kiffer" mean?',options:['To steal','To really like or enjoy — "je kiffe trop cette chanson" = I love this song','To argue','To work hard'],answer:1,exp:'"Kiffer" (from Arabic slang) means to really enjoy something. Very common in French youth culture.'},
    {cat:'Culture',q:'Why don\'t real French speakers say "nous"?',options:['They\'re the same','In spoken French "on" has almost entirely replaced "nous" — using "nous" sounds written and formal','They mean different things','Only Parisians use "on"'],answer:1,exp:'Nobody says "nous allons" in casual speech — they say "on va." Using "nous" in conversation makes you sound like a textbook.'},
    {cat:'Slang',q:'What does "avoir le seum" mean?',options:['To be lucky','To be deeply annoyed or bitter — from Arabic slang','To be happy','To be tired'],answer:1,exp:'"Avoir le seum" (from Arabic for venom) means to be bitter or wronged. Very common in contemporary French urban slang.'},
    {cat:'Food',q:'What is the French paradox?',options:['French people seem rude but are friendly','Low heart disease despite a rich diet of cheese and wine','Paris is romantic but stressful','French fashion is expensive but simple'],answer:1,exp:'The French paradox: relatively low cardiovascular disease despite eating cheese, butter, and foie gras. Attributed to red wine, portion sizes, and slow eating culture.'},
    {cat:'Culture',q:'What is "foie gras" and why is it controversial internationally but defended in France?',options:['A simple pâté','Fatty liver from force-fed ducks — banned in some countries but classified as protected cultural heritage in France','A type of cheese','A fish dish'],answer:1,exp:'Foie gras production (gavage) is banned in California and elsewhere but is protected cultural heritage in France. A genuine values clash between animal welfare and culinary tradition.'},
    {cat:'Slang',q:'What does "franchement" signal?',options:['It means French','Frankly or honestly — prefaces a direct or blunt statement','A polite opener','A regional expression'],answer:1,exp:'"Franchement" signals honesty is coming. "Franchement, c\'est pas terrible" = "Honestly, it\'s not great." French directness is respected as authentic.'},
    {cat:'Culture',q:'What is the French attitude toward lingering after meals?',options:['French people leave immediately after eating','Long conversation after meals is expected — leaving right after eating is considered rude','Only in southern France','Only at dinner parties'],answer:1,exp:'Like Spanish "sobremesa," French meals extend well past the last bite. Long conversations over wine are expected. Rushing off after eating is considered impolite.'},

    {cat:'Culture',q:'How did French culture shape American fine dining?',options:['It had little influence','Enormously — French technique (sauces, knife skills, kitchen brigade) became the foundation of American culinary training. Julia Child brought French cooking to American homes. The CIA (Culinary Institute) built its curriculum on French methods','Only in fancy restaurants','Only recently'],answer:1,exp:'Julia Child\'s "Mastering the Art of French Cooking" (1961) changed how Americans cooked at home. French culinary school techniques — mise en place, mother sauces, the brigade system — are the backbone of professional American kitchens. "French" became synonymous with quality dining in America for decades.'},
    {cat:'Media',q:'What French film movement influenced American cinema?',options:['France only makes foreign films','The French New Wave (Nouvelle Vague) — Godard, Truffaut, and others in the 1950s-60s revolutionized filmmaking technique and directly influenced American directors like Scorsese, Tarantino, and Coppola','Only Charlie Chaplin','Only recent French films matter'],answer:1,exp:'The French New Wave\'s jump cuts, handheld cameras, and non-linear storytelling were radical. Quentin Tarantino has cited Godard extensively. Scorsese learned from Truffaut. Many techniques Americans now take for granted in Hollywood — location shooting, improvised dialogue — came from French filmmakers rebelling against studio conventions.'},
    {cat:'Food',q:'What French food culture concept changed how Americans think about eating?',options:['Only croissants matter','The French approach to food — eating slowly, savoring quality over quantity, treating meals as social rituals — inspired American food movements. The "French Women Don\'t Get Fat" phenomenon and farm-to-table culture both drew from French ideas','France only exported wine','French food is too expensive for influence'],answer:1,exp:'The French paradox — rich food, less obesity — fascinated Americans. French food culture emphasizes quality ingredients, small portions, long meals, and no snacking. Alice Waters\' Chez Panisse and the farm-to-table movement drew explicitly from French market culture. The slow food movement has French philosophical roots.'},
    ]},
  'Japan':{flag:'🇯🇵',lang:'Japanese',questions:[
    {cat:'Culture',q:'What is "tatemae" vs "honne"?',options:['Two types of food','Tatemae is the public face; honne is true feelings — rarely expressed directly','Two dialects','Morning and evening greetings'],answer:1,exp:'"Tatemae" (public facade) and "honne" (true feelings) are central to Japanese interaction. Much communication happens in the space between them.'},
    {cat:'Culture',q:'What does "chotto muzukashii" really mean?',options:['Slightly challenging','A polite indirect no','Need more time','Asking for help'],answer:1,exp:'"Chotto muzukashii" (a little difficult) is a classic indirect "no." Saying no directly is impolite in Japan.'},
    {cat:'Food',q:'What is "mottainai"?',options:['A type of ramen','A philosophy of not wasting anything','A cooking method','A word for delicious'],answer:1,exp:'"Mottainai" expresses regret at waste. It drives Japanese food culture — finishing your plate, using every part of an ingredient.'},
    {cat:'Culture',q:'What is "kawaii" culture really about?',options:['A martial arts tradition','A deep aesthetic of cuteness in fashion, design, food, and daily life','An anime genre','A children\'s brand'],answer:1,exp:'"Kawaii" is a full aesthetic philosophy — present in Harajuku fashion, character bento boxes, corporate mascots, and tax office logos.'},
    {cat:'Culture',q:'What is "nemawashi" in Japanese professional culture?',options:['A garden technique','Building consensus informally before formal meetings — decisions are made before the meeting begins','A management style','A presentation format'],answer:1,exp:'"Nemawashi" means consulting everyone informally first. Japanese meetings rarely decide anything — they ratify what was agreed in private conversations.'},
    {cat:'Slang',q:'What does "otsukaresama" mean?',options:['Goodbye in all contexts','Thank you for your hard work — said constantly at end of workday or after any effort','Good morning','A formal greeting to seniors'],answer:1,exp:'"Otsukaresama" acknowledges shared effort — said when colleagues leave, after completing tasks, after sports. Deeply social and constantly used.'},
    {cat:'Culture',q:'What is "gaman" and how does it shape Japan?',options:['A type of wrestling','Patient endurance in the face of difficulty — a core Japanese virtue','A cooking method','A festival'],answer:1,exp:'"Gaman" means bearing the unbearable with dignity. It\'s credited for Japan\'s orderly disaster response — no looting, patient queuing, composure under pressure.'},
    {cat:'Food',q:'What are the chopstick rules in Japan?',options:['Stick them upright in rice — efficient','Never stick them upright in rice (funeral offering) or pass food chopstick-to-chopstick (funeral ritual)','Cross them when done','Wave them to call a waiter'],answer:1,exp:'Sticking chopsticks upright in rice mimics funeral incense. Passing food chopstick-to-chopstick mimics how bones are passed at cremations. Both are serious faux pas.'},
    {cat:'Culture',q:'What is "wa" (和) and why is it fundamental?',options:['A type of traditional house','Harmony — maintaining group cohesion and avoiding conflict','A musical genre','A type of poetry'],answer:1,exp:'"Wa" (harmony) is a foundational Japanese value. "The nail that sticks up gets hammered down" reflects this — standing out and direct confrontation are avoided.'},
    {cat:'Slang',q:'What does "meccha" mean?',options:['A robot','Very or extremely — "meccha umai" = extremely delicious','A food','Only used in Osaka'],answer:1,exp:'"Meccha" is Osaka slang for "very" that spread nationwide. "Meccha kawaii" = extremely cute.'},
    {cat:'Slang',q:'What does "mendokusai" mean?',options:['Interesting','Troublesome or too much effort','Delicious','Beautiful'],answer:1,exp:'"Mendokusai" means something is a pain or hassle. "Mendokusai naa" is a daily complaint. Very honest and very Japanese.'},
    {cat:'Culture',q:'What is "ikigai" and how does it relate to longevity?',options:['A tea ceremony','A reason for being — intersection of love, skill, world need, and income — linked to Okinawa\'s centenarians','A meditation practice','A diet plan'],answer:1,exp:'"Ikigai" (reason for being) is considered one reason Okinawa has the world\'s highest concentration of centenarians. Purpose and meaning extend life.'},
    {cat:'Food',q:'What is "umami" and why did Japan name it?',options:['A type of sake','The fifth basic taste — savory depth found in dashi, soy, miso — identified by Japanese chemist Ikeda in 1908','A cooking technique','A Japanese spice'],answer:1,exp:'"Umami" was scientifically identified by Professor Ikeda in 1908 studying kombu seaweed. Japan gave the world its understanding of the fifth taste.'},
    {cat:'Culture',q:'What is "meiwaku" and why does it matter?',options:['A type of music','Causing inconvenience to others — one of the greatest social sins in Japan','A greeting','A festival'],answer:1,exp:'"Meiwaku" (causing trouble to others) drives many Japanese behaviors — speaking quietly on trains, not eating while walking, waiting patiently.'},
    {cat:'Slang',q:'What does "yabai" mean now vs before?',options:['Only dangerous','Originally meant dangerous/bad — now youth use it to mean amazing/incredible. Context determines everything.','Always a compliment','Only Tokyo'],answer:1,exp:'"Yabai" originally meant dangerous. Young Japanese repurposed it like English "sick" or "wicked" — now "yabai!" can mean "amazing!" Tone carries the meaning.'},
    {cat:'Culture',q:'What is "hanami" and what does it reveal about Japanese values?',options:['Flower arranging','Cherry blossom viewing — a national tradition connecting to finding beauty in impermanence','A garden competition','A spring parade'],answer:1,exp:'"Hanami" connects to "mono no aware" — finding beauty in impermanence. The fleeting sakura is a metaphor for life itself.'},
    {cat:'Food',q:'What is the Japanese concept of "shokunin"?',options:['A type of restaurant','The artisan spirit — dedicating one\'s life to mastering a single craft completely','A cooking school','A food critic'],answer:1,exp:'"Shokunin" is total dedication to mastering one craft over a lifetime. A ramen shokunin may spend 30 years perfecting one bowl.'},
    {cat:'Slang',q:'What does "natsukashii" express?',options:['Something new','Warm nostalgic feeling for the past — that bittersweet "this takes me back" emotion','Sadness','Excitement'],answer:1,exp:'"Natsukashii" is warm nostalgia — the bittersweet feeling when something takes you back. English has no single word for it.'},
    {cat:'Culture',q:'What is "omotenashi" and how is it different from Western service?',options:['A tea ceremony type','Japanese wholehearted hospitality — anticipating guests\' needs without being asked, with no expectation of a tip','A restaurant type','A formal greeting'],answer:1,exp:'"Omotenashi" is selfless hospitality. The host anticipates every need without being asked and without expecting reward. That\'s why Japan has no tipping culture.'},
    {cat:'Slang',q:'What is "yoroshiku onegaishimasu" really communicating?',options:['Just please','I humbly request your good favor — used when meeting someone, starting business, asking for help — no direct English translation','Just goodbye','A formal apology'],answer:1,exp:'"Yoroshiku onegaishimasu" expresses humility, hope for goodwill, and acknowledgment of the relationship. Used in meetings, introductions, and favors.'},
    {cat:'Culture',q:'What are "hikikomori" and what do they reveal?',options:['A Japanese food','Young people who withdraw completely from social life for months or years — linked to extreme social pressure','A school club','An apartment type'],answer:1,exp:'"Hikikomori" (social recluses) are estimated in the hundreds of thousands in Japan. The extreme pressure of Japanese society pushes some to total withdrawal. Japan has government programs to address it.'},
    {cat:'Food',q:'What is "kaiseki" and what does it represent?',options:['A fast food chain','Japan\'s pinnacle cuisine — a multi-course meal where each dish reflects the season, local ingredients, and aesthetic principles','A type of ramen','A street food tradition'],answer:1,exp:'"Kaiseki" is Japan\'s most refined cuisine — each dish expresses seasonality, visual beauty, and culinary technique. A kaiseki meal is as much art exhibition as dinner.'},
    {cat:'History',q:'What was "the bubble economy" and how does it shape modern Japan?',options:['A children\'s story','Japan\'s 1980s boom followed by catastrophic collapse in 1991 — leading to decades of stagnation and cautious modern attitudes','A technology company','A type of architecture'],answer:1,exp:'Japan\'s bubble economy burst in 1991. Young Japanese today are cautious about spending and risk-taking partly because of this generational economic trauma.'},
    {cat:'Culture',q:'What is Japan\'s "herbivore men" (sōshokukei danshi) phenomenon?',options:['Men who only eat vegetables','Young men who reject traditional aggressive masculinity and competitive romance','A health trend','A fashion movement'],answer:1,exp:'"Herbivore men" reject traditional masculine pressure — competitive careers, pursuing women aggressively. A reflection of changing gender norms and economic anxiety in modern Japan.'},
    {cat:'Sports',q:'What sport unites France like no other?',options:['Rugby','Football (soccer) — especially after the 1998 World Cup victory on home soil','Tennis','Cycling'],answer:1,exp:'France\'s 1998 World Cup victory at home with the diverse "black-blanc-beur" team was a defining national moment. Football is France\'s most popular sport and the national team (Les Bleus) commands passionate attention.'},
    {cat:'Sports',q:'What is the Tour de France?',options:['A cycling race through Paris only','The world\'s most prestigious cycling race — 3 weeks, 21 stages, roughly 3,500km across France','A car race','A French walking trail'],answer:1,exp:'The Tour de France is the world\'s most famous cycling race — 21 grueling stages over 3 weeks. It ends on the Champs-Élysées. Watched by millions and deeply embedded in French summer culture.'},
    {cat:'Sports',q:'What is "pétanque" and where do you see it?',options:['A card game','A French ball-throwing game played in town squares — the ultimate casual French leisure activity','A type of fencing','A school sport'],answer:1,exp:'Pétanque is a beloved French game where players throw metal balls near a small target. You\'ll see it in town squares and parks across France on summer evenings — rosé in hand. It\'s a social ritual.'},
    {cat:'Media',q:'What is the significance of the Cannes Film Festival?',options:['A small local festival','The world\'s most prestigious film festival — the Palme d\'Or is cinema\'s highest honor','Only for French films','A recent creation'],answer:1,exp:'The Cannes Film Festival is the world\'s most prestigious — the Palme d\'Or winner becomes an immediate Oscar contender. Directors from Fellini to Tarantino to Park Chan-wook have competed here. It shapes global cinema taste every May.'},
    {cat:'Media',q:'What is "La Marseillaise" and why does it matter?',options:['A restaurant','The French national anthem — one of the most emotionally powerful anthems in the world','A French TV show','A Paris neighborhood'],answer:1,exp:'"La Marseillaise" was written in 1792 during the Revolution. It\'s among the world\'s most recognizable anthems — sung at stadiums and rallies with genuine passion. Its revolutionary lyrics still resonate.'},
    {cat:'Daily Life',q:'What is the French "apéro" culture?',options:['A type of exercise','Pre-dinner drinks and snacks — a sacred social ritual before meals','A French breakfast','A type of meditation'],answer:1,exp:'"L\'apéro" (apéritif) is a beloved French pre-dinner tradition — wine, kir, or pastis with nibbles before eating. It\'s a social ritual that can last 1-2 hours. Skipping the apéro is almost unthinkable.'},
    {cat:'Daily Life',q:'How do the French feel about eating at their desks?',options:['It\'s common and practical','It\'s generally frowned upon — lunch is a proper 1-2 hour break','Desk eating is encouraged','Only common in Paris'],answer:1,exp:'In France, eating at your desk is poor form. Lunch is a real break — often 1-2 hours — eaten properly at a café or with colleagues. The French see eating as a social activity requiring time, not a task to rush.'},
  ]},
  'Italy':{flag:'🇮🇹',lang:'Italian',questions:[
    {cat:'Food',q:'What is the cardinal sin of Italian coffee culture?',options:['Adding sugar','Ordering a cappuccino after 11am — Italians only drink milk-based coffee in the morning','Drinking espresso standing up','Asking for a large size'],answer:1,exp:'Ordering a cappuccino after breakfast is a genuine faux pas — Italians believe milk after a meal disrupts digestion. Afternoon coffee is always espresso.'},
    {cat:'Culture',q:'What is "la bella figura"?',options:['A famous painting','The cultural value of making a good impression through appearance and behavior','A greeting ritual','A cooking philosophy'],answer:1,exp:'"La bella figura" permeates Italian life — how you dress, speak, present food, behave publicly. The opposite, "fare una brutta figura," is deeply shameful.'},
    {cat:'Slang',q:'What does "dai!" mean?',options:['Only give','Come on!, really?, stop it!, let\'s go! — depending on tone','A strong insult','A formal greeting'],answer:1,exp:'"Dai!" is incredibly versatile. Drawn out = "come on!/no way!" Sharp = "stop it!" or "let\'s go!"'},
    {cat:'Food',q:'What makes Neapolitan pizza legally protected?',options:['Italian copyright law','AVPN certifies authentic recipes — specific flour, San Marzano tomatoes, fior di latte, wood-fired oven at 485°C','Only descendants can make it','The dough is a state secret'],answer:1,exp:'The AVPN has strict rules. In 2017, UNESCO recognized Neapolitan pizzamaking as cultural heritage.'},
    {cat:'Culture',q:'What is "il campanilismo" in Italian culture?',options:['A type of church bell','Fierce pride in one\'s hometown — Italy\'s defining local identity','A national holiday','A cooking competition'],answer:1,exp:'"Campanilismo" means intense loyalty to your hometown. Italians identify as Roman or Milanese or Sicilian before Italian. Food, dialect, and customs are fiercely local.'},
    {cat:'Slang',q:'What does "figurati" mean?',options:['Just imagine','Don\'t mention it, no worries, of course — an extremely versatile reassurance','A drawing term','A complaint'],answer:1,exp:'"Figurati!" means "don\'t mention it," "of course," or "no worries." One of Italian\'s most social and charming words.'},
    {cat:'Food',q:'What is the "pasta rules" culture in Italy?',options:['Italy has no pasta rules','Italians have strong feelings about combinations — carbonara with cream is wrong, wrong shapes with wrong sauces are offensive','Rules only in restaurants','Only older Italians care'],answer:1,exp:'Carbonara must have NO cream. Pesto goes with trofie, not spaghetti. Bolognese goes with tagliatelle, not spaghetti. Break the rules and prepare for strong opinions.'},
    {cat:'Slang',q:'What does "mamma mia" actually express?',options:['Only extreme shock','Surprise, frustration, admiration, or exasperation — an all-purpose exclamation','Only a stereotype','Only used in the south'],answer:1,exp:'"Mamma mia" is a genuine, constantly-used exclamation. Not just a stereotype — real Italians say it all the time for any strong emotion.'},
    {cat:'Culture',q:'What is "la passeggiata"?',options:['A type of pasta','The evening stroll — a daily ritual where Italians walk, see and be seen, and socialize','A festival','A nap tradition'],answer:1,exp:'"La passeggiata" is the evening stroll — Italians dress up and walk through the main piazza at dusk. Social performance, exercise, and community all in one.'},
    {cat:'Food',q:'What is the Italian rule about breakfast?',options:['Big breakfasts like eggs and bacon','Almost always sweet — a cornetto and cappuccino standing at a bar. Savory breakfast is considered foreign and strange.','No rules','Varies by region only'],answer:1,exp:'Italian breakfast is a sweet, quick affair — cornetto and cappuccino standing at the bar. A big savory breakfast confuses most Italians.'},
    {cat:'Slang',q:'What does "boh" mean?',options:['Yes emphatically','I don\'t know or I have no idea — a shrug made vocal','No','Maybe'],answer:1,exp:'"Boh!" is the Italian verbal shrug — "I don\'t know," "who knows," "beats me." More expressive than any full sentence.'},
    {cat:'Culture',q:'What is "furbizia" in Italian culture?',options:['Stupidity','Clever cunning — bending rules, finding shortcuts, outsmarting the system — often admired','Being honest','Being strong'],answer:1,exp:'"Furbizia" (from furbo, cunning) means cleverly navigating around rules. Being "furbo" is often admired as intelligence rather than condemned as dishonesty.'},
    {cat:'Food',q:'What is the significance of Sunday lunch in Italy?',options:['Just a bigger meal','A sacred multi-hour family ritual — Sunday ragù simmering since morning, relatives gathered for 2-3 hours — non-negotiable','Only in the south','A restaurant tradition'],answer:1,exp:'Sunday lunch is the apex of Italian family life — ragù that\'s been simmering since morning, grandparents and cousins gathered for hours. It\'s non-negotiable.'},
    {cat:'Culture',q:'What is Italy\'s relationship with "il calcio" (football)?',options:['Casual enjoyment','Football is religion — it defines identity, divides families, and the national team\'s results affect mood more than politics','Only men follow it','Italy prefers basketball'],answer:1,exp:'Italian football is tribal and emotional. Losing a World Cup match causes national mourning. Derby matches between local rivals are civil wars.'},
    {cat:'Food',q:'What is "aperitivo" in northern Italian cities?',options:['Just a drink before dinner','In Milan, paying for one drink gets you access to a full food buffet — a social institution often replacing dinner','A type of restaurant','Only in Turin'],answer:1,exp:'Milan\'s aperitivo culture is famous — pay for a Campari and eat from a full buffet. "Let\'s do aperitivo" is the most common invitation in Milan.'},
    {cat:'Slang',q:'What does "cavolo" express?',options:['Just the vegetable','A mild exclamation substitute for a stronger word — polite frustration or surprise','A compliment','A greeting'],answer:1,exp:'"Cavolo" (cabbage) is Italy\'s polite substitute for a stronger expletive. "Che cavolo vuoi?" = polite "what the heck do you want?"'},
    {cat:'Culture',q:'What is "arte di arrangiarsi"?',options:['A formal art movement','The art of managing and improvising under constraints — Italian resourcefulness with style','A cooking technique','A dance style'],answer:1,exp:'"L\'arte di arrangiarsi" (the art of getting by) is celebrated Italian resourcefulness — making the best of limited resources with style and ingenuity.'},
    {cat:'Slang',q:'What is the correct response to "in bocca al lupo"?',options:['Grazie','Crepi! (may the wolf die) — saying "grazie" brings bad luck','It\'s an insult','Be careful'],answer:1,exp:'"In bocca al lupo" (into the wolf\'s mouth) is the theatrical way to say good luck. You must respond "crepi!" Saying "grazie" is considered bad luck.'},
    {cat:'Food',q:'Why are Italian regional foods so radically different?',options:['Minor seasoning differences','Italy unified only in 1861 — each region developed completely distinct cuisines over centuries','Only pasta shapes differ','Mostly the same with different names'],answer:1,exp:'Italy unified politically in 1861 but gastronomically it\'s still 20 countries. Northern uses butter; southern uses olive oil. Sicilian cuisine has Arab influences. These are different cuisines, not variations.'},
    {cat:'Culture',q:'What is the role of "la nonna" in Italian family culture?',options:['A reduced role as in modern families','The absolute culinary and moral authority — her recipes are sacred, her Sunday lunch is law, her approval matters most','Only relevant in the south','Only in traditional families'],answer:1,exp:'"La nonna" is the keeper of culinary tradition and family values. Her pasta is always better than the restaurant. The Sunday lunch she hosts is the centerpiece of family life.'},
    {cat:'Culture',q:'What is the "Italian hour" in social timing?',options:['A time zone','Being 10-20 minutes late is normal and expected — arriving on time can seem overly eager','A type of nap','A meal time'],answer:1,exp:'Being slightly late in Italy is socially normal. Arriving exactly on time to a dinner party can catch the host still getting ready. The social contract around time differs — especially in the south.'},
    {cat:'Food',q:'What is "il cibo di strada" culture in Palermo, Sicily?',options:['A modern trend','One of the world\'s great street food traditions — arancini, panelle, stigghiola — ancient markets reflecting Arab, Norman, and Spanish influences','A tourist gimmick','Only panini'],answer:1,exp:'Palermo has one of Europe\'s oldest street food cultures. The Ballarò and Vucciria markets reflect centuries of Arab, Norman, and Spanish culinary layers.'},
    {cat:'Slang',q:'What does "allora" really mean in Italian conversation?',options:['Only then or therefore','An all-purpose conversation starter, pause filler, and transition word — "allora..." can begin any sentence','Only a formal word','Only used in writing'],answer:1,exp:'"Allora" means "then/so/well" but is used constantly as a conversation starter and pause filler. A teacher beginning a lesson, a waiter taking your order, someone thinking — all say "allora."'},
    {cat:'Culture',q:'What is "la bella Italia" vs reality?',options:['Italy is perfect','A gap between Italy\'s stunning beauty and its bureaucratic, infrastructural challenges — Italians both love and exasperatedly criticize their country','Only tourists see beauty','Only about corruption'],answer:1,exp:'Italians are deeply patriotic and deeply critical of Italy at the same time. "Questo paese" (this country) is said with love and exasperation. The beauty and the dysfunction coexist.'},
  
    {cat:'Media',q:'What real Italian-American world inspired The Godfather and The Sopranos?',options:['Pure Hollywood fiction','Both drew heavily from Sicilian and southern Italian immigrant communities in New York and New Jersey — the culture, values, and family codes are rooted in real Italian traditions','Only The Sopranos is based on real events','They were inspired by French crime films'],answer:1,exp:'The Corleone family in The Godfather was inspired by Sicilian immigrant culture. The Sopranos creator David Chase drew from real Italian-American mob culture in New Jersey. Concepts like omertà (code of silence), family loyalty, and honor trace directly back to southern Italian values.'},
    {cat:'Culture',q:'What Italian concept does "an offer he can\'t refuse" from The Godfather reflect?',options:['Just a movie line','It reflects the Italian concept of honor and obligation — in Italian culture, certain debts and favors create binding social contracts that are almost impossible to decline','A business negotiation tactic','A legal term'],answer:1,exp:'The famous Godfather line captures something real in Italian culture — the weight of favors, obligations, and respect. In Italy, "fare un favore" (doing a favor) creates a genuine social bond. The Sicilian concept of reciprocity runs deep.'},
    {cat:'Food',q:'How did Italian immigrants change American food culture?',options:['They had little impact','Enormously — pizza, pasta, espresso, gelato, and Italian-American dishes like spaghetti and meatballs were all brought by Italian immigrants, mostly from southern Italy, and became American staples','Only pizza came from Italy','Only in New York'],answer:1,exp:'The wave of southern Italian immigrants (1880s-1920s) transformed American food. Pizza was virtually unknown outside Naples until Italian-Americans popularized it. "Italian-American" cuisine — richer, more abundant than Italian originals — reflects immigrants adapting to American abundance.'},
    {cat:'Culture',q:'What does the Italian-American concept of "Sunday gravy" represent?',options:['Just a pasta sauce','A Sunday ritual — slow-cooked tomato sauce with meat — that became central to Italian-American family identity, representing the blending of Italian tradition with American abundance','A restaurant dish only','A Sicilian dish unrelated to Italy'],answer:1,exp:'"Sunday gravy" (called "ragù" in Italy) became a cornerstone of Italian-American culture. Families gathered every Sunday as the sauce cooked for hours. It represents how Italian immigrants preserved cultural rituals in America — the table as the center of family life.'},
    {cat:'Sports',q:'What is "calcio" and why is it central to Italian identity?',options:['A type of pasta','Football (soccer) — the passion divides families and cities','A traditional card game','A regional festival'],answer:1,exp:'"Calcio" (football) is Italy\'s national religion. Club loyalties — Milan vs Inter, Roma vs Lazio — divide families. The Azzurri (national team) unite the whole country. Italy has won the World Cup four times.'},
    {cat:'Sports',q:'What is the Giro d\'Italia?',options:['A car race through Rome','One of cycling\'s three Grand Tours — a 3-week race through Italy each May','A sailing competition','A mountain trek'],answer:1,exp:'The Giro d\'Italia is one of cycling\'s three Grand Tours. The leader wears the "maglia rosa" (pink jersey) — pink is the color of La Gazzetta dello Sport, which created the race. Italian mountain stages are legendary.'},
    {cat:'Sports',q:'What is "Serie A"?',options:['Italy\'s top basketball league','Italy\'s top football league — Juventus, Inter Milan, AC Milan, and AS Roma are its giants','A regional cycling league','Italian volleyball'],answer:1,exp:'Serie A is Italy\'s top football league. Juventus, Inter Milan, AC Milan, and AS Roma are historically dominant. Derby matches — Milan\'s Derby della Madonnina, Rome\'s Derby della Capitale — stop the country.'},
    {cat:'Media',q:'What is the significance of Italian fashion globally?',options:['Italy only makes regional clothing','Italy is a world capital of luxury fashion — Milan is one of the four major Fashion Week cities','French fashion replaced Italian','Only Rome matters for fashion'],answer:1,exp:'Milan is one of four global fashion capitals. Gucci, Prada, Versace, Armani, Valentino — Italian houses define luxury fashion worldwide. Italian craftsmanship is a global benchmark.'},
    {cat:'Media',q:'What filmmaker gave us "La Dolce Vita" and the word "paparazzi"?',options:['Sergio Leone','Federico Fellini — "La Dolce Vita" named a character "Paparazzo" giving us the word','Roberto Rossellini','Bernardo Bertolucci'],answer:1,exp:'Federico Fellini\'s "La Dolce Vita" gave the world the term "paparazzi" — a character is named Paparazzo. "8½" is considered one of the greatest films ever. His surrealist style influenced generations of filmmakers.'},
    {cat:'Daily Life',q:'What does "la passeggiata" mean?',options:['A type of pasta','The evening stroll — a ritual walk where people see and be seen','A morning coffee ritual','An afternoon nap'],answer:1,exp:'"La passeggiata" is the Italian ritual of a leisurely evening stroll through town at sunset. People dress well, walk slowly, greet neighbors, stop for gelato. It\'s a way of feeling connected to community.'},
    {cat:'Daily Life',q:'What is the rule about cappuccino in Italy?',options:['Drink it any time','Ordering a cappuccino after 11am marks you as a tourist — Italians only drink it at breakfast','Only for weekends','Children only drink cappuccino'],answer:1,exp:'For Italians, cappuccino is a breakfast drink — period. Ordering one after lunch is a tourist tell. The milk is too heavy for any other time. After meals, Italians drink a short, strong espresso (un caffè).'},
  ]},
  'Haiti': {questions:[
    {cat:'Language',q:'What language is Haitian Creole most closely related to?',options:['Spanish','French — Haitian Creole developed primarily from French with influences from West African languages','Portuguese','English'],answer:1,exp:'Haitian Creole (Kreyòl ayisyen) developed from French colonial rule but was shaped heavily by enslaved Africans from various ethnic groups. It is now one of Haiti\'s two official languages alongside French.'},
    {cat:'Culture',q:'What is "kompa" in Haitian culture?',options:['A traditional dish','The dominant popular music genre of Haiti — a rhythmic, guitar-driven sound created in the 1950s','A religious ceremony','A type of dance only for elders'],answer:1,exp:'Kompa was created by Nemours Jean-Baptiste in 1955 and became Haiti\'s signature music style. It blends African rhythms with Caribbean and Latin influences and is danced throughout the diaspora.'},
    {cat:'History',q:'What makes Haiti historically unique among Caribbean nations?',options:['It was never colonized','It was the first Black republic in the world, winning independence from France in 1804 through a slave revolution','It was founded by the British','It gained independence peacefully'],answer:1,exp:'The Haitian Revolution (1791-1804) was the only successful slave revolt in history that led to a nation\'s founding. Haiti declared independence on January 1, 1804, defeating Napoleon\'s forces.'},
    {cat:'Food',q:'What is "griot" in Haitian cuisine?',options:['A type of bread','Fried pork — marinated in citrus and spices then fried crispy, often served with rice, beans, and pikliz','A spice mixture','A type of fish'],answer:1,exp:'Griot is considered Haiti\'s national dish. Pork is marinated in sour orange, lime, and spices then fried until crispy. It\'s typically served with diri ak pwa (rice and beans) and pikliz (spicy pickled vegetables).'},
    {cat:'Slang',q:'What does "sak pase" mean in Haitian Creole?',options:['Where is the food?','What\'s up? — the most common Haitian greeting','I am tired','Good morning'],answer:1,exp:'"Sak pase" literally means "what\'s happening?" and is the go-to casual greeting. The typical response is "n ap boule" (we\'re good). Used the way English speakers say "what\'s up?"'},
    {cat:'Culture',q:'What is Vodou in Haitian culture?',options:['A type of music','A recognized religion combining West African spiritual traditions with Catholic elements','Only a stereotype','A political movement'],answer:1,exp:'Haitian Vodou is a recognized religion combining Fon, Ewe, and Yoruba spiritual traditions with Catholicism. It\'s a complex spiritual system with priests (ougan) and priestesses (manbo) who serve as community healers.'},
    {cat:'Language',q:'How do you say "thank you" in Haitian Creole?',options:['Merci','Mèsi — similar to French merci but adapted into Creole','Gracias','Danki'],answer:1,exp:'"Mèsi" is the Haitian Creole word for thank you, derived from French "merci." "Mèsi anpil" means thank you very much.'},
    {cat:'Culture',q:'What is "pikliz" in Haitian cuisine?',options:['A sweet dessert','A fiery pickled vegetable condiment — cabbage, carrots, and peppers in vinegar — served with almost every meal','A type of juice','A breakfast dish'],answer:1,exp:'Pikliz is Haiti\'s beloved condiment — shredded cabbage, carrots, and Scotch bonnet peppers in white vinegar. It\'s intensely spicy and served alongside griot and tasso. No Haitian meal is complete without it.'},
    {cat:'History',q:'What is the Citadelle Laferrière?',options:['A tourist resort','A massive mountaintop fortress built after independence to defend against French reinvasion — one of the largest in the Americas','A colonial-era prison','A plantation house'],answer:1,exp:'The Citadelle Laferrière was built by King Henri Christophe starting in 1807 to defend Haiti against a feared French return. It sits 900 meters above sea level and is a UNESCO World Heritage Site.'},
    {cat:'Music',q:'Which of these is a legendary Haitian kompa group?',options:['Shakira','Tabou Combo — one of the most influential Haitian bands who brought kompa to the world stage','Stromae','Maneskin'],answer:1,exp:'Tabou Combo formed in the Dominican Republic in 1968 and became one of the most internationally recognized Haitian bands. They helped popularize kompa worldwide. BélO and T-Vice are other beloved Haitian artists.'},

    {cat:'History',q:'Why is Haiti\'s independence historically unique and why does it matter to the world?',options:['It\'s not particularly unique','Haiti was the first and only successful slave revolt to create a nation — in 1804, enslaved Africans defeated Napoleon\'s army, inspiring freedom movements worldwide and terrifying slaveholding nations','It gained independence peacefully','France gave Haiti independence'],answer:1,exp:'The Haitian Revolution (1791-1804) shocked the world. Enslaved Africans defeated the most powerful army in Europe. Haiti\'s existence terrified American slaveholders — the US refused to recognize Haiti for decades. The revolution directly influenced abolition movements and is considered one of history\'s most significant events.'},
    {cat:'Culture',q:'What Haitian concept has no English equivalent but resonates universally?',options:['All cultures have equivalent concepts','Lakou — the extended family compound where multiple generations live together, sharing resources and raising children collectively. It\'s a philosophy of communal living that sustained Haitian communities through hardship','Only a housing arrangement','A modern concept'],answer:1,exp:'Lakou (from French "la cour" — the courtyard) is both a physical space and a social philosophy. Multiple family units share a compound, decisions are made collectively, children are raised by the community. It survived colonialism and reflects deep African communal values. The concept influenced Haitian diaspora communities worldwide.'},
    {cat:'Food',q:'What does Haitian food culture reveal about the country\'s history?',options:['Haitian food has no distinctive character','Every dish reflects layers of history — African cooking techniques, French influence in sauces and names, indigenous Taino ingredients, and the creativity of people who survived slavery and poverty with flavor and pride','Only French influence matters','Food is not culturally significant'],answer:1,exp:'Haitian cuisine is a history lesson. Griot (fried pork) uses citrus marinades from African and indigenous traditions. Soupe joumou (pumpkin soup) eaten on Independence Day was forbidden to enslaved people — eating it became an act of liberation. The food is bold, labor-intensive, and deeply tied to identity and survival.'},
    ]},

  'European Portuguese':{flag:'🇵🇹',lang:'Portuguese',questions:[
    {cat:'Culture',q:'What is "saudade" and why does it define Portuguese identity?',options:['A type of wine','A melancholic longing for something absent — a person, a place, a time — considered the defining emotional state of Portuguese identity','A popular festival','A word for nostalgia only'],answer:1,exp:'Saudade is untranslatable. It\'s a bittersweet longing for something you love that is gone or out of reach. Poets say the Portuguese discovered it in the Age of Exploration — sailors leaving loved ones behind. It permeates fado music, literature, and daily conversation.'},
    {cat:'Food',q:'What is a pastel de nata and why do people travel to Belém just for one?',options:['A savory meat pie','A flaky custard tart — crispy pastry shell, creamy egg custard, slightly burnt on top. The original recipe from Pastéis de Belém has been kept secret since 1837','A type of bread','A fish cake'],answer:1,exp:'Pastéis de Belém in Lisbon has been making the original recipe since 1837. The secret recipe is known only to a handful of people. The tart should be warm, dusted with cinnamon and powdered sugar, paired with a bica espresso. Tourists queue for an hour. Worth it.'},
    {cat:'Music',q:'What is fado and what emotion does it carry?',options:['A cheerful folk dance','A genre of music expressing saudade — longing, fate, and melancholy. Performed by a solo singer with Portuguese guitar, it is UNESCO-recognized as intangible cultural heritage','A type of street party','Only for tourists'],answer:1,exp:'Fado means "fate" in Portuguese. It emerged in 19th century Lisbon in working-class neighborhoods. The most famous fadista was Amália Rodrigues, who brought it international recognition. Coimbra has its own distinct style — more academic and melancholic, sung only by men.'},
    {cat:'Culture',q:'What is the significance of the rooster of Barcelos?',options:['A local sports team mascot','A symbol of good luck and justice rooted in a legend about a pilgrim falsely accused of theft, saved when the roasted rooster crowed to prove his innocence','Just a tourist souvenir','A religious symbol'],answer:1,exp:'The Galo de Barcelos is Portugal\'s most iconic symbol. The legend: a pilgrim accused of theft was sentenced to death. He pointed to a roasted rooster on the judge\'s table and declared it would crow to prove his innocence. It did. He was freed. The rooster became a symbol of faith, good luck, and justice.'},
    {cat:'History',q:'What was the Age of Discoveries and why does it still shape Portugal today?',options:['A minor historical event','Portugal led 15th-16th century maritime exploration, establishing trade routes to Africa, India, Brazil, and Asia — creating the first global empire and spreading Portuguese language to 250 million people worldwide','Only about Columbus','A brief period'],answer:1,exp:'Portugal\'s Golden Age of Exploration changed the world. Vasco da Gama reached India. Cabral reached Brazil. Portugal established trading posts across four continents. The Portuguese language is now spoken by 250 million people globally. This history gives the Portuguese a complex pride and sense of global connection.'},
    {cat:'Food',q:'What is bacalhau and what is its cultural significance?',options:['Fresh salmon','Salted dried cod — the most important ingredient in Portuguese cuisine with supposedly 365 ways to prepare it, one for each day of the year. Portugal does not produce cod but imports it from Norway','A local freshwater fish','A holiday dish only'],answer:1,exp:'Bacalhau (salt cod) has been eaten in Portugal since the Age of Discoveries — sailors preserved it for long voyages. Today 40,000 tons are consumed annually. "Fiel amigo" (faithful friend) it\'s called. Bacalhau à Brás, Bacalhau com Natas, Bacalhau à Gomes de Sá — each recipe is a regional identity.'},
    {cat:'Culture',q:'How is time and pace of life different in Portugal vs. other European countries?',options:['Identical to Northern Europe','Portugal operates on a Mediterranean rhythm — meals are long, business relationships require trust before contracts, Sunday lunch is sacred, and rushing is considered rude','Very fast-paced','Only rural areas are slow'],answer:1,exp:'Portugal is often described as more relaxed than Spain, which is more relaxed than France. "Cinco minutos" (five minutes) can mean half an hour. Sunday lunch with family lasts three hours. Espresso is consumed standing at the bar in 90 seconds. These aren\'t contradictions — different things deserve different paces.'},
  ]},

  'Parisian':{flag:'🇫🇷',lang:'French',questions:[
    {cat:'Culture',q:'What is the unspoken rule when entering any shop or restaurant in Paris?',options:['Just walk in and start shopping','Always greet with "Bonjour" before asking for anything — failing to do so is considered rude and will affect how you\'re treated','Greet only if you feel like it','Only tourists need to greet'],answer:1,exp:'"Bonjour" is not optional in Paris — it\'s a social contract. Walk into a bakery without saying it and the baker is within their rights to ignore you. It signals "I acknowledge your humanity before asking something of you." Add "Monsieur" or "Madame" and you\'ll be treated significantly better.'},
    {cat:'Food',q:'What is the correct way to order coffee in a Parisian café?',options:['Ask for a "café latte"','Say "un café" for a small espresso, or "un crème" for espresso with steamed milk. A café latte marks you as a tourist. Milky coffees are only acceptable before noon','Order whatever you want','Coffee is coffee everywhere'],answer:1,exp:'In Paris, "un café" = espresso. "Un noisette" = espresso with a drop of milk. "Un crème" = espresso with steamed milk, acceptable in the morning. Ordering a cappuccino after 11am identifies you as a tourist. Parisians drink quickly, standing at the zinc counter, for a cheaper price than sitting.'},
    {cat:'Culture',q:'What does "Parisian chic" actually mean in everyday life?',options:['Wearing luxury brands every day','The art of appearing effortless — a silk scarf with jeans, a blazer thrown on casually, minimal makeup, few carefully chosen pieces. The goal is to look like you didn\'t try','Dressing very formally','Only applies to women'],answer:1,exp:'Parisian style is about restraint. A well-fitted blazer. Dark jeans. A silk scarf. Understated jewelry. The French phrase is "je ne sais quoi" — something ineffable. The goal is quality over quantity, investment pieces over trends. A Parisian woman has fewer clothes than you think, chosen very carefully.'},
    {cat:'History',q:'What happened at Café de Flore and Les Deux Magots that still matters today?',options:['Nothing historically significant','These Saint-Germain-des-Prés cafés were the intellectual heart of 20th century Paris — Sartre and de Beauvoir worked there daily, Hemingway drank there, and ideas that changed philosophy and literature were born at those tables','Just tourist attractions now','They are famous only for food'],answer:1,exp:'Café de Flore and Les Deux Magots were the offices of Parisian intellectual life for decades. Jean-Paul Sartre and Simone de Beauvoir had regular tables at Flore. Camus, Picasso, and Hemingway were regulars. The tradition of using cafés as workplaces — not just for coffee — is distinctly Parisian.'},
    {cat:'Culture',q:'Why do Parisians seem unfriendly to tourists and what changes everything?',options:['They genuinely dislike tourists','Parisians value formality with strangers. Start with "Bonjour, excusez-moi" and make an effort in French, however broken — the reception transforms. Skipping this reads as rude, not efficient','They are always rude','Only in tourist areas'],answer:1,exp:'The "rude Parisian" stereotype exists because tourists often skip French social rituals. Starting a conversation without "Bonjour" or speaking French before English is considered presumptuous. Make the attempt — even badly — and most Parisians respond warmly. They genuinely appreciate the effort and often switch to excellent English to help you.'},
    {cat:'Food',q:'What is the correct etiquette at a Parisian dinner party?',options:['Arrive exactly on time','Arrive 10-15 minutes late (never early), bring wine or flowers (not chrysanthemums — those are for funerals), keep your hands on the table, and don\'t ask for a tour of the apartment','Bring nothing','Leave immediately after eating'],answer:1,exp:'French dinner party rules: arrive slightly late (early is as rude as very late), bring wine, champagne, or chocolates. Chrysanthemums are funeral flowers — never bring them. Hands visible on the table throughout dinner. Conversation is the main event. Leaving right after dessert is considered abrupt — the digestif and conversation continue.'},
    {cat:'Culture',q:'What is "la bise" and when does it cause problems for foreigners?',options:['A type of bread','The cheek-kiss greeting — one to four kisses depending on the region, the relationship, and context. Getting the number wrong or going to the wrong cheek causes an awkward moment','Only done at formal events','Replaced by handshakes now'],answer:1,exp:'La bise is a cheek-kiss greeting between friends, family, and sometimes acquaintances. In Paris, two kisses (right cheek first). In some regions, four. Between men who are good friends, also normal. The rules are unspoken — you learn by doing. Foreigners often go the wrong way and the resulting nose collision is a rite of passage.'},
  ]},

  'Southern French':{flag:'🇫🇷',lang:'French',questions:[
    {cat:'Culture',q:'What is the "art de vivre" of the South of France that Parisians envy?',options:['Nothing specific to the South','A philosophy of living well — long lunches under plane trees, rosé wine at noon, markets in the morning, and an unhurried pace where quality of life matters more than productivity','Only about food','A tourist invention'],answer:1,exp:'The South of France lifestyle — especially in Provence — is built around pleasure and presence. The morning market. The two-hour lunch. Pastis at 5pm in the village square. Parisians take holidays there to decompress. The Mediterranean climate and culture create a fundamentally different relationship with time.'},
    {cat:'Food',q:'What is bouillabaisse and why is it impossible to find the real thing outside Marseille?',options:['A simple fish stew','A Provençal fish soup requiring specific Mediterranean fish, saffron, and traditional technique — the Marseille charter lists exactly which fish must be included, and the correct way to serve it (broth first, then fish)','A tourist trap dish','A pasta dish'],answer:1,exp:'Bouillabaisse originated as a fisherman\'s dish using unsellable fish. Gentrification made it expensive. The Marseille Bouillabaisse Charter (1980) defines the authentic recipe: scorpionfish, John Dory, conger eel, and others. It\'s served in two parts — broth with rouille on croutons first, then the fish. Ordering it elsewhere is a compromise.'},
    {cat:'Culture',q:'What is pétanque and what does it reveal about Southern French culture?',options:['Just a game for the elderly','A form of boules played on gravel, involving throwing metal balls near a small target. More importantly, it\'s a social ritual — games last hours, involve argument, pastis, and conversation, and cross all age groups','Only played in summer','A competitive sport'],answer:1,exp:'Pétanque was invented in La Ciotat in 1907. The name comes from "pès tancats" — feet planted. It\'s played on any gravel surface, from village squares to back streets. The game is an excuse for conversation. Arguments about distances are resolved with passionate debate. Pastis consumption correlates directly with game duration.'},
    {cat:'Food',q:'What is the role of the morning market in Southern French towns?',options:['Just for shopping','The social center of the day — people arrive early, greet their vendors by name, taste before buying, and spend an hour doing what takes ten minutes in a supermarket. It\'s community, not commerce','Replaced by supermarkets','Only on weekends'],answer:1,exp:'The morning market (le marché) in Southern France is a social institution. Vendors know their regular customers. You taste the cheese before buying. The olive seller argues about which variety pairs with what. Transactions involve conversation. Markets in Aix-en-Provence, Arles, and Uzès are famous — but even small village markets follow this philosophy.'},
    {cat:'Language',q:'How does the Southern French accent differ from Parisian French?',options:['No real difference','The Midi accent pronounces final E sounds that Parisians drop, opens vowels more fully, and has a slower, more melodic rhythm. Parisians sometimes mock it; Southerners consider it warmer and more authentic','Only old people have it','A very subtle difference'],answer:1,exp:'The accent du Midi (Southern accent) pronounces the final "e" in words — "une femme" sounds like "une femm-uh" rather than "un femm." Vowels are more open and rounded. The rhythm is slower. Parisians stereotypically mock it; Southerners respond that theirs is the more natural French. The accent varies — Marseille sounds different from Nice, which sounds different from Toulouse.'},
    {cat:'Food',q:'What is pastis and when is it acceptable to drink it?',options:['A dessert','An anise-flavored aperitif diluted with cold water — it turns cloudy, called "le nuage" (the cloud). Drunk before lunch or dinner, especially in summer. The ritual of adding water is part of the experience','A strong spirit drunk straight','Only at night'],answer:1,exp:'Pastis (Ricard and Pastis 51 are the iconic brands) is the drink of Southern France. One part pastis to five parts cold water, which turns the clear liquid milky yellow. It\'s bitter, anise-flavored, refreshing in heat. The ritual is the point — the glass, the water carafe, the slow addition. Pernod was the original until absinthe\'s ban made companies reformulate.'},
    {cat:'Culture',q:'What makes Provence\'s lavender fields culturally significant beyond being pretty?',options:['Only aesthetic value','Lavender production is central to Provençal identity — the essential oil industry, perfumeries in Grasse, traditional medicine, and culinary use (herbes de Provence) make it an economic and cultural backbone','Only a modern tourism phenomenon','It grows everywhere in France'],answer:1,exp:'Provence\'s lavender plateau (the Valensole plateau) blooms in July. Grasse, 30km from Nice, is the world capital of perfume — Chanel No. 5\'s jasmine and rose come from here. Lavender appears in herbes de Provence, local honey, and sachets in every drawer. It\'s not decoration — it\'s identity.'},
  ]},

  'Neapolitan':{flag:'🇮🇹',lang:'Italian',questions:[
    {cat:'Food',q:'What makes Neapolitan pizza categorically different from all other pizza?',options:['Just a regional variation','DOC-certified Neapolitan pizza uses specific San Marzano tomatoes, fior di latte mozzarella, 00 flour, and must be cooked in a wood-fired oven at 485°C for 60-90 seconds — the crust should be soft and slightly charred, never crispy','The sauce recipe','Only the size'],answer:1,exp:'Vera Pizza Napoletana (VPN) is regulated by the Associazione Verace Pizza Napoletana. Dough must rest 8 hours minimum. The oven must reach 485°C. A Margherita has exactly three toppings: tomato, fior di latte, basil — representing Italy\'s flag. The crust should fold over itself without breaking — the "portafoglio" fold is how Neapolitans eat street pizza.'},
    {cat:'Culture',q:'What is the "caffè sospeso" tradition and what does it say about Naples?',options:['A type of coffee drink','Paying for an extra coffee for a stranger who cannot afford one — a tradition of anonymous generosity that has spread beyond Naples to become a symbol of Neapolitan solidarity','A discount system','Only for tourists'],answer:1,exp:'Caffè sospeso ("suspended coffee") was born in Naples. You pay for two coffees, drink one, and leave one "suspended" for whoever needs it. The bar keeps track. A struggling person can ask "c\'è un sospeso?" without shame. This tradition embodies the Neapolitan spirit — communal, generous, and proud. It has spread to cafés worldwide.'},
    {cat:'Music',q:'What is the significance of "O Sole Mio" and Neapolitan music globally?',options:['Just a famous song','Neapolitan song (canzone napoletana) was the first popular music tradition to go global — O Sole Mio, Funiculì Funiculà, and Torna a Surriento were heard worldwide before recorded music. The genre influenced opera and early popular music','Only opera is significant','The song is overplayed'],answer:1,exp:'"O Sole Mio" (1898) has been recorded by everyone from Caruso to Elvis (as "It is Now or Never"). Neapolitan songs were Italy\'s first cultural export — performed by Enrico Caruso and Italian immigrants who took them worldwide. The genre invented the structure of the modern love song.'},
    {cat:'Culture',q:'What does the hand gesture "o ciucciuvettolo" mean and why do Neapolitans gesture so much?',options:['Gestures are just decoration','Neapolitan gestures are a complete communication system — each has specific meaning. Research suggests they evolved because Naples was ruled by so many foreign powers that speaking openly was dangerous; gestures allowed communication without comprehension','Only in old Naples','Gestures are rude'],answer:1,exp:'Neapolitans have a documented gestural language — Isabella Cantelmo\'s 17th century guide described 23 gestures. They evolved partly from necessity under foreign rule: Spanish, French, and Austrian governors couldn\'t interpret them. Today they are part of cultural identity. The gesture museum in Naples teaches their history. Isabella Cantelmo\'s treatise is still referenced.'},
    {cat:'History',q:'Why does Naples have such a complex relationship with the rest of Italy?',options:['No different from other regions','Naples was the capital of the Kingdom of the Two Sicilies — the wealthiest state in pre-unification Italy. After unification (1861), the South was economically exploited by the North, creating resentment and the "Southern Question" that Italy still debates','Purely economic differences','Only cultural differences'],answer:1,exp:'Before Italian unification, the Kingdom of Naples was prosperous. Unification brought heavy taxation of the South to fund Northern industrialization. The "Questione Meridionale" (Southern Question) — why the South remains poorer — is still debated. Neapolitans are proud and defensive of their identity partly in response to decades of being stereotyped by Northern Italians.'},
    {cat:'Food',q:'What is sfogliatella and why is it Naples most technical pastry?',options:['A simple cookie','A shell-shaped pastry — either riccia (crunchy, multi-layered like a seashell) or frolla (shortcrust). The riccia requires laminating the dough hundreds of times to achieve its distinctive layers. It is extremely difficult to make correctly','A cream-filled éclair','Any pastry from Naples'],answer:1,exp:'Sfogliatella riccia requires the dough to be stretched thin and rolled with lard into hundreds of paper-thin layers. When baked, they separate like a seashell. The filling: ricotta, semolina, orange peel, cinnamon. It must be eaten warm from the oven. The frolla version is easier but considered inferior by Neapolitans. Every sfogliatella argument in Naples is deeply personal.'},
  ]},

  'Sicilian':{flag:'🇮🇹',lang:'Italian',questions:[
    {cat:'Food',q:'What is arancina vs arancino and why does the debate matter?',options:['The same thing with different spellings','In Palermo it\'s "arancina" (feminine, round) — in Catania it\'s "arancino" (masculine, cone-shaped). The shape and gender of this fried rice ball is a genuine point of Sicilian regional identity','Just regional spelling','Only tourists care'],answer:1,exp:'The arancina/arancino debate is serious in Sicily. Palermitans make them round, call them arancina, and fill them with ragù or butter and ham. Catanesi make them conical (representing Mount Etna), call them arancino, and have their own fillings. Ordering the wrong version in the wrong city marks you immediately. Both are stuffed fried rice balls — equally delicious, politically charged.'},
    {cat:'History',q:'Why is Sicily called the "crossroads of civilizations" and how does this show in daily life?',options:['A tourism slogan','Sicily was ruled by Greeks, Romans, Arabs, Normans, Spanish, and others — each left traces in the food, architecture, language, and DNA of Sicilians. The Arabic influence is especially visible in food and place names','Only in the architecture','Historical, not relevant today'],answer:1,exp:'Arab rule (9th-11th centuries) transformed Sicily. Arabs introduced citrus, sugar cane, almonds, jasmine, and irrigation. Sicilian cuisine is marked by sweet-savory combinations (caponata) from Arab tradition. Words like "zagara" (orange blossom) and "cuscusu" (couscous, still eaten in Trapani) are Arabic. The Norman-Arab-Byzantine architecture of Palermo is UNESCO-listed.'},
    {cat:'Food',q:'What is granita and why is it different from any other frozen dessert?',options:['Just flavored ice','A Sicilian frozen dessert with a coarser texture than sorbet — made with water, sugar, and real fruit or almond paste. In summer, brioche con granita (almond granita with a warm brioche bun) is breakfast in Sicily','An Italian gelato','Only available in summer'],answer:1,exp:'Sicilian granita comes from Arab "sharbat" (sorbet). Catanese granita is considered the finest — especially mandorla (almond) made from Avola almonds. Breakfast: split a soft brioche, fill it with granita, eat. The texture should be between ice and slush — icy crystals that melt immediately. Limone and fragola versions are standard. Gelato is separate.'},
    {cat:'Culture',q:'What is the Sicilian concept of "fari a figura" and why does it govern social interactions?',options:['An old-fashioned concept','Making a good impression — presentazione and bella figura matter enormously. You dress well to go to the market. You bring food when visiting. You speak well of your family. Shame (vergogna) is its opposite, and Sicilians work hard to avoid it','Only for formal occasions','Only applies to women'],answer:1,exp:'"Fari a figura" means maintaining dignity and making a good impression. It governs how Sicilians dress, what they bring when visiting, how they speak about family in public. Its opposite is "fare una brutta figura" — causing shame. The concept extends to hospitality: a Sicilian host will insist on feeding you to the point of discomfort because the alternative would reflect poorly on the family.'},
    {cat:'History',q:'What is the real history behind "The Godfather" and how do Sicilians feel about it?',options:['The film is completely fiction','The Mafia began in 19th century Sicily as local power structures in the absence of effective government. The Godfather romanticizes it; most Sicilians are frustrated by the stereotype, which overshadows the island\'s extraordinary art, food, and culture','Sicilians are proud of it','The Mafia is a US phenomenon'],answer:1,exp:'The Sicilian Mafia (Cosa Nostra) emerged in the 19th century power vacuum following unification. It\'s real, historically significant, and has caused enormous suffering. Most Sicilians are exhausted by the association — when "The Godfather" is the first thing outsiders mention, it erases 3,000 years of Greek temples, Arab-Norman cathedrals, and the richest cuisine in Italy. The anti-Mafia movement has deep roots.'},
    {cat:'Food',q:'What makes Sicilian cannolo different from what\'s served everywhere else?',options:['Nothing different','The shell must be fried fresh and filled immediately before serving — pre-filled cannoli go soggy. Authentic filling is fresh sheep\'s ricotta with candied fruit, not cream. The shell should crack when bitten','Primarily the size','Only the chocolate chips'],answer:1,exp:'The cannolo crisis: outside Sicily, they\'re often pre-filled, soggy, and use cow\'s ricotta. In Sicily, the shell (scorcia) is fried in lard, the filling is fresh pecora (sheep) ricotta, and it\'s assembled at the last moment. The snap of the shell is the test of quality. "Cannolo" is singular; "cannoli" is already plural — saying "one cannoli" marks you immediately.'},
  ]},

  'American English':{flag:'🇺🇸',lang:'English',questions:[
    {cat:'Culture',q:'What does "How are you?" actually mean in American small talk?',options:['A genuine question requiring an honest answer','A greeting, not a question — the expected response is "Good, how are you?" regardless of how you actually feel. Answering honestly in detail is considered oversharing','Only asked by close friends','The same as in other English-speaking countries'],answer:1,exp:'This confuses many non-Americans. "How are you?" in American English is a greeting equivalent to "hello." The script is: "How are you?" → "Good, you?" → "Good, thanks." Responding with genuine emotional content to a stranger asking this is a social miscalculation. In the UK or Australia, the same phrase carries slightly more genuine inquiry.'},
    {cat:'Language',q:'What is the difference between American and British English that trips people up most?',options:['Mostly spelling differences','The vocabulary gaps: Americans say "apartment" (British: flat), "elevator" (lift), "first floor" (ground floor in UK), "bathroom" (toilet/loo), "check" (bill at a restaurant). Plus American directness vs British indirectness in communication style','Only accents differ','American English is simpler'],answer:1,exp:'Beyond spelling (color/colour, center/centre), the vocabulary diverges significantly. "Tabling" a discussion means postponing it in American English but bringing it forward in British English — the opposite meaning. Americans tend to communicate more directly: "I disagree" vs the British "that\'s an interesting perspective." Neither is ruder — they\'re different communication cultures.'},
    {cat:'Culture',q:'What does "the American Dream" actually mean in practice vs. in theory?',options:['Equal success for everyone','The belief that through hard work, anyone can achieve success regardless of background — in theory. In practice, it drives a culture of individualism, optimism, and self-improvement, while critics note structural barriers make it harder for some to access','Only applies to immigrants','A historical concept'],answer:1,exp:'The American Dream — coined in 1931 by James Truslow Adams — is the idea of upward mobility through effort. It explains American work culture: long hours, side hustles, "self-made" mythology. It also explains American optimism and the cultural discomfort with talking about class or structural inequality. "You can make it if you try hard enough" is both inspiring and, critics say, used to explain away systemic barriers.'},
    {cat:'Culture',q:'Why is tipping culture so different in America vs. other countries?',options:['Americans are more generous','Service workers in the US often earn below minimum wage — legally — with the assumption tips will make up the difference. 18-20% is the standard at restaurants; less is considered an insult to service. In most other countries, service charge is included','Only in expensive restaurants','A recent development'],answer:1,exp:'American tipping norms exist because the federal tipped minimum wage is $2.13/hour — unchanged since 1991. Tips are not optional extras; they\'re how servers pay rent. Standard: 18-20% at sit-down restaurants, $1-2 per drink at bars, $1-2 per bag for hotel bellhops, 15-20% for taxis. Not tipping sends a message. The system is increasingly controversial but deeply entrenched.'},
    {cat:'Language',q:'What American slang has become global and what does it actually mean?',options:['American slang stays in America','Terms like "GOAT" (Greatest of All Time), "ghosting" (cutting contact without explanation), "to vibe" (to feel comfortable/compatible), "salty" (bitter/resentful), and "lowkey" (subtly/somewhat) originated in American urban slang and spread globally through social media','Slang is not important','Only young people use slang'],answer:1,exp:'American English — especially AAVE (African American Vernacular English) — has been the dominant source of global slang for decades. "Cool" is from 1940s jazz culture. "GOAT" originated in hip-hop. "Salty," "slay," "tea" (gossip), "throwing shade" — all from Black American culture. This cultural influence is significant and often under-credited to its origins.'},
    {cat:'Culture',q:'What is "small talk" in American culture and why do foreigners find it strange?',options:['The same as anywhere','American small talk is expected, abundant, and positive — cashiers, colleagues, strangers on elevators all engage in brief cheerful exchanges. Complaining to strangers is unusual; positivity is the default tone. Many cultures find this performative; Americans find silence with strangers uncomfortable','Only in service settings','An outdated concept'],answer:1,exp:'American small talk follows a script: weather, sports, weekend plans, "staying busy?" Complaining to strangers is a violation — you acknowledge problems briefly and pivot to optimism. This confuses people from cultures where silence is comfortable or where direct negative expression is normal. It\'s not fake — it\'s a genuine cultural value around social lubrication and projecting capability.'},
  ]},
  'Mexico':{flag:'🇲🇽',lang:'Spanish',questions:[
    {cat:'Food',q:'What is the difference between a taco al pastor and a regular taco?',options:['Just the meat type','Al pastor uses pork marinated in dried chiles and achiote, slow-cooked on a vertical spit — a technique brought by Lebanese immigrants. The pineapple on top is essential. It\'s one of Mexico\'s most iconic street foods','Only the tortilla differs','Al pastor is a breakfast taco'],answer:1,exp:'Tacos al pastor are a Lebanese-Mexican fusion: the vertical spit mirrors the shawarma technique brought by Lebanese immigrants to Mexico City. The pork is marinated in dried chiles and achiote. The slice of pineapple on top is not optional — it adds acidity that cuts the fat. Mexico City\'s taqueros are famous for their skill with the spit.'},
    {cat:'Food',q:'What is mole and why is it significant in Mexican culture?',options:['A simple chocolate sauce','A complex sauce made from dried chiles, spices, chocolate, and up to 30+ ingredients — each region and family has their own recipe. Making mole from scratch is a multi-day event, served at weddings and major celebrations','A type of Mexican cheese','A modern fusion dish'],answer:1,exp:'Mole (from Nahuatl \"molli\" meaning sauce) is one of Mexico\'s most complex culinary achievements. Mole negro can contain up to 30 ingredients — multiple dried chiles, chocolate, nuts, seeds, spices, even charred tortillas for body. Making it from scratch takes days. It\'s served at weddings, baptisms, and major celebrations. Every family has a recipe they consider the definitive version.'},
    {cat:'Food',q:'What is mezcal and how is it different from tequila?',options:['They\'re the same thing','Tequila is a specific type of mezcal made only from blue agave in Jalisco. Mezcal uses dozens of agave varieties from Oaxaca and other regions. Mezcal typically has a smokier taste from roasting the agave hearts in underground pits','Mezcal is cheaper tequila','Tequila is stronger'],answer:1,exp:'All tequila is mezcal, but not all mezcal is tequila. Tequila has strict rules: must be blue agave (Weber azul) in Jalisco. Mezcal uses 40+ agave varieties — espadín, tobalá, tepeztate — often in Oaxaca. The smoky flavor comes from roasting the piñas in underground pits. The mezcal revival made it a global premium spirit, but traditionally it was a village drink.'},
    {cat:'Music',q:'What is corrido tumbado and how did it evolve from traditional corridos?',options:['An unrelated genre','Traditional corridos were ballads telling stories of heroes and outlaws. Corridos tumbados fuse that storytelling tradition with trap beats — artists like Peso Pluma and Natanael Cano brought it global','Only popular outside Mexico','A type of mariachi'],answer:1,exp:'The corrido is over 150 years old — ballads that chronicled heroes, villains, and historical events. Corridos tumbados emerged in the 2010s in Sonora and Sinaloa, blending that storytelling tradition with trap production. Peso Pluma broke it globally in 2023. The genre is controversial — many narco corridos glamorize cartel life — but its cultural roots in working-class storytelling are deep and genuine.'},
    {cat:'Music',q:'What is mariachi and where did it originate?',options:['A Mexico City invention','Mariachi originated in Jalisco (Guadalajara region) in the 19th century. A traditional ensemble includes guitarrón, vihuela, guitar, violin, and trumpet. Serenatas (serenades) with mariachi for birthdays, Mother\'s Day, and declarations of love are a genuine cultural practice','A government-created tradition','Music only for tourists'],answer:1,exp:'Mariachi originated in rural Jalisco in the 19th century. The modern ensemble (guitarrón, vihuela, guitar, violin, trumpet) was formalized in the 20th century. Plaza Garibaldi in Mexico City is the famous hub where you hire mariachi for serenatas. Sending a mariachi to someone\'s window at 6am for their birthday is a very real cultural tradition.'},
    {cat:'Slang',q:'What does \"güey\" (wey) mean and how is it used?',options:['An insult only','Originally a derogatory term, now the most common Mexican term of address — roughly equivalent to \"dude.\" Used constantly between friends. Context determines whether it\'s friendly or offensive','Only used by young people','A regional word'],answer:1,exp:'\"Güey\" comes from \"buey\" (castrated ox), originally an insult. It was reclaimed and is now Mexico\'s most-used informal address. Between friends it means \"dude/man/bro.\" With strangers or in formal settings it\'s offensive. \"¿Qué onda, güey?\" (What\'s up, dude?) is completely ubiquitous.'},
    {cat:'Slang',q:'What does \"órale\" mean?',options:['Goodbye','A versatile exclamation meaning \"okay,\" \"let\'s go,\" \"right on,\" or expressing agreement and enthusiasm depending on tone and context. It\'s one of the most distinctly Mexican words in existence','A food term','Only used in Monterrey'],answer:1,exp:'\"Órale\" is distinctly Mexican with at least five meanings depending on tone: agreement (\"órale\" = okay/sure), encouragement (let\'s go!), surprise (wow!), hurrying someone (move it!), and approval. It appears in countless Mexican films and is immediately recognizable as Mexican.'},
    {cat:'Slang',q:'What does \"chido/chida\" mean?',options:['Ugly or bad','Cool, awesome, great — the Mexican equivalent of \"cool.\" \"Está muy chido\" = that\'s really cool. Widely used across Mexico, especially by younger generations','Expensive','Spicy food'],answer:1,exp:'\"Chido\" (masc) / \"chida\" (fem) is Mexico\'s primary slang for cool/awesome. \"Está muy chida esa película\" = that film is really cool. It\'s class-neutral and generation-spanning, used everywhere from Mexico City to rural Oaxaca.'},
    {cat:'Culture',q:'What is Día de Muertos and why is it not \"Mexican Halloween\"?',options:['It\'s basically the same thing','Día de Muertos (Nov 1-2) is a pre-Hispanic tradition honoring deceased family members. Families build ofrendas (altars) with photos, food, and marigolds. It\'s a joyful reunion with the dead, not a scary holiday','A Catholic import','Only celebrated in Oaxaca'],answer:1,exp:'Día de Muertos combines Aztec traditions with Catholic All Saints\'/All Souls\' Days. Ofrendas include the deceased\'s favorite food and objects, marigolds (cempasúchil), candles, and photos. In Oaxaca and Michoacán, families spend the night in cemeteries with their loved ones. UNESCO recognized it as Intangible Cultural Heritage in 2008. Calling it \"Mexican Halloween\" fundamentally misses its celebration of memory and continuity.'},
    {cat:'Culture',q:'What is the quinceañera and what does it represent?',options:['Just a big birthday party','A Catholic and cultural coming-of-age ceremony for girls turning 15, combining Mass, a reception, and symbolic rituals (last doll, changing of shoes, waltz with father). It celebrates the transition from childhood to womanhood','A Mexican invention only','Declining in importance'],answer:1,exp:'The quinceañera has roots in Aztec female coming-of-age rituals merged with Spanish Catholic traditions. The ceremony typically includes a thanksgiving Mass, the last doll (symbolizing childhood left behind), the changing from flats to heels, a waltz with her father, and a choreographed dance with chambelanes (escorts). Families save for years for this celebration.'},
    {cat:'Culture',q:'What is lucha libre and what makes it distinct?',options:['Just wrestling with masks','A uniquely Mexican form of professional wrestling defined by acrobatic style, colorful masks, and larger-than-life characters. The mask is sacred — losing it in a wager match is a major humiliation. Luchadores like El Santo became national heroes','A recent American import','Only popular in Mexico City'],answer:1,exp:'Lucha libre developed in Mexico in the 1930s with its own rules and aesthetics. The high-flying style (topes, hurricanranas, moonsaults) was developed in Mexican rings. The mask is the defining element — unmasking is one of the most dramatic moments in the sport. El Santo, Blue Demon, and Mil Máscaras became cultural icons with films, comics, and merchandise.'},
    {cat:'History',q:'What was the Mexican Revolution and why does it still define Mexican identity?',options:['A brief political dispute','A decade-long civil war (1910-1920) that overthrew Porfirio Díaz\'s 30-year dictatorship. Figures like Emiliano Zapata and Pancho Villa became symbols of agrarian justice. The 1917 Constitution and mythology of indigenous dignity still shape Mexican politics','A peaceful transition','A foreign intervention'],answer:1,exp:'The Mexican Revolution began in 1910 when Francisco Madero challenged Díaz. Over 1 million people died. Zapata\'s cry \"Tierra y Libertad\" (Land and Freedom) echoes in Mexican politics today. The resulting 1917 Constitution was one of the world\'s first to enshrine social rights. Zapata\'s image on murals everywhere represents the unfulfilled promise of the revolution.'},
    {cat:'History',q:'What are the murales of Diego Rivera and what do they say about Mexico?',options:['Tourist decorations','Massive public artworks in government buildings depicting Mexican history from pre-Hispanic civilization through the revolution — a deliberate project to create national identity and celebrate indigenous heritage after decades of European cultural dominance','Private art for the wealthy','Recent art installations'],answer:1,exp:'The muralist movement (Rivera, Orozco, Siqueiros) was government-commissioned after the revolution to educate a largely illiterate population and construct national identity. Rivera\'s murals in the National Palace depict all of Mexican history celebrating indigenous heritage that had been suppressed. His Palacio Nacional murals took 25 years to complete. The murals are genuinely one of the great achievements of 20th-century public art.'},
  ]},
  'Colombia':{flag:'🇨🇴',lang:'Spanish',questions:[
    {cat:'Food',q:'What is the bandeja paisa and what does it reveal about Colombian culture?',options:['A light salad','The defining dish of Antioquia — a massive plate with rice, red beans, chicharrón, chorizo, fried egg, arepa, avocado, and ground beef. It originated as a high-calorie meal for farmers and miners working the Andes','A coastal seafood dish','A Bogotá invention'],answer:1,exp:'The bandeja paisa (\"paisa tray\") comes from the Antioquia region (Medellín, Manizales, Pereira). \"Paisa\" refers to people from this region, known for their work ethic and entrepreneurial spirit. The dish\'s caloric density reflects its origins feeding Andean farmers. The arepa on a bandeja paisa is white and unseasoned — a base, not a flavor. It\'s Colombia\'s most recognized national dish.'},
    {cat:'Food',q:'What is ajiaco and why is it especially associated with Bogotá?',options:['A seafood stew','A thick chicken soup made with three types of potato (papa criolla, pastusa, capira), guascas herb, and corn — native to the Bogotá highlands. The three potato varieties give unique texture: some dissolve thickening the broth, others remain whole','A dessert from the coast','A modern fusion dish'],answer:1,exp:'Ajiaco is the definitive soup of Bogotá. The three potato varieties are essential — papa criolla disintegrates and thickens; the others hold their shape. Guascas, a dried Andean herb, gives it a distinctive earthy flavor you can\'t replicate without it. Served with cream, capers, and avocado on the side. On cold Bogotá mornings (2,600m altitude), ajiaco is national-level comfort food.'},
    {cat:'Food',q:'What is aguardiente and why is it Colombia\'s national drink?',options:['A type of wine','An anise-flavored spirit distilled from sugarcane, produced in regional varieties across Colombia. Antioqueño (from Medellín) is the most famous. Shared communally at celebrations, it\'s deeply associated with Colombian social culture','A craft beer','A cocktail only found in Bogotá'],answer:1,exp:'Each Colombian department has its own aguardiente brand — Antioqueño, Cristal, Néctar — and Colombians are tribal about which is best. It\'s drunk in shots, shared communally, and considered classless (enjoyed by rich and poor alike). The bottle is passed around the table. \"Echemos un aguardientico\" (let\'s have a little aguardiente) is a genuine social invitation. Refusing is noticed.'},
    {cat:'Food',q:'What is a tinto in Colombia and why is it significant?',options:['A type of red wine','A small cup of black coffee served throughout the day — not espresso, but light drip coffee, often sweet. Offered constantly in offices, homes, and by street vendors. Accepting a tinto is a social gesture','An expensive coffee drink','Only served in the morning'],answer:1,exp:'A tinto (literally \"tinted\") is Colombia\'s everyday coffee — small, often slightly sweet, drunk all day. Despite Colombia producing world-class beans (most exported), the domestic tinto is simple and democratic. The tinto is social currency: office workers offer it to visitors, vendors sell it from thermoses on street corners. \"¿Le pongo un tinto?\" is how Colombians make people feel at home.'},
    {cat:'Music',q:'What is vallenato and why did it win UNESCO recognition?',options:['A type of salsa','A musical genre from Colombia\'s Caribbean coast built around accordion, caja drum, and guacharaca. Its four rhythms tell stories of love, loss, and daily life. Gabriel García Márquez called it \"the novel of the Colombian people\"','A modern electronic genre','Only popular in Bogotá'],answer:1,exp:'Vallenato emerged in the Caribbean department of Cesar and La Guajira, combining African, indigenous Wayuu, and Spanish musical traditions. The accordion was introduced by German settlers in the 19th century. Carlos Vives brought it global in the 1990s. UNESCO inscribed vallenato on its Intangible Cultural Heritage list in 2015. García Márquez called it the novel of the Colombian people and championed it throughout his career.'},
    {cat:'Music',q:'What is cumbia and where did it originate?',options:['A Cuban import','A Colombian musical genre born on the Caribbean coast from the fusion of African, indigenous, and Spanish elements. Originated among enslaved Africans in Cartagena. It spread across Latin America and became the rhythmic foundation for many regional variations','A Bogotá urban genre','A 20th-century invention'],answer:1,exp:'Cumbia originated in the colonial period on Colombia\'s Caribbean coast as African enslaved people created music from available instruments — drums and gaita (indigenous flute). It spread throughout Latin America and mutated into Mexican cumbia, Argentine cumbia villera, and Peruvian chicha. The original Colombian cumbia remains the root. Carlos Vives modernized it for the 1990s mainstream.'},
    {cat:'Slang',q:'What does \"parce\" or \"parcero\" mean in Colombian slang?',options:['An insult','Close friend or buddy — roughly \"mate,\" \"bro,\" or \"homie.\" Especially used in Medellín and among Paisa culture. \"¿Qué más, parce?\" (What\'s up, mate?) is a common Medellín greeting','Only used in Cali','A formal term'],answer:1,exp:'\"Parcero\" (shortened to \"parce\") comes from the idea of sharing land (parcela) — a companion who shares your space and life. It\'s the defining Paisa (Antioqueño) term of friendship. In Bogotá, \"parce\" can sound slightly regional; in Medellín it\'s completely natural.'},
    {cat:'Slang',q:'What does \"chévere\" mean?',options:['Bad or disappointing','Great, cool, awesome — one of the most pan-Latin American slang terms, deeply associated with Colombia. \"Está chévere\" = it\'s great/cool. Used across all social classes and generations','Only used by older generations','A Venezuelan word'],answer:1,exp:'\"Chévere\" is used across Latin America but is particularly associated with Colombia and Venezuela. Its origin is disputed — possibly from African Yoruba via Cuban Spanish. In Colombia it functions as an all-purpose positive adjective. Colombians use it constantly and it\'s one of the first slang words foreigners learn.'},
    {cat:'Slang',q:'Why do many Colombians use \"usted\" with close friends and family?',options:['It\'s a mistake','In Bogotá and Antioquia, using \"usted\" (the formal \"you\") with close friends and even romantic partners is completely normal and affectionate — it doesn\'t signal distance. \"¿Cómo está usted, mi amor?\" is natural','Only with elders','A dying tradition'],answer:1,exp:'The Colombian usted phenomenon is one of the most fascinating features of Colombian Spanish. In Bogotá and Paisa regions, usted is the default address even between intimate partners. Switching to \"tú\" can actually sound distant or performative. \"Usted\" carries warmth and respect in Colombian culture — it\'s a reminder that Spanish pronouns don\'t map cleanly onto English assumptions about formality.'},
    {cat:'Culture',q:'What is the Carnaval de Barranquilla and why does it matter globally?',options:['A small local festival','One of the largest carnivals in the world, lasting four days before Lent. It blends African, indigenous, and Spanish traditions in music, dance, and costume. UNESCO recognized it as Intangible Cultural Heritage','A recent tourism creation','Only a religious event'],answer:1,exp:'The Carnaval de Barranquilla celebrates the cultural fusion of Colombia\'s Caribbean coast. The cumbia, porro, mapalé, and Congo dances showcase African and indigenous heritage. Shakira was born in Barranquilla — her global success is partly an expression of the city\'s rich cultural DNA. UNESCO inscribed it in 2003.'},
    {cat:'Culture',q:'What is \"magical realism\" and why is it associated with Colombia?',options:['A film genre','A literary style where magical events are presented as ordinary reality — pioneered by Gabriel García Márquez in \"Cien años de soledad.\" It reflects Caribbean Colombian culture\'s blending of the real and the supernatural as a normal part of life','A Colombian government campaign','Only in García Márquez\'s work'],answer:1,exp:'García Márquez\'s 1967 novel \"Cien años de soledad\" brought magical realism to global consciousness and won him the Nobel Prize in 1982. In the novel, ghosts are normal and Remedios the Beauty ascends to heaven. This reflects Caribbean Colombian culture where folk beliefs and the supernatural coexist naturally with daily life. García Márquez said he was simply writing the world as his grandmother described it.'},
    {cat:'History',q:'How has Colombia transformed its image since the 1990s?',options:['It hasn\'t changed much','Medellín — once the most dangerous city in the world due to Pablo Escobar\'s cartel — was radically transformed through urban planning and social investment: cable cars connecting hillside comunas, park libraries, better schools. It won the Urban Land Institute\'s Most Innovative City award in 2013','Only tourism improved','The change is mostly cosmetic'],answer:1,exp:'In 1991, Medellín had 381 murders per 100,000 people. By 2013 it had dropped over 95%. The transformation came through targeted social investment in the poorest comunas: Metrocable connecting hillside neighborhoods, escalators in steep streets, park libraries, better schools. The urban planning innovations are genuine and internationally recognized, studied by cities worldwide.'},
  ]},
  'Castilian':{flag:'🇪🇸',lang:'Spanish',questions:[
    {cat:'Food',q:'What is the difference between a tortilla española and a Mexican tortilla?',options:['They\'re similar flatbreads','A tortilla española is a thick omelette made with eggs and potato — a staple of Spanish bar culture, served as a tapa or a meal. It has nothing to do with the thin Mexican corn or flour flatbread','Both are pancakes','The Spanish version is newer'],answer:1,exp:'The tortilla española (tortilla de patatas) is one of Spain\'s most beloved dishes — a thick egg-and-potato omelette eaten at any hour, hot or cold, in tapas bars, at home, and in sandwiches. The debate over whether it should include onion is one of Spain\'s great cultural divides. A 2022 survey found Spain almost evenly split. The Mexican tortilla shares only the name.'},
    {cat:'Food',q:'What is jamón ibérico de bellota and why is it so revered?',options:['Just any cured ham','The highest grade of Spanish cured ham — from free-range Iberian pigs that roam oak forests and eat only acorns (bellotas). The fat marbles through the meat creating a nutty, complex flavor. A single leg can cost €500-1000','A cheap everyday product','A recent invention'],answer:1,exp:'Jamón ibérico de bellota is at the apex of Spain\'s cured meat tradition. The black-hoofed Iberian pig (pata negra) produces uniquely marbled meat due to genetics and the montanera (acorn-feeding period). The fat has a high oleic acid content similar to olive oil, giving it a silky texture that melts at room temperature. Spanish bars have legs of ham hanging from the ceiling as both food and decoration.'},
    {cat:'Food',q:'What are pintxos and how are they different from tapas?',options:['The same thing','Pintxos are Basque Country bar snacks — small pieces of bread with toppings, displayed on the bar counter and grabbed by customers. Tapas are small shared dishes associated with southern Spain and may come free with drinks in some regions','Pintxos are a modern trend','Only found in Barcelona'],answer:1,exp:'Pintxos (Basque: \"pintxo\") are the defining food of San Sebastián and the Basque Country. You walk from bar to bar, grabbing pintxos from the counter and keeping toothpicks to count what you ate. The quality in San Sebastián — which has one of the highest concentrations of Michelin stars per capita in the world — is extraordinary. Tapas may come free with drinks in Granada, Almería, and León — an unwritten rule that confuses visitors.'},
    {cat:'Music',q:'What is flamenco and what are its cultural roots?',options:['A folk dance from Barcelona','An art form (music, song, dance) born in Andalusia from the fusion of Romani, Moorish, and Spanish folk traditions. The deep song (cante jondo) expresses extreme emotion. UNESCO recognized it as Intangible Cultural Heritage in 2010','A modern Spanish invention','Only performed for tourists'],answer:1,exp:'Flamenco emerged in Andalusia (Seville, Cádiz, Jerez) in the 18th-19th centuries as Romani (gitano) musicians fused their traditions with Moorish and Spanish folk elements. The duende — the emotional power that great flamenco generates — is central to the art. Federico García Lorca wrote about it. It\'s not background music; great flamenco is an intense, intimate experience.'},
    {cat:'Music',q:'What is Rosalía\'s significance in contemporary Spanish music?',options:['Just a pop star','A Catalan artist who fused traditional flamenco with electronic production and hip-hop, winning three Latin Grammys and global critical recognition — representing a new generation reinterpreting Spanish heritage for a global audience','A flamenco traditionalist','Only popular outside Spain'],answer:1,exp:'Rosalía studied flamenco at the Escola Superior de Música de Catalunya. \"El Mal Querer\" (2018) fused flamenco structures with trap production. \"MOTOMAMI\" (2022) pushed further into reggaeton and electronic music. She\'s controversial in flamenco circles — some purists call it exploitation — but her technical command of flamenco is genuine and earned over years of study.'},
    {cat:'Slang',q:'What does \"tío/tía\" mean in Spanish slang?',options:['Uncle/aunt only','In colloquial Spanish, tío/tía means \"dude/guy\" or \"girl\" — used like \"man\" in English. \"¿Qué pasa, tío?\" = what\'s up, man? It has no family meaning in casual speech','A formal term of address','Only used in Madrid'],answer:1,exp:'\"Tío/tía\" in colloquial Spanish means \"dude\" or \"guy\" — completely detached from its literal uncle/aunt meaning. It\'s ubiquitous in Spain but less common in Latin America (where it sounds European). \"Ese tío\" = that guy. \"¿Qué pasa, tía?\" = what\'s up, girl? It\'s class-neutral and generation-spanning — your grandfather uses it and so does your classmate.'},
    {cat:'Slang',q:'What does \"mola\" mean and where does it come from?',options:['A type of food','A colloquial Spanish verb meaning \"it\'s cool/great/I like it.\" \"Mola mucho\" = it\'s really cool. It comes from Romani (Caló) language — much of Spanish working-class slang has Romani roots','An insult','Only used by teenagers'],answer:1,exp:'\"Molar\" comes from Caló, the Romani language spoken in Spain. \"Me mola ese tío\" = I like that guy. The Romani influence on Spanish slang is significant and underacknowledged — words like \"mola,\" \"chaval\" (kid), \"currar\" (to work), and \"parné\" (money) all come from Caló. The Roma have been in Spain since the 15th century and their language shaped working-class Spanish.'},
    {cat:'Slang',q:'What does \"venga\" mean in Spanish?',options:['Come here only','A versatile word meaning okay/alright, bye, come on, let\'s go, or expressing agreement — context-dependent. \"Venga, nos vemos\" = okay, see you. \"¡Venga ya!\" = come on!/no way! It ends many Spanish conversations','Only in Andalusia','A formal word'],answer:1,exp:'\"Venga\" is conjugated from \"venir\" (to come) but functions as pure social lubricant. It closes conversations, agrees with suggestions, expresses disbelief, and hurries people. In Andalusia it can be shortened to \"vnga\" in text messages. It\'s one of the most Spanish words in the language — foreigners learn it fast and locals notice when you use it naturally.'},
    {cat:'Culture',q:'What is la sobremesa and why do Spanish people value it?',options:['A type of tablecloth','The time spent at the table after eating — talking, having coffee, not rushing to leave. It can last longer than the meal itself. La sobremesa is a deliberate Spanish value: you don\'t eat and run','Only in restaurants','A dying tradition'],answer:1,exp:'La sobremesa (\"over the table\") is one of Spain\'s most distinctive cultural values. The meal is not over when the food is eaten — it continues with coffee, digestives, and conversation. Rushing out is considered rude and antisocial. A Sunday family lunch with sobremesa can last four hours — the eating part was two. It reflects the Mediterranean view that relationships and conversation are ends in themselves, not things to manage efficiently.'},
    {cat:'Culture',q:'What was la Movida Madrileña and why was it significant?',options:['A traffic problem','The cultural explosion in Madrid following Franco\'s death in 1975 — art, music, film, and sexual freedom erupting after 40 years of dictatorship. Pedro Almodóvar, Alaska, Mecano. Madrid became one of Europe\'s most vibrant cultural capitals in under a decade','A food movement','A political party'],answer:1,exp:'After 36 years of Francoism, Spain went from one of Europe\'s most conservative to most permissive societies in just a few years. Madrid\'s Malasaña neighborhood became the center. Pedro Almodóvar made transgressive films. Punk bands, new wave, experimental art. Spain essentially lived out the 60s, 70s, and 80s simultaneously. Its speed and intensity were unique in European cultural history.'},
    {cat:'History',q:'What was the Spanish Civil War and why does it still divide Spain?',options:['A brief conflict','A brutal war (1936-1939) between the elected Republican government and Franco\'s Nationalist forces (backed by Nazi Germany and Fascist Italy). Over 500,000 died. Franco ruled until 1975. The war\'s wounds — mass graves, suppressed memory — were never fully processed','A colonial war','A conflict Spain has fully resolved'],answer:1,exp:'The Spanish Civil War became an international proxy conflict: Nazi Germany and Mussolini backed Franco; the Soviet Union backed the Republic; 35,000 international volunteers (including Hemingway and Orwell) fought for the Republic. Franco won and installed a 36-year dictatorship. Unlike Germany, Spain never conducted a formal reckoning with fascism. Unmarked mass graves still contain Republican victims. This division resurfaces in Spanish politics regularly.'},
    {cat:'History',q:'What is the significance of the 1978 Spanish Constitution?',options:['Just a legal document','The constitution drafted after Franco\'s death that transformed Spain into a parliamentary democracy — La Transición. It created autonomous communities giving regions like Catalonia and the Basque Country significant self-governance','A colonial era document','Written by foreigners'],answer:1,exp:'La Transición (1975-1982) was Spain\'s peaceful transformation from dictatorship to democracy. The 1978 Constitution was a negotiated settlement — everyone gave something up for stability. The autonomous communities system created 17 regions with significant powers. It\'s now being stress-tested: Catalonia\'s 2017 independence referendum was declared illegal under it, and unresolved tensions around regional sovereignty continue to shape Spanish politics.'},
  ]},
  'Haiti':{flag:'🇭🇹',lang:'Creole',questions:[
    {cat:'History',q:'What makes Haiti\'s independence in 1804 unique in world history?',options:['It was a peaceful transition','Haiti was the first and only successful slave revolution to create a nation — enslaved Africans defeated Napoleon\'s army and founded the first Black republic in the world','France gave Haiti independence','It was a colonial war'],answer:1,exp:'The Haitian Revolution (1791-1804) shocked the world. Enslaved Africans under Toussaint Louverture and Jean-Jacques Dessalines defeated the most powerful army in Europe. Haiti declared independence January 1, 1804. The US refused to recognize Haiti for decades — its existence terrified slaveholding nations. Haiti\'s revolution directly influenced abolition movements worldwide and remains one of history\'s most extraordinary events.'},
    {cat:'History',q:'What is the significance of "Bwa Kayiman" in Haitian history?',options:['A mountain range','A ceremony held in August 1791 where enslaved people gathered, made a pact, and launched the Haitian Revolution — the spiritual origin point of Haitian independence','A coastal fort','A type of dance'],answer:1,exp:'Bwa Kayiman (Bois Caïman) was a ceremony held on August 14, 1791, led by the houngan (Vodou priest) Dutty Boukman. Participants made a blood oath to fight for freedom. The revolution began days later. For Haitians, Bwa Kayiman is the spiritual birthplace of their nation — the moment the revolution was consecrated. It is both historical fact and national myth.'},
    {cat:'Culture',q:'What is Vodou and what is misunderstood about it outside Haiti?',options:['A form of black magic','A legitimate Afro-Haitian religion that blends West African spiritual traditions with Catholic elements. It involves lwa (spirits), ceremony, and healing — not curses or zombies as portrayed in Western media','A dance style','A recent invention'],answer:1,exp:'Vodou (also spelled Voodoo) is a genuine religion practiced by millions. It emerged from the fusion of West African religious traditions (especially Fon and Ewe from Dahomey) with elements of Catholicism forced on enslaved people. Lwa are spiritual forces — Erzulie Freda (love), Baron Samedi (death and resurrection), Ogou (war and justice). The zombie myth comes from a real pharmacological practice used to punish community members but has been sensationalized beyond recognition. Vodou sustained Haitian identity through slavery and remains central to cultural life.'},
    {cat:'Culture',q:'What is Rara and when does it happen?',options:['A type of food','A street procession tradition during Lent featuring bamboo trumpets (vaksin), drums, and costumed bands that move through neighborhoods in celebration and spiritual ceremony','A political movement','A harvest festival'],answer:1,exp:'Rara happens during the Lenten season (Carnival to Easter) — when Vodou tradition says spirits roam the earth. Rara bands (bann rara) process through streets with vaksin (bamboo trumpets), drums, and ratchets. It\'s deeply spiritual, community-based, and tied to Vodou ceremony. In the Haitian diaspora, Rara has spread to New York, Miami, and Montreal. It represents the survival of African ceremonial tradition through slavery and colonization.'},
    {cat:'Culture',q:'What is the significance of Carnival in Haiti?',options:['A small local festival','The biggest celebration of the year — a three-day street festival before Lent with massive sound systems, costumed bands (bann a pye), and politically satirical songs. The Sunday night show in Port-au-Prince draws hundreds of thousands','A religious ceremony','Only for the elite'],answer:1,exp:'Haitian Carnival is among the most intense in the Caribbean. It begins the Sunday before Mardi Gras. The meringue and kompa music is deafening, the crowds are enormous, and the satirical songs (often attacking politicians by name) are a form of free political speech. Bann a pye (bands on foot) parade through neighborhoods. Carnival is genuinely democratic — it belongs to everyone and the street reclaims the city for three days.'},
    {cat:'Food',q:'What is joumou soup and why is it eaten on January 1st?',options:['Just a pumpkin soup','A rich pumpkin and beef soup eaten every January 1st to celebrate Haitian Independence Day. Under French colonization, enslaved people were forbidden from eating joumou — reserved for their enslavers. Free Haitians ate it on the first day of independence as an act of liberation','A Christmas food','A recent tradition'],answer:1,exp:'Soup joumou (pumpkin soup) is Haiti\'s most politically meaningful food. Under French slavery, joumou soup was a luxury forbidden to the enslaved. On January 1, 1804 — the day of independence — Haitians ate it as a declaration of freedom. Every January 1st since, Haitian families make and share joumou. UNESCO inscribed the tradition on its Intangible Cultural Heritage list in 2021. Eating joumou is an act of memory, pride, and communal celebration.'},
    {cat:'Food',q:'What is griot and why is it central to Haitian cuisine?',options:['A type of flatbread','Fried pork — marinated in citrus and spices, slow-cooked, then deep-fried until crispy. Served with pikliz (spicy pickled vegetables) and riz et pois (rice and beans). It\'s Haiti\'s unofficial national dish','A type of stew','A dessert'],answer:1,exp:'Griot (pronounced "gree-oh") is marinated pork that is first simmered, then fried to get a crispy exterior and tender interior. The marinade — sour orange (citron), thyme, garlic, Scotch bonnet — gives it a distinctly Haitian flavor. Served with pikliz (a fiery vinegar-pickled cabbage) and riz et pois. You\'ll find it at every party, family gathering, and street food stand. It\'s the dish Haitians in the diaspora most crave from home.'},
    {cat:'Food',q:'What is pikliz and what does it reveal about Haitian food culture?',options:['A type of pickle from Europe','A vinegar-pickled condiment of cabbage, carrots, and Scotch bonnet peppers — fiery and essential. Served with almost every Haitian dish, especially griot. Heat and acid are fundamental to Haitian flavor','A sweet relish','A French import'],answer:1,exp:'Pikliz (pronounced "peek-leez") is non-negotiable in Haitian cooking. The combination of vinegar, Scotch bonnet peppers, and vegetables provides the sharp, fiery contrast to rich fried and stewed meats. Haitian food is bold — not subtle. The African culinary tradition of fermented and pickled condiments survived through slavery and became central to Haitian taste. Every Haitian family has their own pikliz recipe and heat level.'},
    {cat:'Language',q:'What is the difference between Haitian Creole and French?',options:['They are basically the same language','Haitian Creole is a separate, complete language that developed from French but has African grammatical structures, different vocabulary, and distinct pronunciation. A French speaker cannot understand Creole without learning it. About 90% of Haitians speak Creole as their first language','Creole is just simplified French','Creole is only spoken by the poor'],answer:1,exp:'Haitian Creole is a fully developed language, not broken French. The grammar is fundamentally different — no verb conjugation, postpositive articles, different tense markers. About 40% of vocabulary has French roots but pronunciation is so different it\'s often unintelligible to French speakers. The other vocabulary comes from West African languages (Fon, Ewe, Wolof), English, Spanish, and indigenous Taíno. Both Creole and French are official languages of Haiti, but Creole is what 90%+ of Haitians actually speak at home.'},
    {cat:'Language',q:'What does "Sak pase / N ap boule" mean and why is it important?',options:['A formal greeting','The most common call-and-response greeting in Haitian — "What\'s up? / We\'re managing / We\'re good." Learning the response is as important as the greeting. Using it marks you as someone who understands the culture','A farewell','A religious phrase'],answer:1,exp:'\"Sak pase?\" (literally \"what\'s happening?\") and the response \"N ap boule\" (literally \"we\'re burning\" — meaning we\'re getting by, we\'re good) is the fundamental Haitian social exchange. Like \"¿Qué lo qué / Ahí tamo\' \" in Dominican or \"Sup / Not much\" in American English — it\'s social glue. The response encodes something important about Haitian resilience: life is hard, but we\'re managing. Learning both sides of the exchange is essential.'},
    {cat:'Music',q:'What is kompa and why is it central to Haitian identity?',options:['A type of drum','Haiti\'s national popular music genre — a slow, hypnotic dance music with African rhythms and brass. Created by Nemours Jean-Baptiste in 1955. Kompa is the soundtrack of Haitian celebrations worldwide from Port-au-Prince to Brooklyn','A religious chant','A recent import'],answer:1,exp:'Kompa (also spelled compas) was created by guitarist Nemours Jean-Baptiste in 1955 by fusing meringue with Cuban son and African rhythmic traditions. Its characteristic 4/4 beat and brass arrangements became instantly distinctive. Kompa is the music of Haitian parties, weddings, and nostalgia — diaspora Haitians in New York, Miami, and Montreal use it to maintain connection to home. Bands like Tabou Combo, Zin, and T-Vice carry it globally.'},
    {cat:'Music',q:'What is "twoubadou" and what tradition does it represent?',options:['A type of drum','Haitian troubadour music — romantic ballads in Creole influenced by Cuban bolero and African traditions. Artists like BélO and Coupé Cloué created intimate, poetic songs about love, loss, and Haitian life','A carnival genre','Only popular in rural areas'],answer:1,exp:'Twoubadou (troubadour) is Haiti\'s romantic music tradition — intimate acoustic ballads with introspective Creole lyrics. Coupé Cloué was its greatest practitioner — witty, wise, and deeply Haitian. BélO carries the tradition forward today. Twoubadou is what you hear in quieter moments — at home, at smaller gatherings, among friends who want to feel something real. It represents a different side of Haitian music from kompa\'s energy.'},
    {cat:'Culture',q:'What does "lakou" mean in Haitian culture?',options:['A type of market','A traditional communal courtyard shared by an extended family — the basic unit of rural Haitian social organization. Multiple households share a lakou, including resources, childcare, and ceremonies','A political structure','A dance style'],answer:1,exp:'The lakou (from French \"la cour\" — the courtyard) is the foundation of traditional Haitian rural life. Extended families live around a shared courtyard — not just as geography but as a social and spiritual unit. The lakou has a peristyle (Vodou temple), shared cooking areas, and collective responsibility for children and elders. The lakou system helped Haitians survive slavery and continues to structure rural life. Urban migration weakened it but lakou logic — collective responsibility, extended family bonds — shapes Haitian social values everywhere.'},
  ]},
  'Puerto Rico':{flag:'🇵🇷',lang:'Spanish',questions:[
    {cat:'Food',q:'What is a "jibarito" in Puerto Rican cuisine?',options:['A small coffee','A sandwich made with flattened fried plantains instead of bread','A type of fried pork','A rice and bean dish'],answer:1,exp:'The jibarito replaces bread with tostones (flattened, twice-fried green plantains). It is filled with steak, lettuce, tomato, and garlic mayo. A Chicago invention by Puerto Rican immigrants, but deeply claimed as boricua.'},
    {cat:'Food',q:'What is "mofongo" and what makes it distinctly Puerto Rican?',options:['A seafood stew','Mashed fried plantains with garlic and pork crackling, often served as a bowl for seafood or meat','A sweet coconut dessert','Fried rice with sofrito'],answer:1,exp:'Mofongo is mashed tostones pounded with garlic, olive oil, and chicharron. Often shaped into a bowl and filled with shrimp, chicken, or pork broth. Puerto Rico most iconic dish.'},
    {cat:'Slang',q:'What does "Wepa!" mean?',options:['Watch out','A general exclamation of joy, excitement, or approval','Goodbye','Lets go'],answer:1,exp:'Wepa is one of Puerto Ricos signature expressions — used to celebrate, cheer, express surprise, or show enthusiasm. The boricua equivalent of "Woohoo!"'},
    {cat:'Slang',q:'If someone calls you "pana" in Puerto Rico, what do they mean?',options:['An insult','A close friend or buddy','Someone who is annoying','A stranger'],answer:1,exp:'Pana means close friend or buddy, similar to bro or mate. Mi pana is a term of warm affection between friends.'},
    {cat:'Slang',q:'What does "boricua" mean?',options:['A Puerto Rican person, derived from the Taino name for the island','A type of street food','A term for someone from San Juan only','A musical style'],answer:0,exp:'Boricua comes from Boriken — the Taino indigenous name for Puerto Rico. A proud self-identifier used with great pride.'},
    {cat:'Culture',q:'What is a "parranda"?',options:['A type of rice dish','A surprise Christmas carol group that shows up at your house at midnight and will not leave until you feed them','A formal dance','A beach bonfire'],answer:1,exp:'A parranda is a Puerto Rican Christmas tradition where a group surprises a friends house late at night playing music, singing, and demanding food and drinks. The host then joins to surprise the next person. Joyful chaos.'},
    {cat:'Culture',q:'What makes Puerto Ricos Christmas (Navidades) unique?',options:['A one-day holiday on December 25th','A Christmas season running from late November to mid-January — the longest in the world','A summer festival','A harvest celebration'],answer:1,exp:'Puerto Rican Navidades officially runs from Thanksgiving through January 6th (Three Kings Day) and unofficially well beyond. Street parties (parrandas), plena music, and coquito (coconut rum eggnog) define it.'},
    {cat:'Music',q:'What is "plena" and how is it different from bomba?',options:['They are the same thing','Bomba is African-rooted ceremonial music; plena is narrative street music called the "sung newspaper"','Plena is classical; bomba is modern','Bomba is from Spain; plena is indigenous'],answer:1,exp:'Both are Afro-Puerto Rican. Bomba is call-and-response ceremony music rooted in African traditions. Plena is livelier street music that historically narrated current events — the original sung newspaper of the Puerto Rican people.'},
    {cat:'Music',q:'What is salsa and what is Puerto Ricos connection to it?',options:['A sauce made in Mexico','A Caribbean music genre developed largely in New York by Puerto Rican and Cuban musicians in the 1960s-70s','A traditional Spanish dance','A type of merengue'],answer:1,exp:'Salsa emerged in New York in the 1960s-70s from Puerto Rican and Cuban musicians. Puerto Rico has since become its spiritual home. The Fania All Stars era is sacred history.'},
    {cat:'Food',q:'What is "lechon" and where is the unofficial lechon capital of Puerto Rico?',options:['A seafood festival in Ponce','Slow-roasted whole pig, with Guavate in the Cayey mountains known as the lechonera capital','A type of Christmas cookie','A coconut rum drink'],answer:1,exp:'Lechon is whole-roasted pig cooked over wood for hours. The stretch of road in Guavate, Cayey — La Ruta del Lechon — is lined with lechoneras and is a weekend pilgrimage for many Puerto Ricans.'}
  ]},
  'Mexico':{flag:'🇲🇽',lang:'Spanish',questions:[
    {cat:'Food',q:'What is "chile en nogada" and when is it traditionally eaten?',options:['A spicy year-round soup','A stuffed poblano pepper with walnut cream sauce and pomegranate, eaten during the Independence season in September','A mole-based chicken dish','A Day of the Dead dessert'],answer:1,exp:'Chile en nogada is a seasonal masterpiece: a poblano pepper stuffed with picadillo covered in walnut cream sauce and garnished with pomegranate seeds and parsley — the colors of the Mexican flag. Traditionally made around Independence Day when walnuts and pomegranates are in season.'},
    {cat:'Food',q:'What makes "mole negro" different from other moles?',options:['Its made without chiles','It can contain over 30 ingredients including chocolate, multiple dried chiles, and charred tortilla — made over several days','It is a quick everyday sauce','Its only from the coast'],answer:1,exp:'Mole negro from Oaxaca is a deeply complex sauce that can take days to make, involving over 30 ingredients: multiple dried chiles, chocolate, charred tortilla and chiles, spices. One of Mexico most treasured culinary achievements.'},
    {cat:'Slang',q:'What does "mande" mean in Mexican Spanish?',options:['Go away','A polite way to say pardon or what did you say — considered respectful','An insult','A greeting'],answer:1,exp:'Mande is quintessentially Mexican — the polite response when you did not hear something or when someone calls your name. Using it shows respect, especially to elders. Other Spanish speakers find it formal, but in Mexico it is basic good manners.'},
    {cat:'Slang',q:'What does "ahorita" actually mean in Mexico?',options:['Right now, immediately','Ambiguously soon — could mean in a minute, in an hour, tomorrow, or never','Yesterday','Formally'],answer:1,exp:'Ahorita is one of Mexico most famous linguistic quirks. In theory it means right now but in practice it means anytime from immediately to indefinitely. Context and tone tell you which. Foreigners who take it literally often wait forever.'},
    {cat:'Slang',q:'What is a "chilango" and is it offensive?',options:['A type of chile pepper','A person from Mexico City — used neutrally by chilangos themselves, sometimes mockingly by others','A formal title','A type of music'],answer:1,exp:'Chilango refers to someone from Mexico City. Chilangos often use it proudly; people from other Mexican states sometimes use it with gentle mockery. Context-dependent but rarely truly offensive.'},
    {cat:'Culture',q:'What is Dia de Muertos and how is it different from Halloween?',options:['They are essentially the same celebration','A Mexican celebration of deceased loved ones on Nov 1-2 — joyful, focused on welcoming spirits back home with offerings','A mourning period','A pre-Hispanic harvest festival'],answer:1,exp:'Dia de Muertos is not Mexican Halloween. It is a joyful Indigenous tradition fused with Catholicism — families build ofrendas with photos, food, marigolds, and candles to welcome the spirits of loved ones back. Celebrating their return is the vibe, not fear.'},
    {cat:'Culture',q:'What is "jeitinho mexicano" — or rather, the Mexican equivalent concept?',options:['Rule-following','The art of finding creative workarounds — using charm, connections, and flexibility to navigate bureaucracy and social situations','Giving up','Complaining'],answer:1,exp:'Like Brazil jeitinho, Mexico has a cultural tradition of finding creative solutions to obstacles — using personal connections (palanca), flexibility, and charm. It can mean corruption at worst or resourceful problem-solving at best. Context determines which.'},
    {cat:'Culture',q:'What is the significance of mariachi?',options:['Its purely a tourist attraction','A traditional music ensemble representing Mexican identity — used for serenades, celebrations, funerals, and national pride','A modern pop genre','A religious ceremony music'],answer:1,exp:'Mariachi is UNESCO-recognized cultural heritage. A proper ensemble has violins, guitars, vihuela, guitarron, and trumpets. It is used for serenades (mananitas on birthdays), weddings, funerals, and pure celebration. Hiring a mariachi to surprise someone is an act of love.'},
    {cat:'Food',q:'What is "tlayuda" and where is it from?',options:['A type of taco from Mexico City','A large crispy tortilla topped with beans, asiento, and Oaxacan cheese — from Oaxaca','A Yucatan peninsula dish','A Jalisco breakfast'],answer:1,exp:'Tlayuda is an Oaxacan specialty: a large, partially dried tortilla spread with asiento (unrefined pork fat), black beans, Oaxacan string cheese, and various toppings. Best eaten at street stalls at night.'},
    {cat:'Music',q:'What is a "corrido" and what does it typically narrate?',options:['A childrens lullaby','A ballad-style song that narrates stories — historically about heroes and battles, now often about drug lords (narcocorridos)','A love song genre','A religious hymn'],answer:1,exp:'Corridos are Mexican storytelling ballads with a long history of narrating revolution heroes, outlaws, and love. The modern narcocorrido subgenre narrates drug trade stories and is controversial — some states have banned them, others see them as authentic social documentation.'}
  ]},
  'Colombia':{flag:'🇨🇴',lang:'Spanish',questions:[
    {cat:'Food',q:'What is "bandeja paisa" and which region is it from?',options:['A coastal seafood platter','The iconic Antioquia/Paisa region plate: red beans, white rice, ground meat, chicharron, egg, avocado, plantain, arepa, and sausage','A Bogota soup','A Pacific coast stew'],answer:1,exp:'Bandeja paisa is the emblematic dish of the Antioquia region — a massive plate with red beans, white rice, ground beef, chicharron, fried egg, avocado, sweet plantain, chorizo, and a corn arepa. A cultural statement about paisa hospitality.'},
    {cat:'Food',q:'What is "ajiaco" and which city is it most associated with?',options:['A coastal ceviche','A Bogota chicken and potato soup made with three types of potato and guasca herb','An Antioquia bean stew','A Valle del Cauca dessert'],answer:1,exp:'Ajiaco is Bogota signature soup — a thick, comforting broth with chicken and three types of potato and the distinctive guasca herb. On a cold Bogota afternoon, nothing else will do.'},
    {cat:'Slang',q:'What does "bacano" mean in Colombian slang?',options:['An insult','Cool, great, awesome — a universal Colombian positive','Confused','Expensive'],answer:1,exp:'Bacano is one of Colombia most versatile words — it means cool, awesome, great, kind. Que bacano means How cool. A bacano person is generous and good-hearted.'},
    {cat:'Slang',q:'What is "parce" or "parcero"?',options:['A type of food','Close friend, buddy — the Colombian equivalent of bro or mate','Someone from the coast','An insult'],answer:1,exp:'Parce (short for parcero/a) is the quintessential Colombian word for close friend. Warm, casual, and used constantly. Most associated with Medellin and Antioquia.'},
    {cat:'Slang',q:'What does "Quiubo?" mean?',options:['Where are you going?','A contracted greeting meaning Whats up? (from Que hubo?)','How much does it cost?','Goodbye'],answer:1,exp:'Quiubo is the most common Colombian greeting — more casual than hola, warmer than como esta? Translates roughly to Whats up? Youll hear it dozens of times a day.'},
    {cat:'Culture',q:'What is "con mucho gusto" and why is it significant in Colombia?',options:['Just a formal phrase','Colombia genuine cultural attitude — warmth and willingness to help are core Colombian values','A phrase only used in formal settings','A Bogota-specific expression'],answer:1,exp:'Con mucho gusto (with great pleasure) is the spirit behind Colombia welcoming reputation — Colombians are genuinely warm and eager to help. Saying gracias and getting con mucho gusto back is a daily Colombian exchange.'},
    {cat:'Culture',q:'What is the "Feria de las Flores" and where does it happen?',options:['A flower market in Cartagena','Medellin annual flower festival featuring silleteros carrying elaborate flower arrangements on their backs','A Bogota music festival','A Cali carnival'],answer:1,exp:'La Feria de las Flores in Medellin (August) is one of Colombia most beautiful festivals. The highlight is the Desfile de Silleteros — flower farmers carry ornate flower arrangements on their backs in a parade. UNESCO-recognized.'},
    {cat:'Music',q:'What is "cumbia" and what are its roots?',options:['A modern pop genre','Colombia most iconic rhythm — a fusion of Indigenous, African, and Spanish musical traditions from the Caribbean coast','An Andean classical music style','A recent urban genre'],answer:1,exp:'Cumbia is Colombia musical heartbeat — born on the Caribbean coast from the fusion of Indigenous flutes, African drums, and Spanish melodies. It spread across all of Latin America and is one of the foundational rhythms of the continent.'},
    {cat:'Music',q:'What is "vallenato" and why is it culturally sacred?',options:['A coastal dance music','A UNESCO-protected musical genre from the Caribbean coast — accordion, caja drum, guacharaca — that tells stories of love, loss, and daily life','A Bogota urban genre','A modern fusion style'],answer:1,exp:'Vallenato is UNESCO Intangible Cultural Heritage. Its four rhythms played on accordion, caja drum, and guacharaca tell stories of love, hardship, and life. Carlos Vives brought it global attention. For Colombians it is deeply emotional — the sound of home.'},
    {cat:'Culture',q:'What is the significance of Cartagena walled city?',options:['It was built for tourism','A UNESCO World Heritage site — the colonial fortified city built by the Spanish to protect gold shipments, now a symbol of Colombia history','A modern shopping district','A neighborhood built in the 20th century'],answer:1,exp:'Cartagena Ciudad Amurallada is a UNESCO World Heritage site — a Spanish colonial fortification built in the 16th-17th centuries to protect the port from pirates. Its colorful buildings, bougainvillea, and cobblestones make it one of South Americas most beautiful cities.'}
  ]},
  'Castilian':{flag:'🇪🇸',lang:'Spanish',questions:[
    {cat:'Food',q:'What is the difference between tortilla espanola and a Mexican tortilla?',options:['They are the same thing','Tortilla espanola is a thick potato and egg omelette — nothing to do with Mexican flatbreads','Tortilla espanola is spicier','Tortilla espanola is a dessert'],answer:1,exp:'Tortilla de patatas is one of Spain most beloved dishes — a thick round omelette made with slowly cooked potatoes and eggs. Whether to add onion is a fierce national debate. It has zero relation to Mexican tortillas.'},
    {cat:'Food',q:'What is the unwritten rule about when to eat dinner in Spain?',options:['Dinner is at 6pm like most of Europe','Dinner rarely starts before 9pm and 10-11pm is normal — eating before 8:30pm marks you as a tourist','Dinner is the smallest meal','Dinner is only eaten on weekends'],answer:1,exp:'Spain runs on a radically delayed schedule. Lunch (the main meal) is at 2-3pm. Dinner rarely starts before 9pm — 10 or 11pm is perfectly normal, even with children. Restaurants are often empty at 7pm because it is still considered the afternoon.'},
    {cat:'Slang',q:'What does tio/tia mean in everyday Castilian speech?',options:['Only uncle/aunt','Guy/girl, dude/mate — used constantly between friends the way man or mate is used in English','An older person','Someone from the countryside'],answer:1,exp:'Tio and tia literally mean uncle/aunt, but in colloquial Spanish (especially in Spain) they mean dude/guy/girl. Que pasa, tio means Whats up, man. Youll hear it in every conversation between young Spaniards.'},
    {cat:'Slang',q:'What does mola or mola mazo mean?',options:['Its moldy','Its cool / Its really cool','Its expensive','Go away'],answer:1,exp:'Mola means its cool or I like it in Spanish slang — very common in Spain, rarely used in Latin America. Mola mazo means its super cool. If someone says eso mola, they are impressed.'},
    {cat:'Culture',q:'What is el tapeo and how does it work?',options:['Eating one large dinner at a restaurant','The practice of moving from bar to bar eating small plates (tapas) with drinks — a social ritual not just a meal','A formal dining tradition','A breakfast custom'],answer:1,exp:'Tapeo is the art of bar-hopping while eating tapas — in many parts of Spain tapas still come free with drinks. It is not about the food alone; it is a deeply social ritual. The route from bar to bar is taken seriously. In Granada, tapas are still often free.'},
    {cat:'Culture',q:'What is la siesta — myth or reality in modern Spain?',options:['Everyone in Spain takes a 2-hour nap every day','Historically real but increasingly rare in cities — more a long lunch break than actual sleep, mainly survives in smaller towns','Completely invented by tourists','Only practiced by old people'],answer:1,exp:'The siesta as actual nap is largely a myth in modern urban Spain — but the long midday break when many businesses close is still real, especially outside major cities. In August, the whole country slows down. The real siesta is increasingly a long lunch with wine.'},
    {cat:'Culture',q:'What is la movida madrilena and why does it matter?',options:['A traffic problem in Madrid','The explosive cultural movement in Madrid after Francos death (late 70s-80s) — music, film, art, and total social liberation','A type of dance','A food festival'],answer:1,exp:'La movida madrilena was Spain cultural explosion after Francos dictatorship — a burst of freedom in music, film (Almodovar), art, and nightlife. It defined a generation and explains why Madrid has such a fierce creative identity. Pedro Almodovar is its most famous product.'},
    {cat:'Music',q:'What is flamenco and where is it truly from?',options:['A national Spanish dance practiced everywhere equally','An Andalusian art form with deep Romani, Moorish, and Sephardic roots — cante (song), baile (dance), and guitarra (guitar)','A Latin American import','A 20th-century creation for tourism'],answer:1,exp:'Flamenco is UNESCO Intangible Cultural Heritage from Andalusia — specifically rooted in the Romani (gitano) communities of Jerez, Seville, and Cadiz. Real flamenco, especially cante jondo (deep song), is raw and emotionally overwhelming — not the tourist show version.'},
    {cat:'Culture',q:'What is jamon iberico de bellota and why is it so prized?',options:['A cheap everyday ham','Dry-cured ham from free-range Iberian pigs fed exclusively on acorns — among the most prized cured meats in the world','A type of cooked ham','A regional Catalonian product'],answer:1,exp:'Jamon iberico de bellota comes from Iberian pigs that roam oak forests eating only acorns for months before slaughter. The result is extraordinary — marbled, nutty, complex. A single leg can cost 500 euros or more. A serious cultural and gastronomic institution in Spain.'},
    {cat:'Culture',q:'Why does Spain having 17 autonomous communities matter culturally?',options:['They are like US states with little real difference','Spain has strong regional identities — Catalonia, Basque Country, Galicia, Andalusia each have distinct languages, cultures, and political tensions','They are purely administrative divisions','Only Madrid and Barcelona matter'],answer:1,exp:'Spain regional identity is fierce and sometimes politically explosive. Catalonia and the Basque Country have separatist movements. Galicia has its own language. Andalusia has distinct culture and accent. Spain is almost a loose federation of very different cultures.'}
  ]},
  'Italian':{flag:'🇮🇹',lang:'Italian',questions:[
    {cat:'Food',q:'What is the difference between espresso and caffe americano in Italy?',options:['They are the same drink','Espresso is 25-30ml of concentrated coffee; Americano is espresso diluted with hot water — Italians rarely drink Americano','Americano is stronger','Espresso is only for mornings'],answer:1,exp:'In Italy, un caffe means espresso — a 25-30ml concentrated shot drunk standing at the bar in seconds. Americano is seen as a foreign concession. Italians are deeply serious about coffee: never a cappuccino after 11am.'},
    {cat:'Food',q:'Why would an Italian be offended if you order spaghetti bolognese in Bologna?',options:['It does not exist','Bolognas meat sauce (ragu) is traditionally served with tagliatelle, not spaghetti — spaghetti bolognese is considered an American invention','Bolognese is too expensive','It is not on menus there'],answer:1,exp:'The Bolognese Chamber of Commerce literally registered the official recipe of ragu alla bolognese in 1982 — it calls for tagliatelle, not spaghetti. Ordering spaghetti bolognese in Bologna earns polite horror from locals who consider spaghetti the wrong pasta for ragus richness.'},
    {cat:'Slang',q:'What does dai mean in Italian and how is it used?',options:['Only give me','A versatile expression meaning come on, really?, no way, let us go — tone determines meaning','An insult','Goodbye'],answer:1,exp:'Dai (from dare, to give) is one of Italians most multipurpose expressions. Tone does everything: Dai (rising) = come on / really? Dai, andiamo = come on, let us go. Ma dai! = No way! It is in every Italian conversation.'},
    {cat:'Culture',q:'What is la passeggiata and when does it happen?',options:['A morning jog','The early evening ritual of strolling through town — seeing and being seen, socializing — especially in smaller Italian cities','A type of Sunday lunch','A market tradition'],answer:1,exp:'La passeggiata is the Italian evening stroll — typically between 5-8pm, when people dress well and walk through the main street or piazza to see friends and socialize. It is not exercise; it is social theater.'},
    {cat:'Culture',q:'What is campanilismo in Italian culture?',options:['A type of church architecture','Deep attachment to ones own town or village — loyalty to the local bell tower (campanile) over any broader national identity','A music festival','A regional food tradition'],answer:1,exp:'Campanilismo comes from campanile (bell tower) — the fierce local pride that makes a Neapolitan see themselves as Neapolitan first, Italian second. This explains why Italian food, dialect, and culture varies so dramatically from town to town.'},
    {cat:'Culture',q:'What is the cultural significance of Sunday lunch in Italy?',options:['Just a meal','A multi-hour sacred family ritual — the weeks most important gathering, with multiple courses, lasting 3+ hours','Only practiced in the south','A dying tradition'],answer:1,exp:'Sunday lunch is one of Italian cultures most sacred rituals — an extended multi-course family affair lasting 3-4 hours. The table is set properly, grandmothers cook, multiple generations gather. Skipping it without good reason is a social transgression.'},
    {cat:'Culture',q:'What does fare la scarpetta mean?',options:['Buying expensive shoes','Using bread to wipe up the remaining sauce from your plate — a sign of appreciation for the cook','A childrens game','A formal toast'],answer:1,exp:'Fare la scarpetta (making a little shoe) means using bread to mop up the last sauce on your plate. It is considered a genuine compliment to the cook — you loved it so much you do not want to waste a drop.'},
    {cat:'Music',q:'What is bel canto and why is Italy its homeland?',options:['A modern pop style','The classical singing technique emphasizing beautiful tone, ornamentation, and breath control — Italy operatic tradition','A folk music tradition','A Renaissance dance music'],answer:1,exp:'Bel canto (beautiful singing) is the Italian operatic tradition — emphasizing smooth legato, breath control, and ornamentation. Rossini, Donizetti, and Bellini defined it. Opera is not elitist in Italy — it is genuinely popular.'},
    {cat:'Food',q:'What does bella mean when used between strangers in Italy?',options:['Only a compliment about appearance','A casual, warm address — like hey or mate — not about looks','Exclusive to romantic relationships','Only used between women'],answer:1,exp:'Bella and bello are used constantly as casual greetings between friends and strangers alike — like hey or mate. Ciao bella to a friend is warm and normal. It is not a romantic or physical comment in casual use.'},
    {cat:'Culture',q:'What is the cultural rule about cappuccino in Italy?',options:['Cappuccino is drunk at any time','Cappuccino is a morning drink — ordering it after 11am or after a meal marks you as a tourist to any Italian','Cappuccino is only for weekends','Cappuccino is only drunk in Rome'],answer:1,exp:'The cappuccino-after-11am rule is real and strongly felt. Milk-based coffee drinks are considered breakfast in Italy — the milk makes it too heavy after a meal. Ordering a cappuccino after lunch is the fastest way to identify yourself as a tourist.'}
  ]},
  'Brazilian':{flag:'🇧🇷',lang:'Portuguese',questions:[
    {cat:'Food',q:'What is feijoada and when is it traditionally eaten?',options:['An everyday lunch dish','A slow-cooked black bean and pork stew — the national dish, traditionally eaten on Wednesdays and Saturdays','A coastal seafood dish','A light breakfast'],answer:1,exp:'Feijoada is Brazil national dish — a rich, slow-cooked black bean stew with various pork cuts. Traditionally eaten on Wednesdays and Saturdays, served with white rice, couve (collard greens), farofa (toasted cassava flour), and orange slices.'},
    {cat:'Food',q:'What is pao de queijo and where does it come from?',options:['A wheat bread roll from Sao Paulo','Small, chewy cheese bread made from tapioca flour — originally from Minas Gerais, now a national obsession','A Portuguese import','A coastal specialty'],answer:1,exp:'Pao de queijo (cheese bread) is one of Brazil most beloved foods — small, puffy rolls made from tapioca flour and queijo minas cheese. Chewy outside, airy inside, slightly tangy. From Minas Gerais but eaten everywhere at any time of day.'},
    {cat:'Slang',q:'What does saudade mean and why is it untranslatable?',options:['Happiness','A profound longing for someone or something loved and lost — a melancholic, bittersweet emotion with no direct English equivalent','Anger','Surprise'],answer:1,exp:'Saudade is a deep emotional state of nostalgic longing for something absent that you love, with the awareness it may never return. The soul of fado music in Portugal and deeply embedded in Brazilian emotional culture too.'},
    {cat:'Slang',q:'What is jeitinho brasileiro?',options:['A type of dance','The Brazilian way of finding creative workarounds to rules and obstacles — the art of navigating bureaucracy and social situations with flexibility and charm','A cooking technique','A musical style'],answer:1,exp:'Jeitinho brasileiro (the little Brazilian way) refers to the cultural tendency to find creative, flexible solutions to problems — bending rules, using personal connections. Celebrated as resourcefulness, sometimes criticized as a root of corruption. Either way, a recognized cultural trait.'},
    {cat:'Culture',q:'What is Carnaval in Brazil and how does it differ by city?',options:['One standardized national celebration','A 4-day celebration with dramatically different styles: Rio has samba school parades; Salvador has axe music blocos; Sao Paulo has its own parade','Only celebrated in Rio de Janeiro','A modern tourist creation'],answer:1,exp:'Carnaval is Brazil greatest cultural festival — but it is not one thing. Rio has the iconic Sambadrome parades. Salvador has street blocos with axe and pagode music. Recife has Frevo and Maracatu. Each city is a different experience.'},
    {cat:'Culture',q:'What is jogo bonito and what does it mean for Brazilian culture?',options:['A childrens board game','The beautiful game — Brazil philosophy of football as artistic expression, not just winning','A type of capoeira','A carnival dance'],answer:1,exp:'Jogo bonito (the beautiful game) is how Brazil conceptualizes football — not just winning but playing with creativity, skill, and beauty. Pele popularized the term. Brazil has won 5 World Cups. Football is not just sport in Brazil; it is culture, identity, and religion.'},
    {cat:'Food',q:'What is coxinha and what does the name mean?',options:['A sweet dessert','A fried dough croquette shaped like a chicken thigh, filled with shredded chicken and cream cheese — the name means little thigh','A type of cheese','A savory breakfast bread'],answer:1,exp:'Coxinha (little thigh) is shaped like a teardrop — a dough casing filled with shredded chicken and catupiry cheese, then breaded and fried. Brazil most iconic savory snack, found at padarias everywhere.'},
    {cat:'Music',q:'What is bossa nova and what did it revolutionize?',options:['A traditional samba variant','A sophisticated fusion of samba rhythms with jazz harmonies — invented in Rio in the late 1950s, changed popular music globally','A modern pop style','A Northeastern folk tradition'],answer:1,exp:'Bossa nova emerged in Rio in the late 1950s — Joao Gilberto intimate guitar style, Tom Jobim jazz harmonies, Vinicius de Moraess poetry. The Girl from Ipanema became one of the most recorded songs in history. Changed popular music globally.'},
    {cat:'Culture',q:'What is forro and where is it from?',options:['A type of housing','A popular dance music genre from Northeast Brazil — accordion-driven, intimate couple dancing, now mainstream nationally','A Sao Paulo nightlife genre','A carnival music style'],answer:1,exp:'Forro is from Brazil Northeast — a rhythmic, infectious music driven by the triangle, zabumba drum, and accordion. The dance is close-couples style, hip-driven, and deeply social. What started as Northeastern folk music is now danced across all of Brazil.'},
    {cat:'Music',q:'What is axe music and where is it from?',options:['A type of electronic music','An Afro-Brazilian popular music genre from Salvador, Bahia — carnival-oriented, energetic, drawing from African rhythms','A Rio samba variant','A Northeastern ballad style'],answer:1,exp:'Axe music is the sound of Salvadors Carnival — energetic, Afro-Brazilian popular music from Bahia drawing on candomble rhythms, reggae, and samba. Artists like Ivete Sangalo, Claudinho, and Daniela Mercury are its stars. It defines Salvadors Carnival energy.'}
  ]},
  'European Portuguese':{flag:'🇵🇹',lang:'Portuguese',questions:[
    {cat:'Food',q:'What is a bica and how do the Portuguese drink it?',options:['A large coffee drink','A short, intense espresso — drunk quickly standing at the counter in a pastelaria, usually with a glass of water','A type of wine','A breakfast pastry'],answer:1,exp:'A bica is Lisbon word for espresso — short, strong, drunk standing at the counter of a pastelaria. (Porto calls it cimbalino.) It comes with a glass of water and is drunk quickly. The balcao (counter) is where real Lisboetas refuel.'},
    {cat:'Food',q:'What is bacalhau and how significant is it to Portuguese cuisine?',options:['A type of fresh fish dish','Salt cod — arguably Portugal national ingredient, with over 365 traditional recipes (one for every day of the year)','A dessert made with almonds','A type of smoked sausage'],answer:1,exp:'Bacalhau (salt cod) is central to Portuguese identity — there are supposedly 365 ways to cook it (fiel amigo: faithful friend). Bacalhau a Bras, a Gomes de Sa, and com natas are classics. The paradox: Portugal has the Atlantic but its national dish is dried imported cod.'},
    {cat:'Food',q:'What is pastel de nata and where was it invented?',options:['A pastry from Brazil','A custard tart — invented by monks at the Jeronimos Monastery in Belem, Lisbon, in the 18th century','A Moorish dessert','A modern bakery creation'],answer:1,exp:'Pastel de nata is Portugal most iconic pastry — a crispy puff pastry shell filled with creamy, slightly caramelized egg custard. Created by monks at Jeronimos Monastery in the 1830s. The original bakery (Pasteis de Belem) still makes them with the secret recipe. Eaten warm with cinnamon and icing sugar.'},
    {cat:'Slang',q:'What does fixe mean in European Portuguese?',options:['Fixed or repaired','Cool, great, fine — one of the most common informal positives in Portugal','Expensive','Boring'],answer:1,exp:'Fixe is one of Portugal most common informal words — it means cool, great, or fine. Esta fixe means Its good. Que fixe! means How cool! It notably differs from Brazilian Portuguese slang and marks you as speaking European Portuguese immediately.'},
    {cat:'Culture',q:'What is fado and what emotions does it express?',options:['An upbeat dance music','Portugal UNESCO-protected national music — melancholic, expressing saudade, fate, and longing; most associated with Lisbon and Coimbra','A modern pop genre','A religious hymn tradition'],answer:1,exp:'Fado is Portugal UNESCO Intangible Cultural Heritage — a deeply emotional music of longing, fate, and saudade. Lisbon fado (singers like Amalia Rodrigues or Mariza) has raw urban emotion. Coimbra fado is more poetic, traditionally sung by male university students.'},
    {cat:'Culture',q:'What is Os Descobrimentos and why does it define Portugal self-image?',options:['A modern political movement','The Age of Discoveries (15th-16th centuries) — when Portugal mapped the world, establishing sea routes to India, Africa, and Brazil','A type of folk festival','A cuisine tradition'],answer:1,exp:'The Age of Discoveries is central to how Portugal sees itself — a small nation that mapped the world. Vasco da Gama, Bartolomeu Dias, and Pedro Alvares Cabral are national heroes. Portugal language being spoken by 250+ million people globally is its lasting legacy.'},
    {cat:'Culture',q:'What is azulejo and what role does it play in Portuguese culture?',options:['A type of music','Decorative ceramic tiles — Portugal most distinctive visual art form, covering churches, train stations, facades, and palaces','A type of food','A traditional costume'],answer:1,exp:'Azulejos are Portugal soul in tile form — hand-painted ceramic tiles covering everything from the humblest church to Lisbon Sao Bento railway station. The blue-and-white variety is iconic. Portuguese azulejo tradition is UNESCO-listed. They are not decoration — they are storytelling.'},
    {cat:'Culture',q:'What distinguishes Coimbra fado from Lisbon fado?',options:['They are identical','Coimbra fado is traditionally performed by male university students, with a more academic and poetic character; Lisbon fado is more raw and urban','Coimbra uses different instruments','Lisbon fado is older'],answer:1,exp:'Coimbra fado emerged from the university city academic tradition — traditionally sung by male students wearing the black academic cape. More structured and poetic compared to Lisbon raw emotional power. The two styles share the name but have distinct souls.'},
    {cat:'Culture',q:'What is the cultural significance of the sardinha in Lisbon?',options:['An everyday cheap fish','The sardine is a symbol of Lisbon — Junes Festas de Lisboa feature sardines grilled everywhere, and the sardine has become an ironic modern art symbol of the city','A formal dish','A tourist gimmick'],answer:1,exp:'Sardines are central to Lisbon Festas de Lisboa (June) — the city fills with the smell of grilled sardines. The sardinha has also become Lisbon slightly ironic symbol: artisanal sardine tins with beautiful designs are sold as souvenirs. What started as poor working-class food is now proudly claimed by the whole city.'},
    {cat:'Slang',q:'What does saudade mean in its Portuguese context?',options:['Just nostalgia','A deep, bittersweet longing for something or someone absent and loved — embedded in Portuguese national identity and fado music','A word for homesickness only','Happiness'],answer:1,exp:'Saudade is Portugal most famous untranslatable concept — a profound emotional state of longing for something loved and gone, with the awareness it may never return. It is the emotional core of fado music. The Portuguese consider it specifically Portuguese.'}
  ]},
  'Parisian':{flag:'🇫🇷',lang:'French',questions:[
    {cat:'Food',q:'What is a jambon-beurre and why is it culturally significant?',options:['A gourmet restaurant dish','A simple baguette sandwich with ham and butter — Paris most-consumed sandwich, a symbol of French simplicity done perfectly','A type of dessert','A breakfast pastry'],answer:1,exp:'The jambon-beurre (ham-butter) baguette is Paris most popular sandwich — millions sold daily. A testament to French philosophy: great ingredients need no embellishment. Sold at every boulangerie and eaten standing up or walking.'},
    {cat:'Food',q:'What is the French apero and how does it work?',options:['A formal dinner course','Pre-dinner drinks and nibbles — a social ritual that often lasts longer than planned and can become the entire evening','A type of restaurant','A morning coffee tradition'],answer:1,exp:'Lapero (aperitif) is France most social institution — pre-dinner drinks with nibbles shared between friends. Typically starts at 7-8pm. In reality it often turns into the whole evening. Viens a lapero is one of the most common French social invitations.'},
    {cat:'Slang',q:'What does cest nul mean?',options:['Its zero','Its rubbish / its terrible — a very common French informal negative','It is nothing important','Its new'],answer:1,exp:'Cest nul literally means its null but colloquially means its rubbish, terrible, worthless. Ce film est nul = This film is terrible. Tes nul = Youre useless (can be affectionate or critical depending on tone).'},
    {cat:'Slang',q:'What does sympa mean?',options:['Sympathetic in the English sense','Nice, pleasant, cool — shortened from sympathique, used constantly for people and places','Formal','Complicated'],answer:1,exp:'Sympa (short for sympathique) means nice, pleasant, or friendly. Il est sympa = Hes nice. Cetait sympa = That was nice. Note: it does not mean sympathetic in the English sense of feeling sorry for someone.'},
    {cat:'Slang',q:'What is la bise and when do Parisians do it?',options:['A type of cheese','The cheek-kiss greeting — with rules that vary by region; Paris is typically 2 kisses','Only a romantic gesture','A formal greeting reserved for elders'],answer:1,exp:'La bise is the French cheek-kiss greeting — not a real kiss but cheek-to-cheek contact. Paris is typically 2 bises. Across France the number varies (3 or 4 in some regions), creating awkward moments when counts do not match. Done between friends, family, and colleagues you know well.'},
    {cat:'Culture',q:'What is the French concept of laicite and why does it matter?',options:['A religious holiday','Strict separation of religion from public life — a French republican value that shapes debates on headscarves, religious symbols, and public space','Just another word for secularism','A recent concept'],answer:1,exp:'Laicite is a core French republican value — the strict separation of religion from public institutions. This explains why France bans religious symbols in public schools, why headscarves are debated so intensely, and why French culture is more confrontational about religion in public life than other Western countries.'},
    {cat:'Culture',q:'What is la rentree and why do French people talk about it so much?',options:['A return flight','The September back-to-school cultural reset — the most important moment in France social calendar, when the whole country restarts after summer','Just the start of school','A government calendar event'],answer:1,exp:'La rentree is France collective cultural reset in September — when Parisians return from August holidays, schools reopen, political life restarts, publishers release new books, TV shows resume. August in Paris is famously empty; September snaps it back to life.'},
    {cat:'Music',q:'What is chanson francaise and who are its icons?',options:['French pop music','A tradition of literate, melodic French song with poetic lyrics — Edith Piaf, Jacques Brel, Georges Brassens, and Serge Gainsbourg are its icons','A classical tradition','A regional folk style'],answer:1,exp:'Chanson francaise is France great popular music tradition — songs where lyrics matter as much as melody. Edith Piaf (La Vie en Rose) is its global symbol. Jacques Brel was its poet-provocateur. Serge Gainsbourg was its enfant terrible. The tradition values wit, emotion, and words — very French.'},
    {cat:'Culture',q:'What does it mean when Parisians complain about being Parisian?',options:['They want to leave','Parisians frequently complain about their city (noise, rudeness, cost, metro) while being fiercely proud of it — Paris is loved through complaint','They are generally unhappy people','Its false modesty'],answer:1,exp:'Parisians have a complex relationship with their city: they complain about it constantly while being deeply proud and slightly superior about it. Being Parisian is an identity — slightly exhausting, deeply felt, and never fully abandoned even after leaving.'},
    {cat:'Food',q:'What does une bonne table mean?',options:['A physical table of good quality','A restaurant or home where food is taken seriously — where the meal is an event, not just sustenance','An expensive restaurant only','A tourist restaurant'],answer:1,exp:'Une bonne table (a good table) means a place where eating is taken seriously — good ingredients, proper preparation, attention to the meal as an experience. French culture treats eating as a social and cultural ritual. A meal at une bonne table is expected to take at least 2 hours.'}
  ]},
  'Southern French':{flag:'🇫🇷',lang:'French',questions:[
    {cat:'Food',q:'What is bouillabaisse and where is it from?',options:['A simple fish soup eaten everywhere in France','A complex Marseille fish stew with multiple fish, rouille sauce, croutons, and strict traditional rules about what fish must be included','A Provencal vegetable dish','A Lyon specialty'],answer:1,exp:'Bouillabaisse is Marseille great dish — originally poor fishermen food using unsellable bony fish, now a prestigious feast. The real version requires specific Mediterranean fish, served in two courses: broth first with rouille and croutons, then the fish. Marseillais are fierce about authenticity.'},
    {cat:'Food',q:'What is pastis and when do people drink it in the South?',options:['A type of wine','An anise-flavored spirit diluted with water (turning cloudy) — the quintessential aperitif of Marseille and Provence, especially during petanque','A sweet dessert liqueur','A cocktail from Paris'],answer:1,exp:'Pastis (Ricard, Pastis 51) is the Souths answer to every social occasion. Mixed with water 5:1, it turns milky yellow. Drunk as an aperitif, especially while playing petanque. Drinking pastis in Paris is unusual; in Provence it is default.'},
    {cat:'Slang',q:'What does peuchere mean in Marseille slang?',options:['An insult','An expression of pity, compassion, or sympathy — poor thing or bless them','A greeting','Expensive'],answer:1,exp:'Peuchere is a Marseillais expression of sympathy and pity — like poor thing or bless. It is warm and compassionate, deeply Marseillais, and rarely heard in Paris. It reflects the southern French tendency toward more open, expressive emotion.'},
    {cat:'Culture',q:'What is le mistral and how does it affect life in Provence?',options:['A regional wine','A powerful cold, dry north wind that blows through the Rhone Valley into Provence — affecting mood, fire risk, and daily life','A Provencal dance','A type of boat'],answer:1,exp:'The mistral is a fierce, cold, dry wind that funnels down the Rhone Valley and across Provence. It can blow for 3, 6, or 9 days (traditionally counted in threes). It dries laundry instantly, raises fire risk in summer, and is blamed for everything from bad moods to headaches. Provencaux plan around it.'},
    {cat:'Culture',q:'What is petanque and how seriously is it taken in the South?',options:['A childrens game','A boules game played on gravel — deeply social, played by all ages, central to Southern French village life','A competitive Olympic sport only','A game played only in summer'],answer:1,exp:'Petanque is the game of throwing metal boules toward a small target ball. In the South it is a way of life — played in village squares by everyone from retirees to teenagers. The social rituals around it (arguing about measurements, trash-talking) are complex. Almost always accompanied by pastis.'},
    {cat:'Culture',q:'What are les calanques and why are they significant?',options:['A type of pastry','Dramatic limestone inlets along the coast between Marseille and Cassis — UNESCO-protected natural sites central to Marseillais identity','A village festival','A wine region'],answer:1,exp:'Les calanques are stunning white limestone fjords along the Mediterranean coast west of Marseille — dramatic cliffs dropping into turquoise water. They are a National Park and UNESCO-recognized. For Marseillais they are simply home. They define the relationship between Marseille and its landscape.'},
    {cat:'Culture',q:'What is the cultural difference between Marseille and Paris in French eyes?',options:['There is no significant difference','Marseille is seen as rougher, warmer, more diverse, more chaotic, and more authentically Mediterranean than Paris — and Marseillais consider this a compliment','Marseille is considered more sophisticated','They are considered identical'],answer:1,exp:'The Paris-Marseille divide is a French cultural axis. Paris is seen as cold, organized, elitist. Marseille is warm, chaotic, diverse, Mediterranean. Marseillais actively resist the Parisian norm. The city is also France most ethnically diverse.'},
    {cat:'Food',q:'What is tapenade and where does it come from?',options:['A type of bread from Toulouse','A Provencal olive paste with capers, anchovies, and olive oil — from Provence, the original party dip','A cheese spread from Lyon','A Basque sauce'],answer:1,exp:'Tapenade comes from the Provencal word for capers (tapenas) — it is a paste of olives, capers, anchovies, and olive oil. Deeply Provencal, eaten spread on toast as an appetizer. The South of France runs on olives, and tapenade is their most portable form.'},
    {cat:'Music',q:'What is Occitan and what is its cultural status in Southern France?',options:['A dead language with no modern relevance','The historical language of southern France (Languedoc) — experiencing a revival through music and cultural movements','A dialect of Spanish','An Italian dialect'],answer:1,exp:'Occitan was the dominant language of medieval southern France — troubadour poetry was written in it. Suppressed by French state centralization but never fully dead. Today it is experiencing revival through music (Massilia Sound System raps in Occitan and French) and cultural pride. A symbol of southern identity resistance.'},
    {cat:'Culture',q:'Why is Marseille considered France most authentically Mediterranean city?',options:['It is the oldest city in France but has no special character','As France oldest city (founded by Greeks in 600 BC), Marseille has centuries of Mediterranean trade, diverse immigration from North Africa and Southern Europe, and a culture closer to Naples or Algiers than Paris','It is a recent industrial city','Only because of its location'],answer:1,exp:'Marseille was founded by Greek colonists in 600 BC — making it France oldest city. Its port culture brought centuries of North African, Italian, Armenian, and Comorian immigration. This diversity shapes the food, language, and culture. Marseillais often feel more Mediterranean than French. The city accents, cuisine, and social culture reflect this layered history.'}
  ]},
  'Neapolitan':{flag:'🇮🇹',lang:'Italian',questions:[
    {cat:'Food',q:'What makes Neapolitan pizza fundamentally different from other pizzas?',options:['Only the toppings differ','The dough — made with specific flour, long fermentation (24-72 hours), cooked at 485C+ in a wood-fired oven for 60-90 seconds, with a soft charred crust (cornicione)','The sauce only','The cheese used'],answer:1,exp:'Vera pizza napoletana (VPN) is protected by law and tradition. The dough uses specific flour, ferments 24-72+ hours, and cooks in a wood-fired oven at 485C for 90 seconds maximum. The result has a soft, blistered crust (cornicione) — nothing like the stiff American or Roman versions.'},
    {cat:'Food',q:'What is caffe sospeso and what does it represent?',options:['A suspended coffee order for late customers','The Neapolitan tradition of paying for an extra coffee for a stranger who cannot afford one — an anonymous act of community generosity','A type of cold coffee drink','A coffee served at the end of a meal'],answer:1,exp:'Caffe sospeso (suspended coffee) is a beautiful Neapolitan institution — you pay for two coffees but only drink one, leaving the second suspended for whoever comes in and cannot afford it. An act of anonymous community solidarity that embodies Neapolitan cultures warmth toward strangers.'},
    {cat:'Slang',q:'What is the Neapolitan word for friend or guy used constantly in speech?',options:['Amico','Uaglio (pronounced wah-lyo) — the Neapolitan term for boy, guy, friend used as casual address','Compagno','Fratello'],answer:1,exp:'Uaglio (from guaglione, meaning boy or guy) is one of the most characteristic Neapolitan words — used as casual address between friends, like mate or bro. You will hear it constantly in Naples and in Neapolitan music and film.'},
    {cat:'Culture',q:'What is the significance of San Gennaro to Naples?',options:['The patron saint of a small neighborhood','The patron saint of Naples — his blood, kept in a vial in the Duomo, is expected to liquefy three times a year; if it does not, Neapolitans consider it an omen of disaster','A historical figure with no current relevance','A character from Neapolitan folklore only'],answer:1,exp:'San Gennaro is Naples patron saint, and his blood liquefaction is one of Catholicisms most famous phenomena. Three times a year, a vial of his dried blood is expected to liquefy. The city watches anxiously — if it liquefies, relief and celebration. If it delays, fear of disaster follows. Neapolitans take it seriously.'},
    {cat:'Culture',q:'What is the Neapolitan presepe and how elaborate does it get?',options:['A simple church nativity scene','A nativity scene tradition taken to extraordinary artistic extremes — with detailed craftwork, multiple scenes, and figures including contemporary people','A childrens toy','A museum display only'],answer:1,exp:'The presepe (nativity scene) is a Neapolitan obsession. Via San Gregorio Armeno is lined year-round with craftsmen making presepe figures. Neapolitan presepis are elaborate masterpieces with dozens of scenes — including contemporary celebrities and politicians alongside traditional characters. An art form taken to beautiful excess.'},
    {cat:'Culture',q:'What is Spaccanapoli?',options:['A modern road division','The ancient straight road (decumanus) that cuts through Naples from west to east — the spine of the historic center','A canal through the city','A wall dividing neighborhoods'],answer:1,exp:'Spaccanapoli (splits Naples) is the long, straight ancient Greek-Roman road that cuts through the historic center. It is one of Europes most densely layered urban streets — churches, palaces, pizzerias, street altars. The historic center around it is a UNESCO World Heritage site.'},
    {cat:'Food',q:'What is ragu napoletano and how does it differ from Bolognese?',options:['They are essentially the same sauce','A slow-cooked Sunday meat sauce that simmers for hours with whole cuts of meat that become the second course — completely different from Bologneses minced meat','A spicier version of Bolognese','A lighter, modern sauce'],answer:1,exp:'Ragu napoletano simmers for hours (sometimes 5-8) with whole pieces of meat — beef rolls (braciole), pork ribs, sausage. The meat becomes a second course after the pasta. Nothing like Bolognas loose, quick-cooked minced meat sauce.'},
    {cat:'Music',q:'What is canzone napoletana and what are its most famous examples?',options:['A modern pop style','The classical Neapolitan song tradition — romantic, theatrical, melodically rich — with songs like O Sole Mio and Funiculi Funicula known globally','A folk tradition from the Naples countryside','A type of opera'],answer:1,exp:'Canzone napoletana is one of Italy greatest musical traditions — romantic, operatic in spirit, with extraordinary melodies. O Sole Mio (1898) is its global ambassador. Enrico Caruso (himself Neapolitan) brought these songs to the world. They remain living music in Naples, not nostalgia.'},
    {cat:'Music',q:'What is neomelodica and what does it reveal about Neapolitan culture?',options:['Classical Neapolitan music','A modern, often melodramatic popular music genre popular in working-class Naples — love songs, sometimes with Camorra references, considered kitsch by outsiders but beloved locally','A childrens music style','An imported American genre'],answer:1,exp:'Neomelodica is a grassroots Neapolitan pop genre — intensely emotional, melodramatic love songs popular in working-class neighborhoods, often performed at outdoor festivals. Frequently dismissed as kitsch by middle-class Italians but reflects authentic popular culture.'},
    {cat:'Culture',q:'What does o sistema (the system) refer to in Neapolitan culture?',options:['A traffic system','Informal term for the Camorras shadow economy and power structure — a fact of life that Neapolitans navigate daily','A government bureaucracy','A neighborhood watch'],answer:1,exp:'O sistema (the system) refers to the Camorras shadow economy and influence. Roberto Saviano Gomorrah exposed it globally. It is not something most Neapolitans support, but it is a reality they navigate — in construction, waste, certain neighborhoods. Understanding it is part of understanding the city complexity honestly.'}
  ]},
  'Haitian Creole':{flag:'🇭🇹',lang:'Creole',questions:[
    {cat:'Food',q:'What is griot and when is it typically eaten?',options:['A West African storyteller','Fried pork shoulder — marinated, boiled, then fried until crispy — Haiti national dish, eaten at celebrations and family gatherings','A type of fried fish','A bean soup'],answer:1,exp:'Griot (fried pork) is Haiti most beloved dish — pork shoulder marinated in citrus and spices, slow-cooked, then deep-fried until golden and crispy outside, tender inside. Served with pikliz (spicy pickled cabbage), bannann peze (fried plantains), and diri kole (rice and beans). Essential at every celebration.'},
    {cat:'Food',q:'What is pikliz and why is it on every Haitian table?',options:['A dessert pickle','A fiery condiment of pickled cabbage, carrots, and Scotch bonnet peppers in vinegar — Haiti essential hot condiment served alongside almost every dish','A type of pepper sauce from the coast','A sweet relish'],answer:1,exp:'Pikliz is Haiti essential condiment — shredded cabbage, carrots, and sometimes bell peppers pickled in white vinegar with Scotch bonnet or habanero peppers. Fiery, crunchy, tangy, and served alongside griot, akra, and most Haitian dishes. No Haitian table is complete without it.'},
    {cat:'Food',q:'What is diri kole ak pwa and how central is it to Haitian cuisine?',options:['An occasional festival dish','Rice and red kidney beans cooked together — Haiti daily staple, eaten by most Haitians almost every day','A soup dish','A breakfast porridge'],answer:1,exp:'Diri kole ak pwa (rice and beans cooked together) is Haiti daily staple — the foundation of the cuisine. The beans are cooked into the rice, giving it flavor and color. Eaten at lunch (the main meal), often with meat or vegetables. Simple, deeply satisfying, and irreplaceable.'},
    {cat:'Culture',q:'Why is Haiti 1804 independence uniquely significant in world history?',options:['It was one of many Caribbean independence movements','Haiti was the first Black republic in the world and the first country to win independence through a slave revolt — a world-historical event','It was the first French colony to gain independence','It was won peacefully through negotiation'],answer:1,exp:'Haiti 1804 independence was revolutionary — the only successful slave revolt in history that established a nation. Enslaved Africans defeated Napoleons army. This terrified slaveholding powers who isolated and punished Haiti economically for over a century. Haiti paid France reparations for its own freedom until 1947.'},
    {cat:'Culture',q:'What is Vodou and how is it misrepresented in Western popular culture?',options:['An evil practice identical to horror movie depictions','A complex Afro-Caribbean religion fusing West African Vodun with Catholicism — with sophisticated theology, healing practices, and community ritual','A political movement','A form of magic with no spiritual dimension'],answer:1,exp:'Vodou is a complex syncretic religion brought by enslaved Africans and fused with Catholicism — with sophisticated theology (Lwa/spirits, ancestral communication), healing practices, music, and community ritual. The horror movie voodoo is a racist distortion. Vodou played a role in the Haitian Revolution.'},
    {cat:'Slang',q:'What does pa gen pwoblem mean in everyday Haitian conversation?',options:['There is a big problem','No problem — one of the most common expressions, reflecting Haitian resilience and social warmth','I do not understand','Go away'],answer:1,exp:'Pa gen pwoblem (no problem) is heard constantly in Haiti — a reflection of the country cultural resilience and warmth. Despite immense challenges, Haitian social culture emphasizes warmth, grace, and not burdening others with worry.'},
    {cat:'Slang',q:'What does se konsa mean?',options:['Its expensive','Thats how it is — a philosophical acceptance of circumstances, widely used','Lets go','Impossible'],answer:1,exp:'Se konsa (that is how it is / such is life) reflects a Haitian philosophical attitude toward circumstance — acknowledging difficulty without being defeated by it. It is used to accept what cannot be changed while maintaining dignity.'},
    {cat:'Culture',q:'What is Kanaval (Carnival) in Haiti and how does it compare to others?',options:['A small local celebration','Haiti massive pre-Lent celebration with rara bands, elaborate costumes, political commentary in music, and weeks of festivities','An imported celebration identical to Trinidads','A religious ceremony only'],answer:1,exp:'Haitian Kanaval is one of the Caribbeans most vibrant celebrations — weeks of rara band music (bamboo trumpets, drums, call-and-response), political satire in songs, elaborate costumes. Unlike Trinidads Carnival, it has a distinctly Haitian character: rawer, more political, more community-rooted.'},
    {cat:'Music',q:'What is konpa (compas) and why is it central to Haitian identity?',options:['A traditional folk music only for elders','Haiti most popular music genre — a meringue-influenced dance music created in the 1950s by Nemours Jean-Baptiste, now deeply tied to Haitian diaspora identity worldwide','A Jamaican import','A religious music style'],answer:1,exp:'Konpa (compas direct) was created by Nemours Jean-Baptiste in 1955 — a modernized meringue with rich harmonies and a distinctive rhythm. It is Haiti dance music: slow, romantic, everyone dances. The Haitian diaspora in Miami, New York, Montreal, and Paris plays konpa at every gathering — it is the sound of being Haitian wherever you are.'},
    {cat:'Culture',q:'What does Nou pral ranje sa mean as a cultural statement?',options:['We will never fix this','We will fix this — an expression of Haitian resilience and collective determination in the face of adversity','Someone else will fix it','It cannot be fixed'],answer:1,exp:'Nou pral ranje sa (we will fix/arrange this) reflects Haiti profound cultural resilience — a determination to rebuild and persevere despite repeated catastrophes. Haitian resilience is not passive acceptance; it is active determination. The Haitian diaspora worldwide carries this spirit as cultural inheritance.'}
  ]},

}
